window.COURSE_LANG["c10-exam"]["ru"] = [
  {"id":1,"q":"Цепь 120 В питает нагревательный элемент сопротивлением 20 Ом; какой ток потребляется?","opts":["2 А","0,17 А","6 А","2400 А"],"re":"По закону Ома, I = V/R = 120/20 = 6 А."},
  {"id":2,"q":"Какой тип изоляции проводника рассчитан на 90°C в сухих помещениях, но НЕ разрешён для применения во влажных местах?","opts":["THWN-2","THHN","XHHW-2","USE-2"],"re":"THHN — это изоляция на 90°C для сухих/слегка влажных мест; для влажных мест используют THWN-2 или XHHW-2. См. NEC Table 310.4(A)."},
  {"id":3,"q":"В жилом помещении, какое максимальное горизонтальное расстояние от любой точки вдоль линии стены до розетки?","opts":["3 фута","12 футов","10 футов","6 футов"],"re":"NEC 210.52(A) требует, чтобы ни одна точка вдоль линии пола стены не находилась далее 6 футов от розетки, чтобы шнур прибора длиной 6 футов мог дотянуться до розетки с любой стороны."},
  {"id":4,"q":"Согласно NEC 430.22, какая минимальная допустимая токовая нагрузка проводника ответвления требуется для одного двигателя длительного режима с током полной нагрузки 28 ампер?","opts":["28 ампер","31 ампер","40 ампер","35 ампер"],"re":"NEC 430.22 требует, чтобы проводники ответвления для одного двигателя имели допустимую токовую нагрузку не менее 125% от тока полной нагрузки двигателя: 28 А x 1.25 = 35 А."},
  {"id":5,"q":"Согласно разделу 3314 Title 8 Cal/OSHA, какова основная цель процедуры lockout/tagout (LOTO)?","opts":["Контролировать опасную энергию, чтобы оборудование не могло неожиданно получить питание или запуститься во время обслуживания или ремонта","Документировать квалификацию каждого электрика на объекте","Снизить доступный ток короткого замыкания на клеммах оборудования","Обеспечить резервный путь заземления для электрической системы"],"re":"Раздел 3314 Title 8 Cal/OSHA требует контроля опасной энергии посредством lockout/tagout, чтобы оборудование было изолировано и не могло неожиданно запуститься во время обслуживания."},
  {"id":6,"q":"Что обозначает буква 'W' в маркировке изоляции проводника THWN-2?","opts":["Многопроволочная (скрученная) конструкция","Провод одножильный","Белая цветовая маркировка","Пригоден для влажных мест"],"re":"В буквенной маркировке изоляции NEC буква 'W' означает, что проводник рассчитан на влажные места. См. NEC Table 310.4(A)."},
  {"id":7,"q":"Какую мощность рассеивает прибор на 240 В, потребляющий 12,5 А?","opts":["3000 Вт","19,2 Вт","252,5 Вт","1920 Вт"],"re":"По формуле P = V x I = 240 x 12,5 = 3000 Вт."},
  {"id":8,"q":"При выборе проводников ответвления для одного двигателя согласно NEC 430.22 какое значение следует использовать как основу для расчёта?","opts":["Значение тока полной нагрузки из таблиц NEC","Ток полной нагрузки с заводской таблички двигателя","Ток заторможенного ротора двигателя","Ток сервис-фактора, указанный на табличке"],"re":"NEC 430.6(A) указывает, что выбор проводника и устройства защиты по 430.22 основан на табличных значениях (таблицы 430.248/430.250), а не на токе FLA с таблички."},
  {"id":9,"q":"Согласно NFPA 70E, каково общее правило относительно работы на электрооборудовании?","opts":["Оборудование должно быть приведено в электробезопасное рабочее состояние (обесточено), если только обесточивание не создаёт дополнительных опасностей или невыполнимо","Оборудование может оставаться под напряжением, пока присутствует второй работник","Оборудование должно оставаться под напряжением, чтобы напряжение можно было проверять в любое время","Работа под напряжением всегда допустима, если надеты резиновые перчатки"],"re":"NFPA 70E требует создания электробезопасного рабочего состояния до начала работы; работа под напряжением допускается только когда обесточивание создаёт дополнительные или повышенные опасности либо невыполнимо из-за конструкции оборудования или эксплуатационных ограничений."},
  {"id":10,"q":"Какой тип изоляции специально предназначен для подземного ввода и пригоден для прямой укладки в грунт?","opts":["THHN","USE","RHW","TW"],"re":"USE (Underground Service Entrance) рассчитан на прямую укладку в грунт и подземное применение. См. NEC Table 310.4(A)."},
  {"id":11,"q":"Резистор 8 Ом проводит ток 5 А; какую мощность он рассеивает?","opts":["200 Вт","40 Вт","1,6 Вт","320 Вт"],"re":"По формуле P = I в квадрате x R = 5 в квадрате x 8 = 25 x 8 = 200 Вт."},
  {"id":12,"q":"Согласно правилу размещения розеток в жилье, какое максимальное расстояние допускается между соседними розетками общего назначения вдоль стены?","opts":["6 футов","20 футов","15 футов","12 футов"],"re":"Поскольку ни одна точка не может находиться далее 6 футов от розетки, розетки, равномерно расположенные вдоль стены, могут отстоять друг от друга до 12 футов (по 6 футов с каждой стороны), согласно NEC 210.52(A)."},
  {"id":13,"q":"Трёхфазный двигатель длительного режима имеет ток полной нагрузки 80 ампер; какая минимальная допустимая токовая нагрузка проводника ответвления требуется по NEC 430.22?","opts":["100 ампер","92 ампера","80 ампер","125 ампер"],"re":"NEC 430.22 требует 125% от тока полной нагрузки двигателя: 80 А x 1.25 = 100 А минимальная допустимая токовая нагрузка проводника."},
  {"id":14,"q":"Какая процедура используется для проверки того, что цепь обесточена, прежде чем квалифицированный специалист начнёт работу?","opts":["Метод live-dead-live (проверка перед прикосновением) с использованием детектора напряжения соответствующего класса","Подтверждение того, что счётчик коммунальной службы перестал вращаться","Только визуальный осмотр маркировки щита","Кратковременное прикосновение тыльной стороной ладони к проводнику"],"re":"Метод live-dead-live требует проверки детектора напряжения на заведомо живом источнике, проверки обесточенных проводников, а затем повторной проверки на заведомо живом источнике для подтверждения работоспособности прибора, что подтверждает отсутствие напряжения."},
  {"id":15,"q":"На какую максимальную рабочую температуру рассчитана изоляция RHW?","opts":["75°C","90°C","60°C","105°C"],"re":"RHW — термореактивная изоляция, рассчитанная на 75°C для влажных и сухих мест. См. NEC Table 310.4(A)."},
  {"id":16,"q":"Источник 120 В подключён к резистору 60 Ом; какая мощность рассеивается?","opts":["2 Вт","7200 Вт","240 Вт","120 Вт"],"re":"По формуле P = V в квадрате / R = 120 в квадрате / 60 = 14400 / 60 = 240 Вт."},
  {"id":17,"q":"Для двигателя длительного режима с указанным сервис-фактором 1.15 какой процент от тока полной нагрузки с таблички двигателя используется для выбора отдельной защиты от перегрузки по NEC 430.32?","opts":["125%","115%","140%","250%"],"re":"NEC 430.32(A)(1) допускает защиту от перегрузки на уровне 125% от FLA с таблички, когда сервис-фактор составляет 1.15 или более (или превышение температуры 40°C или менее)."},
  {"id":18,"q":"Согласно NFPA 70E, какую границу может пересекать только квалифицированный специалист с использованием соответствующих СИЗ от поражения током?","opts":["Границу дугового разряда для неквалифицированных наблюдателей","Границу limited approach для сопровождаемых посетителей","Ограниченную границу приближения (restricted approach boundary)","Внешнюю границу ограждения территории"],"re":"Согласно NFPA 70E, restricted approach boundary может пересекать только квалифицированный специалист, имеющий документированный план и использующий соответствующие СИЗ от поражения током из-за повышенного риска контакта с частями под напряжением."},
  {"id":19,"q":"XHHW — это термореактивная изоляция; на какую температуру она рассчитана в сухом помещении?","opts":["60°C","75°C","110°C","90°C"],"re":"XHHW рассчитана на 90°C в сухих/слегка влажных местах (и 75°C во влажных). См. NEC Table 310.4(A)."},
  {"id":20,"q":"Три резистора 10 Ом, 15 Ом и 25 Ом соединены последовательно; каково общее сопротивление?","opts":["4,84 Ом","5 Ом","50 Ом","3750 Ом"],"re":"Последовательные сопротивления складываются: 10 + 15 + 25 = 50 Ом."},
  {"id":21,"q":"Для целей размещения розеток в жилье, любое пространство стены какой ширины или шире должно быть оборудовано розеткой?","opts":["12 дюймов (1 фут) или шире","24 дюйма (2 фута) или шире","18 дюймов или шире","36 дюймов (3 фута) или шире"],"re":"NEC 210.52(A)(2) определяет пространство стены, которое должно учитываться, как любое пространство шириной 2 фута (600 мм) или более, включая пространство, измеренное вокруг углов."},
  {"id":22,"q":"Двигатель длительного режима имеет сервис-фактор 1.0 и превышение температуры 50°C; какой процент от тока полной нагрузки с таблички разрешён для выбора его защиты от перегрузки согласно NEC 430.32?","opts":["100%","130%","125%","115%"],"re":"NEC 430.32(A)(1) ограничивает защиту от перегрузки до 115% от FLA с таблички для двигателей, которые не имеют сервис-фактора 1.15+ или превышения температуры 40°C или менее."},
  {"id":23,"q":"Для трассы нужны проводники в трубе, прокладываемой в постоянно влажном подземном месте; какая изоляция подходит?","opts":["THWN-2","Только TW","Только THHN","RHH"],"re":"THWN-2 имеет маркировку 'W' и пригоден для влажных мест; THHN, TW (60°C) и RHH (сухие) здесь подходят хуже. См. NEC Table 310.4(A)."},
  {"id":24,"q":"Какой документ требуется по NFPA 70E перед выполнением обоснованной работы под напряжением внутри restricted approach или границы дугового разряда?","opts":["Паспорт безопасности материала (MSDS)","Сертификат о вводе здания в эксплуатацию","Разрешение на электрические работы под напряжением (energized electrical work permit)","Лист расчёта нагрузки"],"re":"NFPA 70E требует разрешения на электрические работы под напряжением, подписанного уполномоченным руководством, когда работа выполняется внутри restricted approach boundary или там, где существует опасность дугового разряда и работа не может быть выполнена в обесточенном состоянии."},
  {"id":25,"q":"Два резистора по 20 Ом соединены параллельно; каково эквивалентное сопротивление?","opts":["40 Ом","10 Ом","20 Ом","0,1 Ом"],"re":"Для двух равных параллельных резисторов R = R/2 = 20/2 = 10 Ом."},
  {"id":26,"q":"По сравнению с медью, алюминиевый проводник того же размера AWG, как правило, имеет какую характеристику?","opts":["Большую допустимую нагрузку (ampacity)","Не имеет указанной нагрузки","Одинаковую допустимую нагрузку","Меньшую допустимую нагрузку (ampacity)"],"re":"Алюминий имеет большее удельное сопротивление, чем медь, поэтому алюминиевый проводник того же размера имеет меньшую ampacity. См. NEC Table 310.16."},
  {"id":27,"q":"На табличке двигателя указан ток полной нагрузки 16 ампер и сервис-фактор 1.25; какая максимальная уставка защиты от перегрузки разрешена по NEC 430.32?","opts":["16 ампер","20 ампер","18.4 ампера","24 ампера"],"re":"При сервис-факторе 1.15 или более NEC 430.32(A)(1) допускает 125% от FLA с таблички: 16 А x 1.25 = 20 А."},
  {"id":28,"q":"Как NFPA 70E определяет квалифицированного специалиста (qualified person)?","opts":["Любой работник, проработавший в компании не менее пяти лет","Любой человек с действующими водительскими правами и сертификатом первой помощи","Только лицензированный профессиональный инженер","Тот, кто продемонстрировал навыки и знания, связанные с конструкцией и эксплуатацией электрооборудования, и прошёл обучение по технике безопасности для распознавания и предотвращения соответствующих опасностей"],"re":"NFPA 70E определяет квалифицированного специалиста как того, кто продемонстрировал навыки и знания, связанные с конструкцией и эксплуатацией электрооборудования и установок, и прошёл обучение по технике безопасности для выявления и предотвращения соответствующих опасностей."},
  {"id":29,"q":"Резисторы 6 Ом и 12 Ом соединены параллельно; каково общее сопротивление?","opts":["18 Ом","4 Ом","9 Ом","0,25 Ом"],"re":"Параллельно: R = (6 x 12)/(6 + 12) = 72/18 = 4 Ом."},
  {"id":30,"q":"Согласно NEC Table 310.16, какова ampacity медного проводника 14 AWG в колонке 60°C?","opts":["25 A","20 A","15 A","30 A"],"re":"В колонке 60°C таблицы 310.16 проводник 14 AWG из меди рассчитан на 15 A."},
  {"id":31,"q":"Вдоль кухонной столешницы розетки, обслуживающие стойку, должны быть установлены так, чтобы ни одна точка вдоль настенной столешницы не находилась дальше какого расстояния от розетки?","opts":["24 дюйма","20 дюймов","12 дюймов","30 дюймов"],"re":"NEC 210.52(C) требует размещать розетки так, чтобы ни одна точка вдоль линии стены столешницы не находилась далее 24 дюймов от розетки, что соответствует правилу 'не далее 24 дюймов' для шнура длиной 2 фута."},
  {"id":32,"q":"Какова основная цель устройства защиты двигателя от перегрузки, требуемого NEC 430 Часть III?","opts":["Защита от коротких замыканий между проводниками","Защита двигателя и проводников от длительного сверхтока из-за перегрузки двигателя","Обеспечение мгновенного отключения при замыкании на землю","Ограничение скачков напряжения при пуске двигателя"],"re":"Устройства защиты от перегрузки NEC 430.32 защищают двигатель, аппаратуру управления и проводники ответвления от чрезмерного нагрева рабочими сверхтоками (перегрузками), а не от коротких замыканий или замыканий на землю."},
  {"id":33,"q":"Какова цель границы дугового разряда (arc-flash boundary), устанавливаемой согласно NFPA 70E?","opts":["Она отмечает место, где падающая энергия равна 1,2 кал/см2 — порог ожога второй степени для незащищённой кожи","Она указывает максимально допустимую длину удлинителя","Она определяет минимальный радиус изгиба проводников","Она задаёт расстояние для требуемого аварийного освещения"],"re":"Граница дугового разряда — это расстояние, на котором падающая энергия составляет 1,2 кал/см2; в этой точке незащищённый человек может получить ожог второй степени при возникновении дугового разряда."},
  {"id":34,"q":"Четыре резистора по 100 Ом соединены параллельно; каково эквивалентное сопротивление?","opts":["400 Ом","100 Ом","25 Ом","50 Ом"],"re":"Для равных параллельных резисторов R = R/n = 100/4 = 25 Ом."},
  {"id":35,"q":"Три температурные колонки в NEC Table 310.16 отражают какое свойство проводника?","opts":["Температурные классы изоляции","Диапазоны температуры окружающей среды","Проценты заполнения трубы","Классы напряжения"],"re":"Колонки 60°C, 75°C и 90°C соответствуют температурному классу изоляции проводника. См. NEC Table 310.16."},
  {"id":36,"q":"Какое устройство в ответвлении двигателя предназначено для защиты от коротких замыканий и замыканий на землю, а не от рабочих перегрузок?","opts":["Тепловое реле перегрузки","Управляющий трансформатор","Удерживающий контакт двигателя","Устройство защиты ответвления от короткого замыкания и замыкания на землю (предохранитель или автомат)"],"re":"NEC 430 Часть IV требует устройство защиты ответвления от короткого замыкания и замыкания на землю (обычно предохранитель или автомат с обратнозависимой характеристикой), отдельное от устройства защиты от рабочей перегрузки в Части III."},
  {"id":37,"q":"В последовательной цепи с резисторами 30 Ом и 60 Ом под напряжением 90 В, каков ток цепи?","opts":["3 А","0,5 А","1 А","90 А"],"re":"Общее R = 30 + 60 = 90 Ом; I = V/R = 90/90 = 1 А."},
  {"id":38,"q":"Когда проводник с изоляцией 90°C подключается к оборудованию, рассчитанному на 75°C, ampacity какой колонки нужно использовать для итоговой нагрузки на зажимах?","opts":["60°C","90°C","75°C","Среднее между 75°C и 90°C"],"re":"Согласно NEC 110.14(C), действует наименьший температурный класс зажима или проводника; здесь применяется колонка 75°C."},
  {"id":39,"q":"При применении lockout/tagout согласно разделу 3314 Title 8 Cal/OSHA, кому разрешено снимать замок, установленный уполномоченным работником на разъединитель?","opts":["Любому электрику следующей смены, которому нужна цепь","Как правило, только уполномоченному работнику, установившему этот замок, за исключением документированной процедуры, когда этот работник недоступен","Охраннику объекта в конце рабочего дня","Любому ученику, работающему в той же зоне"],"re":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы каждый замок снимал работник, который его установил; снятие другими допускается только по специальной документированной процедуре, когда этот работник отсутствует и работодатель убедился, что это безопасно."},
  {"id":40,"q":"Какой минимальной ширины должно быть пространство кухонной настенной столешницы, прежде чем потребуется обслуживающая его розетка?","opts":["12 дюймов","6 дюймов","18 дюймов","24 дюйма"],"re":"NEC 210.52(C)(1) требует розетку для каждого настенного пространства столешницы шириной 12 дюймов (300 мм) или более."},
  {"id":41,"q":"Почему устройство защиты ответвления двигателя от короткого замыкания и замыкания на землю обычно рассчитано на ток выше тока полной нагрузки двигателя?","opts":["Потому что оно должно также служить устройством защиты от перегрузки","Потому что проводники всегда завышены по сечению","Потому что оно должно пропускать высокий пусковой ток (ток заторможенного ротора) при пуске двигателя без срабатывания","Потому что ток с таблички неточен"],"re":"Двигатели потребляют большой пусковой ток / ток заторможенного ротора при запуске, поэтому NEC 430.52 допускает уставку устройства защиты от короткого замыкания / замыкания на землю значительно выше тока полной нагрузки, чтобы оно не срабатывало ложно, при этом защищая от повреждений."},
  {"id":42,"q":"Колонка 90°C в таблице ampacity в основном используется для какой цели?","opts":["Итоговая допустимая нагрузка на зажимах","Для определения размера трубы","Как исходное значение для применения коэффициентов снижения/коррекции","Для прямого выбора аппарата защиты"],"re":"Ampacity 90°C обычно используется как исходное значение для применения коэффициентов снижения и коррекции, при условии что зажимы не перегружаются. См. NEC 110.14(C) и 310.15."},
  {"id":43,"q":"Однофазная нагрузка потребляет 16 А при 240 В; какова полная мощность в вольт-амперах?","opts":["3840 ВА","15 ВА","256 ВА","1920 ВА"],"re":"Полная мощность S = V x I = 240 x 16 = 3840 ВА."},
  {"id":44,"q":"Что требуется для создания электробезопасного рабочего состояния после размыкания отключающего устройства?","opts":["Немедленно начать работу, поскольку выключатель отключён","Подождать 24 часа перед любой проверкой","Визуально убедиться, что разъединитель разомкнут, применить lockout/tagout, проверить отсутствие напряжения и заземлить там, где может присутствовать наведённая или накопленная энергия","Позвонить в коммунальную службу для подтверждения показаний счётчика"],"re":"NFPA 70E перечисляет шаги для создания электробезопасного рабочего состояния, включая проверку разомкнутого состояния разъединителя, применение LOTO, проверку отсутствия напряжения прибором соответствующего класса и установку заземления там, где может существовать накопленное или наведённое напряжение."},
  {"id":45,"q":"Когда температура окружающей среды превышает 30°C (86°F), ampacity из Table 310.16 нужно:","opts":["Умножить на коэффициент коррекции меньше 1.0","Увеличить на коэффициент коррекции","Оставить без изменений","Умножить на 1.25"],"re":"Более высокая температура окружающей среды снижает ampacity, поэтому применяется коэффициент коррекции меньше 1.0 из Table 310.15(B)(1)."},
  {"id":46,"q":"Какой ток потребляет однофазный резистивный нагреватель 1500 Вт в цепи 120 В?","opts":["12,5 А","180000 А","0,08 А","8 А"],"re":"I = P/V = 1500/120 = 12,5 А (резистивная нагрузка, PF = 1)."},
  {"id":47,"q":"В стандартном трёхфазном асинхронном двигателе как изменяется направление вращения?","opts":["Изменением подключения всех трёх линейных вводов","Изменением подключения заземляющего проводника оборудования","Меняя местами любые два из трёх линейных вводов","Увеличением напряжения питания"],"re":"Перестановка любых двух из трёх линейных проводников меняет порядок чередования фаз, что изменяет направление вращающегося магнитного поля и, следовательно, вращение двигателя."},
  {"id":48,"q":"Какую из следующих задач разрешено выполнять неквалифицированному специалисту вблизи электрооборудования под напряжением?","opts":["Открывать находящийся под напряжением центр управления двигателями для поиска неисправностей","Работу за пределами limited approach boundary, где нет контакта с частями под напряжением","Пересекать restricted approach boundary для выполнения измерений","Заменять находящиеся под напряжением шинные соединения во время отключения"],"re":"Согласно NFPA 70E, неквалифицированный специалист может работать за пределами limited approach boundary; ему не разрешается пересекать её в сторону открытых частей под напряжением, кроме как под постоянным сопровождением квалифицированного специалиста, и даже тогда он не может выполнять квалифицированную работу."},
  {"id":49,"q":"Кухонный остров со столешницей с длинной стороной 24 дюйма или более и короткой стороной 12 дюймов или более, как правило, требует как минимум сколько розеток?","opts":["Ноль","Три","Две","Одну"],"re":"NEC 210.52(C) требует как минимум одну розетку для пространства столешницы острова, отвечающего минимальным размерам 24 на 12 дюймов."},
  {"id":50,"q":"Таблицы ampacity, такие как Table 310.16, основаны на расчётной температуре окружающей среды:","opts":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"re":"Table 310.16 основана на температуре окружающей среды 30°C (86°F); для других температур нужны коэффициенты коррекции. См. NEC 310.15(B)."},
  {"id":51,"q":"Резистор рассеивает 600 Вт при токе 5 А; каково его сопротивление?","opts":["120 Ом","24 Ом","3000 Ом","0,042 Ом"],"re":"Из P = I в квадрате x R, R = P / I в квадрате = 600 / 25 = 24 Ом."},
  {"id":52,"q":"Трёхфазный двигатель, подключённый к линиям L1-T1, L2-T2, L3-T3, вращается в неправильном направлении; какое изменение исправит вращение?","opts":["Поменять местами только L1 и L2","Поменять местами все три ввода одновременно","Переподключить нейтраль","Добавить фазосдвигающий конденсатор"],"re":"Изменение любых двух вводов меняет вращение; перестановка L1 и L2 (или любой одной пары) изменяет порядок чередования фаз и исправляет направление."},
  {"id":53,"q":"Если проводник на 90°C установлен при температуре окружающей среды 50°C, почему выгодно начинать с колонки 90°C?","opts":["Его более высокая базовая ampacity лучше выдерживает температурную коррекцию","Это исключает любое снижение","Это устраняет необходимость в коэффициентах коррекции","Это позволяет использовать меньший аппарат защиты"],"re":"Использование более высокой базовой ampacity 90°C даёт больший запас, когда коэффициент коррекции по температуре уменьшает значение, что разрешено NEC 310.15(B) и 110.14(C)."},
  {"id":54,"q":"От какой основной опасности предназначены защищать СИЗ от дугового разряда?","opts":["Падений с высотных рабочих площадок","Термических ожогов от лучистого и конвективного тепла электрической дуги","Потери слуха от вращающихся механизмов","Химических брызг электролита аккумулятора"],"re":"СИЗ с дуговой защитой (arc-rated) выбираются на основе падающей энергии для защиты работника от интенсивной тепловой энергии дугового разряда; они классифицируются в кал/см2, чтобы соответствовать или превышать расчётную падающую энергию."},
  {"id":55,"q":"Какое напряжение нужно, чтобы пропустить 4 А через резистор 35 Ом?","opts":["140 В","8,75 В","0,114 В","39 В"],"re":"По закону Ома, V = I x R = 4 x 35 = 140 В."},
  {"id":56,"q":"В магнитном пускателе двигателя какова функция удерживающего (фиксирующего) контакта в цепи управления?","opts":["Размыкать цепь при перегрузке","Удерживать катушку пускателя под напряжением после отпускания кнопки пуска кратковременного действия","Понижать управляющее напряжение","Изменять направление вращения двигателя"],"re":"Удерживающий контакт — это вспомогательный контакт, подключённый параллельно кнопке пуска; как только катушка получает питание, он замыкается и поддерживает питание катушки, чтобы двигатель продолжал работать после отпускания кнопки пуска."},
  {"id":57,"q":"Согласно Table 310.15(C)(1), какой коэффициент снижения применяется при наличии от 4 до 6 токоведущих проводников в трубе?","opts":["100%","80%","70%","50%"],"re":"Для 4-6 токоведущих проводников коэффициент снижения составляет 80%. См. NEC Table 310.15(C)(1)."},
  {"id":58,"q":"Розетки, установленные для обслуживания кухонных столешниц в жилье, должны питаться как минимум от скольких ответвлённых цепей для мелких приборов?","opts":["Одной цепи 15 А","Двух цепей 20 А","Одной цепи 30 А","Трёх цепей 15 А"],"re":"NEC 210.11(C)(1) и 210.52(B) требуют как минимум две ответвлённые цепи 20 А для мелких приборов для обслуживания розеток столешниц и других розеток на кухне, в кладовой и обеденных зонах."},
  {"id":59,"q":"Согласно методу категорий СИЗ по NFPA 70E, что определяет, какая категория СИЗ от дугового разряда применяется к задаче?","opts":["Цвет корпуса оборудования","Конкретное оборудование и параметры задачи, указанные в таблицах категорий СИЗ от дугового разряда, включая напряжение и доступный ток короткого замыкания","Суммарная мощность всех подключённых двигателей в л.с.","Возраст электрического щита"],"re":"Таблицы категорий СИЗ NFPA 70E присваивают категорию (от 1 до 4) на основе конкретного типа оборудования, доступного тока короткого замыкания и времени отключения при коротком замыкании, что вместе оценивает воздействие дугового разряда."},
  {"id":60,"q":"Прибор мощностью 2000 Вт работает 3 часа; сколько энергии он потребляет?","opts":["0,67 kWh","667 Вт·ч","6 kWh","6000 kWh"],"re":"Энергия = мощность x время = 2000 Вт x 3 ч = 6000 Вт·ч = 6 kWh."},
  {"id":61,"q":"В стандартной трёхпроводной цепи управления пуск/стоп как обычно подключаются кнопки пуска и стоп?","opts":["Пуск нормально замкнут, а стоп нормально разомкнут","Обе кнопки нормально замкнуты и параллельны","Пуск (нормально разомкнутый) параллельно удерживающему контакту, а стоп (нормально замкнутый) последовательно","Обе кнопки нормально разомкнуты и последовательны"],"re":"Стандартный пост пуск/стоп использует нормально разомкнутую кнопку пуска (параллельно удерживающему контакту для самоблокировки) и нормально замкнутую кнопку стоп последовательно, поэтому нажатие стоп обесточивает катушку."},
  {"id":62,"q":"Согласно Table 310.15(C)(1), какой коэффициент снижения применяется при наличии от 7 до 9 токоведущих проводников, проложенных вместе в трубе?","opts":["60%","80%","70%","50%"],"re":"Для 7-9 токоведущих проводников коэффициент снижения составляет 70%. См. NEC Table 310.15(C)(1)."},
  {"id":63,"q":"При выполнении теста live-dead-live, почему детектор напряжения должен проверяться на заведомо живом источнике как до, так и после проверки обесточенной цепи?","opts":["Чтобы зарядить внутреннюю батарею прибора","Чтобы подтвердить исправность прибора и не полагаться на ложное показание «отсутствия напряжения»","Чтобы откалибровать прибор под частоту местной коммунальной сети","Чтобы разрядить накопленную ёмкость в проводниках"],"re":"Повторная проверка прибора на заведомо живом источнике после теста на отсутствие напряжения подтверждает, что прибор не вышел из строя во время проверки, гарантируя, что показание отсутствия напряжения было достоверным до прикосновения к проводникам."},
  {"id":64,"q":"Если электроэнергия стоит 0,20 доллара за kWh, сколько стоит работа нагрузки 5 кВт в течение 8 часов?","opts":["40,00 долларов","1,60 доллара","8,00 долларов","0,20 доллара"],"re":"Энергия = 5 кВт x 8 ч = 40 kWh; стоимость = 40 x 0,20 = 8,00 долларов."},
  {"id":65,"q":"При каком количестве токоведущих проводников в одной трубе впервые применяются коэффициенты снижения из Table 310.15(C)(1)?","opts":["2 или больше","Более 3 (4 или больше)","3 или больше","Более 9"],"re":"Коэффициенты снижения начинают применяться, когда токоведущих проводников более трёх (то есть 4 или больше). См. NEC 310.15(C)(1)."},
  {"id":66,"q":"В чём основное различие между контактором и магнитным пускателем двигателя?","opts":["Контактор включает встроенную защиту от перегрузки, а пускатель нет","Контактор может коммутировать только нагрузки постоянного тока","Пускатель — это, по существу, контактор с добавленной встроенной защитой от перегрузки","У пускателя нет электромагнитной катушки"],"re":"Магнитный пускатель двигателя — это контактор, объединённый с реле перегрузки; обычный контактор коммутирует нагрузку, но не обеспечивает защиту от рабочей перегрузки."},
  {"id":67,"q":"В жилье коридоры какой минимальной длины требуют как минимум одну розетку?","opts":["15 футов","5 футов","12 футов","10 футов"],"re":"NEC 210.52(H) требует, чтобы коридоры длиной 10 футов (3,0 м) или более имели как минимум одну розетку."},
  {"id":68,"q":"Двигатель выдаёт 10 HP механической мощности; сколько это примерно ватт?","opts":["746 Вт","7460 Вт","1340 Вт","74,6 Вт"],"re":"Используя 1 HP = 746 Вт, 10 HP = 10 x 746 = 7460 Вт."},
  {"id":69,"q":"Согласно NFPA 70E, какое условие оправдывает выполнение работы на проводниках под напряжением вместо их обесточивания?","opts":["Бригада хочет закончить работу быстрее","Руководитель устно предпочитает работу под напряжением","Обесточивание создало бы дополнительные или повышенные опасности либо невыполнимо из-за конструкции оборудования или эксплуатационных ограничений","Оборудование рассчитано на напряжение выше 600 вольт"],"re":"NFPA 70E допускает работу под напряжением только когда обесточивание создаёт дополнительные или повышенные опасности (например, отключение систем жизнеобеспечения) или невыполнимо из-за конструкции оборудования или эксплуатационных ограничений; удобство или экономия времени не подходят."},
  {"id":70,"q":"Шесть токоведущих медных проводников THHN 12 AWG (значение 90°C = 30 A) проложены в одной трубе; после применения коэффициента за пучкование скорректированная ampacity составляет примерно:","opts":["30 A","27 A","21 A","24 A"],"re":"Начиная со значения 90°C = 30 A и применяя коэффициент 80% для 4-6 проводников, получаем 30 × 0.80 = 24 A. См. NEC Table 310.15(C)(1)."},
  {"id":71,"q":"Когда реле перегрузки магнитного пускателя двигателя срабатывает, какую цепь оно непосредственно размыкает для остановки двигателя?","opts":["Цепь управления, обесточивая катушку пускателя","Основные силовые (линейные) проводники к двигателю","Заземляющий проводник оборудования","Питающую линию ответвления"],"re":"Контакты реле перегрузки включены в цепь управления; при их размыкании катушка пускателя обесточивается, отключая главные контакты и двигатель."},
  {"id":72,"q":"Двигатель 5 HP со 100-процентным КПД работает от 240 В однофазной сети при PF 1; какой ток он потребляет?","opts":["3730 А","15,5 А","0,064 А","31 А"],"re":"P = 5 x 746 = 3730 Вт; I = P/V = 3730/240 = 15,5 А."},
  {"id":73,"q":"Восемь токоведущих проводников с базовой ampacity 90°C по 40 A каждый собраны в пучок в трубе; скорректированная ampacity равна:","opts":["40 A","36 A","28 A","32 A"],"re":"Для 7-9 проводников коэффициент 70%, поэтому 40 × 0.70 = 28 A. См. NEC Table 310.15(C)(1)."},
  {"id":74,"q":"Какова функция limited approach boundary согласно NFPA 70E?","opts":["Это расстояние от открытой части под напряжением, в пределах которого существует опасность поражения током","Это максимальный вылет автовышки","Она отмечает край системы заземляющих электродов оборудования","Это граница зоны покрытия пожарными спринклерами"],"re":"Limited approach boundary — это расстояние от открытого проводника или части цепи под напряжением, в пределах которого существует опасность поражения током; неквалифицированные лица не должны пересекать её без квалифицированного сопровождающего."},
  {"id":75,"q":"В типичной цепи управления двигателем с управляющим трансформатором какое напряжение чаще всего подаётся в цепь управления?","opts":["480 вольт","240 вольт","24 вольта","120 вольт"],"re":"Управляющие трансформаторы обычно понижают линейное напряжение до 120 вольт для цепи управления, обеспечивая более безопасное и стандартизированное напряжение для пилотных устройств и катушек."},
  {"id":76,"q":"В жилом помещении должно быть установлено как минимум сколько розеток для каждой ванной комнаты, расположенных рядом с каждой раковиной?","opts":["Не требуется","Как минимум две на ванную комнату","Только одну, если площадь комнаты превышает 50 кв. футов","Как минимум одну в пределах 36 дюймов от внешнего края каждой раковины"],"re":"NEC 210.52(D) требует как минимум одну розетку, установленную в пределах 36 дюймов от внешнего края каждой раковины (умывальника) ванной комнаты."},
  {"id":77,"q":"Двигатель имеет входную мощность 5000 Вт и выходную 4000 Вт; каков его КПД?","opts":["125 процентов","80 процентов","20 процентов","90 процентов"],"re":"КПД = выход/вход = 4000/5000 = 0,80 = 80 процентов."},
  {"id":78,"q":"В нормально сбалансированной 3-проводной однофазной цепи 120/240 В нейтральный проводник:","opts":["Всегда считается токоведущим проводником","Считается только если нагрузка превышает 50 ампер","Не считается токоведущим проводником","Считается за два проводника"],"re":"Нейтраль сбалансированной однофазной 3-проводной цепи несёт только небалансный ток и не считается токоведущей. См. NEC 310.15(E)."},
  {"id":79,"q":"Перед подачей напряжения на вновь установленное оборудование после обслуживания согласно разделу 3314 Title 8 Cal/OSHA, что должно быть проверено?","opts":["Что гарантийные документы поданы","Что краска на корпусе высохла","Что все работники удалены, инструменты убраны, ограждения установлены на место, и каждый работник снял свой собственный замок перед повторной подачей напряжения","Что счёт за электроэнергию оплачен"],"re":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы перед повторной подачей напряжения рабочая зона была проверена для удаления несущественных предметов, целостности компонентов, удаления работников, и каждый уполномоченный работник снял своё собственное блокирующее устройство."},
  {"id":80,"q":"Что использует реверсивный магнитный пускатель для изменения направления трёхфазного двигателя?","opts":["Один контактор с реверсивной катушкой","Два контактора (вперёд и назад), которые меняют местами два из линейных вводов","Переменный резистор в цепи ротора","Конденсаторную батарею, подключаемую к линии"],"re":"Реверсивный пускатель использует два механически и электрически взаимоблокированных контактора; контактор реверса подключён так, чтобы менять местами два из трёх линейных вводов, изменяя направление вращения."},
  {"id":81,"q":"Когда нейтральный проводник 4-проводной трёхфазной цепи звезда обязан учитываться как токоведущий?","opts":["Никогда","Только когда он несёт небалансный ток линейной нагрузки","Когда большую часть нагрузки составляют нелинейные нагрузки","Только в системах 480Y/277 В"],"re":"Согласно NEC 310.15(E), нейтраль учитывается, когда большую часть нагрузки составляют нелинейные (гармонические) нагрузки, так как тогда она несёт значительный ток."},
  {"id":82,"q":"Двигатель выдаёт 3 HP на валу при КПД 75 процентов; какова входная электрическая мощность?","opts":["2984 Вт","1678 Вт","2238 Вт","1119 Вт"],"re":"Выход = 3 x 746 = 2238 Вт; вход = выход/КПД = 2238/0,75 = 2984 Вт."},
  {"id":83,"q":"Анализ опасности дугового разряда главным образом определяет какие два ключевых параметра для единицы оборудования?","opts":["Цвет изоляции проводника и размер кабелепровода","Производителя автоматического выключателя и каталожный номер","Температуру и влажность окружающей среды","Падающую энергию (или категорию СИЗ) и границу дугового разряда"],"re":"Оценка риска дугового разряда устанавливает падающую энергию (или присваивает категорию СИЗ) и границу дугового разряда, чтобы можно было выбрать правильные СИЗ с дуговой защитой и знать защитное расстояние."},
  {"id":84,"q":"В 3-проводной цепи, взятой от двух фаз и нейтрали трёхфазной 4-проводной системы звезда, нейтраль:","opts":["Не считается токоведущей","Считается токоведущим проводником","Считается за половину проводника","Может быть меньше фазных"],"re":"Согласно NEC 310.15(E), нейтраль такой 3-проводной цепи звезда несёт примерно такой же ток, как и фазные проводники, и считается токоведущей."},
  {"id":85,"q":"Почему контакторы прямого и обратного хода в реверсивном пускателе механически и электрически взаимоблокированы?","opts":["Чтобы предотвратить одновременное замыкание обоих контакторов, которое вызвало бы межфазное короткое замыкание","Чтобы увеличить крутящий момент двигателя","Чтобы снизить управляющее напряжение","Чтобы обеспечить одновременную работу в двух направлениях"],"re":"Взаимоблокировка гарантирует, что одновременно может быть включён только один контактор направления; замыкание обоих соединило бы две фазы через переставленные вводы, создав межфазное короткое замыкание."},
  {"id":86,"q":"Прихожая жилого помещения, не являющаяся частью коридора и имеющая площадь более 60 кв. футов, требует розеток на любом пространстве стены какой ширины или шире?","opts":["3 фута","2 фута","1 фут","4 фута"],"re":"NEC 210.52(I) требует розетки в прихожих площадью более 60 кв. футов для каждого пространства стены шириной 3 фута (900 мм) или более, не прерванного дверными проёмами и подобными отверстиями."},
  {"id":87,"q":"Однофазный двигатель потребляет 10 А при 240 В и выдаёт 1800 Вт активной мощности; каков его коэффициент мощности?","opts":["0,90","1,33","0,50","0,75"],"re":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0,75."},
  {"id":88,"q":"Заземляющий проводник оборудования (EGC), проложенный в той же трубе, что и проводники цепи, считается за сколько токоведущих проводников?","opts":["Один","Два","Ноль","Зависит от его сечения"],"re":"Заземляющие и уравнивающие проводники не считаются токоведущими при расчёте коэффициентов снижения. См. NEC 310.15(E)."},
  {"id":89,"q":"Какой прибор подходит для проверки отсутствия напряжения на этапе проверки перед прикосновением?","opts":["Бесконтактный детектор-ручка, используемый сам по себе как единственное средство","Омметр для проверки целостности цепи на шкале сопротивления","Токоизмерительные клещи, измеряющие ток нагрузки","Контактный детектор напряжения соответствующего класса, исправность которого подтверждена до и после проверки"],"re":"NFPA 70E требует детектора или тестера напряжения соответствующего класса для проверки отсутствия напряжения, и прибор должен быть проверен на правильную работу непосредственно до и после теста на отсутствие напряжения."},
  {"id":90,"q":"Какова активная мощность однофазной нагрузки, потребляющей 20 А при 120 В с коэффициентом мощности 0,85?","opts":["2400 Вт","102 Вт","2823 Вт","2040 Вт"],"re":"Активная мощность P = V x I x PF = 120 x 20 x 0,85 = 2040 Вт."},
  {"id":91,"q":"Чем однофазный асинхронный двигатель отличается от трёхфазного асинхронного двигателя в отношении пуска?","opts":["Однофазному двигателю требуется вспомогательный метод пуска (например, пусковая обмотка), а трёхфазный двигатель самозапускающийся","Однофазный двигатель самозапускающийся без вспомогательных средств","Трёхфазный двигатель не может запускаться под нагрузкой","Оба требуют конденсатор для пуска"],"re":"Трёхфазный двигатель создаёт вращающееся магнитное поле и самозапускающийся; пульсирующее поле однофазного двигателя — нет, поэтому ему нужна пусковая обмотка (и часто конденсатор) для создания пускового момента."},
  {"id":92,"q":"Какой минимальный размер проводника обычно разрешён для проводников, соединяемых параллельно?","opts":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"re":"NEC 310.10(G) (параллельные проводники) разрешает параллельное соединение только для размеров 1/0 AWG и больше, с ограниченными исключениями."},
  {"id":93,"q":"Согласно разделу 3314 Title 8 Cal/OSHA, что необходимо сделать с накопленной энергией (например, заряженными конденсаторами или натяжением пружины) во время блокировки?","opts":["Её можно игнорировать, если главный разъединитель заблокирован в разомкнутом положении","Её следует увеличить для проверки оборудования","Она должна быть сброшена, отсоединена, ограничена или иным образом сделана безопасной до начала работы","Её необходимо измерить, но оставить на месте"],"re":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы накопленная или остаточная энергия была рассеяна или ограничена так, чтобы она не могла причинить травму; одна только блокировка разъединителя не устраняет накопленную ёмкостную или механическую энергию."},
  {"id":94,"q":"Однофазная цепь несёт 25 А по трассе, где суммарное сопротивление проводников составляет 0,4 Ом; какова потеря напряжения?","opts":["10 В","62,5 В","0,016 В","100 В"],"re":"Потеря напряжения Vd = I x R = 25 x 0,4 = 10 В."},
  {"id":95,"q":"Какое место в жилье требует, чтобы розетки 125 В, 15 и 20 А были защищены GFCI?","opts":["Шкаф в спальне","Ванная комната","Чердачное пространство без оборудования","Парадная столовая"],"re":"NEC 210.8(A) перечисляет ванные комнаты среди мест в жилье, где розетки 125 В, 15 и 20 А должны иметь защиту устройством защитного отключения по току утечки (GFCI)."},
  {"id":96,"q":"В однофазном двигателе с конденсаторным пуском какова цель пускового конденсатора?","opts":["Создавать фазовый сдвиг в пусковой обмотке, чтобы двигатель развивал пусковой момент","Постоянно улучшать рабочий коэффициент мощности","Ограничивать ток заторможенного ротора в рабочей обмотке","Преобразовывать однофазное питание в трёхфазное"],"re":"Пусковой конденсатор сдвигает ток в пусковой обмотке по фазе относительно рабочей обмотки, создавая вращающееся поле, которое обеспечивает высокий пусковой момент."},
  {"id":97,"q":"Когда проводники соединяются параллельно, параллельные проводники каждой фазы должны быть:","opts":["Разного сечения для балансировки нагрузки","Одинаковой длины, материала и сечения","Разных типов изоляции","Подключены разными способами"],"re":"Согласно NEC 310.10(G), параллельные проводники каждой фазы должны быть одинаковыми по длине, материалу, сечению и изоляции и одинаково оконцованы."},
  {"id":98,"q":"Ответвлённая цепь 120 В имеет измеренную потерю напряжения 6 В; каков процент потери напряжения?","opts":["20 процентов","0,5 процента","2 процента","5 процентов"],"re":"Процент потери = Vd/Vисточника x 100 = 6/120 x 100 = 5 процентов."},
  {"id":99,"q":"Когда неквалифицированный специалист может пересечь limited approach boundary в сторону открытой части под напряжением?","opts":["Никогда, ни при каких обстоятельствах","В любое время, пока надеты защитные очки","Только в светлое время суток","Только под постоянным сопровождением или руководством квалифицированного специалиста и при надлежащей защите"],"re":"NFPA 70E разрешает неквалифицированному специалисту пересекать limited approach boundary только при постоянном сопровождении квалифицированного специалиста, который информирует его об опасностях и обеспечивает защиту; при этом он всё равно не может выполнять квалифицированную работу."},
  {"id":100,"q":"В двигателе с конденсаторным пуском и асинхронным режимом работы какое устройство отключает пусковую обмотку, когда двигатель достигает примерно 75% полной скорости?","opts":["Тепловое реле перегрузки","Центробежный выключатель","Магнитный контактор","Управляющий трансформатор"],"re":"Центробежный выключатель (или эквивалентное реле) размыкается, чтобы убрать пусковую обмотку и пусковой конденсатор из цепи, когда двигатель приближается к рабочей скорости."},
  {"id":101,"q":"Два медных проводника 250 kcmil на фазу проложены параллельно; электрически они работают как:","opts":["Один проводник 250 kcmil","Проводник с половинной ampacity","Один проводник примерно удвоенной ampacity","Две отдельные ответвлённые цепи"],"re":"Параллельные проводники делят нагрузку и рассматриваются как один проводник суммарной (примерно удвоенной) ampacity. См. NEC 310.10(G)."},
  {"id":102,"q":"На фидере 240 В проводники имеют суммарное сопротивление 0,15 Ом и несут 40 А; каков процент потери напряжения?","opts":["2,5 процента","6 В","0,6 процента","25 процентов"],"re":"Vd = 40 x 0,15 = 6 В; процент = 6/240 x 100 = 2,5 процента."},
  {"id":103,"q":"Розетки жилого помещения, установленные для обслуживания поверхностей кухонной столешницы, должны быть снабжены какой защитой?","opts":["Только AFCI","Только защита от перенапряжений","Защита GFCI","Никакой особой защиты"],"re":"NEC 210.8(A) требует защиту GFCI для розеток, обслуживающих поверхности кухонной столешницы в жилье."},
  {"id":104,"q":"Какой минимальный размер медного проводника ответвлённой цепи обычно разрешён для бытовой цепи 15 ампер?","opts":["12 AWG","16 AWG","14 AWG","10 AWG"],"re":"Медный проводник 14 AWG — наименьший стандартный проводник ответвлённой цепи (15 A); для цепей 20 A требуется 12 AWG. См. NEC 210.19 и Table 310.16."},
  {"id":105,"q":"Какую информацию обычно должно содержать разрешение на электрические работы под напряжением согласно NFPA 70E?","opts":["Расписание обедов на объекте и распределение парковочных мест","Розничную цену запасных частей","Имена всех бывших работников, обслуживавших оборудование","Описание работы, обоснование работы под напряжением, результаты оценки риска поражения током и дугового разряда, и требуемые СИЗ"],"re":"NFPA 70E указывает, что разрешение на работу под напряжением должно включать описание цепи/оборудования, обоснование работы под напряжением, результаты оценки риска поражения током и дугового разряда, требуемые СИЗ и подписи руководства об одобрении."},
  {"id":106,"q":"Однофазный двигатель с конденсаторным пуском гудит, но не запускается и не вращается; какая неисправность является наиболее вероятной причиной?","opts":["Обрыв рабочей обмотки","Обрыв цепи пускового конденсатора или пусковой обмотки (например, неисправный конденсатор или центробежный выключатель)","Слишком высокое напряжение питания","Подшипники двигателя переполнены смазкой"],"re":"Гудение без запуска обычно указывает на то, что рабочая обмотка под напряжением, но пусковая цепь (конденсатор, пусковая обмотка или центробежный выключатель) разомкнута, поэтому пусковой момент не создаётся."},
  {"id":107,"q":"Используя однофазную формулу потери напряжения Vd = 2 x K x I x L / CM, при K = 12,9, I = 20 А, L = 100 футов и CM = 10380, какова приблизительная потеря напряжения?","opts":["2,48 В","4,97 В","9,94 В","0,50 В"],"re":"Vd = (2 x 12,9 x 20 x 100)/10380 = 51600/10380 = 4,97 В."},
  {"id":108,"q":"Какой наименьший размер медного проводника разрешён для ответвлённой цепи 20 ампер?","opts":["16 AWG","12 AWG","14 AWG","10 AWG"],"re":"Ответвлённая цепь 20 ампер требует минимум медный проводник 12 AWG согласно NEC 240.4(D) и Table 310.16."},
  {"id":109,"q":"Какова основная функция частотно-регулируемого привода (VFD), подключённого к асинхронному двигателю переменного тока?","opts":["Управлять скоростью двигателя путём изменения частоты (и напряжения), подаваемой на двигатель","Преобразовывать переменный ток в постоянный для двигателя","Обеспечивать только защиту от перегрузки","Корректировать коэффициент мощности со стороны сети"],"re":"VFD регулирует выходную частоту и пропорционально напряжение, подаваемое на двигатель; поскольку синхронная скорость пропорциональна частоте, это управляет скоростью двигателя."},
  {"id":110,"q":"Почему NFPA 70E подчёркивает обесточивание оборудования, а не опору исключительно на СИЗ?","opts":["СИЗ дороже, чем обесточивание","Устранение опасности путём обесточивания эффективнее СИЗ, которые лишь смягчают последствия в случае инцидента","СИЗ нельзя очистить после использования","Обесточивание требуется только из косметических соображений"],"re":"NFPA 70E следует иерархии управления рисками, где устранение (обесточивание) является наиболее эффективным средством, а СИЗ — последней линией защиты, которая лишь снижает тяжесть травмы при возникновении дуги или поражения током."},
  {"id":111,"q":"Однофазная резистивная нагрузка 240 В потребляет 4800 Вт; каково её сопротивление?","opts":["12 Ом","20 Ом","0,05 Ом","50 Ом"],"re":"Из P = V в квадрате / R, R = V в квадрате / P = 57600 / 4800 = 12 Ом."},
  {"id":112,"q":"Согласно NEC 240.4(D), какова максимальная защита от сверхтока, обычно разрешённая для медных проводников 14 AWG?","opts":["10 A","20 A","15 A","25 A"],"re":"NEC 240.4(D) ограничивает медный проводник 14 AWG максимальным аппаратом защиты на 15 ампер, независимо от его более высокой табличной ampacity."},
  {"id":113,"q":"Какое из следующих мест размещения розеток в жилье обычно требует защиты GFCI?","opts":["Стена гостиной","На улице","Стена спальни","Центральный коридор"],"re":"NEC 210.8(A) требует защиту GFCI для наружных розеток 125 В, 15 и 20 А в жилых домах."},
  {"id":114,"q":"VFD обычно управляет скоростью асинхронного двигателя переменного тока, поддерживая какое соотношение между напряжением и частотой?","opts":["Нулевое напряжение на низкой частоте","Постоянный ток независимо от частоты","Максимальное напряжение на всех частотах","Постоянное соотношение вольт на герц (V/Hz)"],"re":"Чтобы поддерживать постоянный магнитный поток и способность создавать момент во всём диапазоне скоростей, VFD обычно удерживает постоянное соотношение вольт на герц при изменении выходной частоты."},
  {"id":115,"q":"Что из следующего лучше всего описывает restricted approach boundary по сравнению с limited approach boundary?","opts":["Restricted approach boundary находится ближе к части под напряжением и учитывает повышенный риск из-за электрической дуги в сочетании с непреднамеренным движением","Restricted approach boundary находится дальше от части под напряжением, чем limited approach boundary","Обе границы всегда находятся на одинаковом расстоянии","Restricted approach boundary применяется только к механическим опасностям"],"re":"Restricted approach boundary находится ближе к открытой части под напряжением, чем limited approach boundary; её пересечение требует квалифицированного специалиста с соответствующими СИЗ из-за повышенной вероятности дугового перекрытия в сочетании с непреднамеренным движением."},
  {"id":116,"q":"Согласно NEC 240.4(D), максимальный аппарат защиты для медных проводников 12 AWG обычно составляет:","opts":["30 A","25 A","15 A","20 A"],"re":"NEC 240.4(D) ограничивает медный проводник 12 AWG максимальным аппаратом защиты на 20 ампер."},
  {"id":117,"q":"Три лампы по 60 Вт каждая при 120 В соединены параллельно; какой суммарный ток потребляется?","opts":["0,5 А","180 А","4,5 А","1,5 А"],"re":"Суммарная P = 3 x 60 = 180 Вт; I = P/V = 180/120 = 1,5 А."},
  {"id":118,"q":"Что является распространённым преимуществом пуска двигателя переменного тока с VFD вместо прямого пуска от сети?","opts":["Увеличивает пусковой ток заторможенного ротора","Обеспечивает плавный пуск со сниженным пусковым током и механической нагрузкой","Устраняет необходимость в любой защите от перегрузки","Требует, чтобы двигатель был синхронного типа"],"re":"VFD постепенно повышает частоту и напряжение, обеспечивая плавный пуск, который значительно снижает пусковой ток и механическую/электрическую нагрузку по сравнению с прямым пуском от сети."},
  {"id":119,"q":"Согласно разделу 3314 Title 8 Cal/OSHA, когда только устройство tagout (без замка) считается приемлемым?","opts":["Всякий раз, когда работник предпочитает бирки замкам","В любое время, когда оборудование выше 480 вольт","Только когда устройство изоляции энергии не может быть заблокировано замком, и дополнительные меры безопасности обеспечивают защиту, эквивалентную блокировке","Только по выходным"],"re":"Раздел 3314 Title 8 Cal/OSHA допускает только tagout, когда устройство изоляции энергии не может принять замок, и тогда работодатель должен обеспечить полную защиту работников, эквивалентную программе блокировки."},
  {"id":120,"q":"Согласно NEC 240.4(D), максимальный аппарат защиты для медных проводников 10 AWG обычно составляет:","opts":["20 A","30 A","25 A","40 A"],"re":"NEC 240.4(D) ограничивает медный проводник 10 AWG максимальным аппаратом защиты на 30 ампер."},
  {"id":121,"q":"Элемент водонагревателя имеет сопротивление 12,8 Ом в цепи 240 В; каково его энергопотребление?","opts":["3072 Вт","18,75 Вт","4500 Вт","737280 Вт"],"re":"P = V в квадрате / R = 57600 / 12,8 = 4500 Вт."},
  {"id":122,"q":"Розетка 125 В в неотделанном подвале жилья обычно требует какой защиты?","opts":["Никакой защиты","Только AFCI","Защита GFCI","Только изолированное заземление"],"re":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в неотделанных подвалах жилых домов."},
  {"id":123,"q":"Для алюминиевых проводников согласно NEC 240.4(D), какова максимальная защита от сверхтока для алюминия 12 AWG?","opts":["20 A","10 A","15 A","25 A"],"re":"NEC 240.4(D) ограничивает алюминий/алюминий в медной оболочке 12 AWG максимальным аппаратом защиты на 15 ампер."},
  {"id":124,"q":"При чтении заводской таблички двигателя что представляет указанное значение оборотов в минуту (RPM)?","opts":["Синхронную скорость магнитного поля","Скорость только на холостом ходу","Максимально допустимую скорость превышения","Приблизительную рабочую скорость вала двигателя при полной нагрузке"],"re":"RPM на табличке — это скорость двигателя при полной (номинальной) нагрузке, которая для асинхронного двигателя немного меньше синхронной скорости из-за скольжения."},
  {"id":125,"q":"Какова правильная последовательность процедуры проверки live-dead-live?","opts":["Проверить заведомо живой источник, проверить рабочую цепь на отсутствие напряжения, затем повторно проверить заведомо живой источник","Проверить обесточенную цепь, затем прикоснуться к ней, затем проверить живой источник","Сначала прикоснуться к цепи, затем дважды проверить живой источник","Проверить сопротивление, проверить целостность, затем проверить ток"],"re":"Метод live-dead-live проверяет прибор на заведомо живом источнике, затем подтверждает, что целевая цепь обесточена, затем повторно проверяет прибор на заведомо живом источнике, чтобы доказать его работоспособность, подтверждая достоверный результат отсутствия напряжения."},
  {"id":126,"q":"В последовательной цепи за резисторами 5 Ом и 5 Ом следует резистор 10 Ом; каково общее сопротивление?","opts":["2 Ом","250 Ом","20 Ом","10 Ом"],"re":"Последовательно складывается: 5 + 5 + 10 = 20 Ом."},
  {"id":127,"q":"Почему алюминиевая проводка обычно требует большего сечения, чем медь, для той же ampacity?","opts":["Алюминий плавится при более низкой температуре","Алюминий хуже изолируется","Алюминий тяжелее меди","Алюминий имеет большее удельное электрическое сопротивление"],"re":"Большее удельное сопротивление алюминия означает, что для передачи того же тока нужно большее сечение. См. сравнения ampacity в NEC Table 310.16."},
  {"id":128,"q":"На заводской табличке двигателя что в основном указывает кодовая буква (кодовая буква NEMA)?","opts":["КВА заторможенного ротора на лошадиную силу (пусковую характеристику)","КПД при полной нагрузке","Максимальную температуру окружающей среды","Класс изоляции"],"re":"Кодовая буква NEMA на табличке указывает кВА заторможенного ротора на лошадиную силу, что используется для определения пускового тока двигателя."},
  {"id":129,"q":"Каково эквивалентное сопротивление резисторов 10 Ом, 20 Ом и 30 Ом, соединённых параллельно?","opts":["60 Ом","0,183 Ом","20 Ом","5,45 Ом"],"re":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5,45 Ом."},
  {"id":130,"q":"Какое утверждение об одежде с дуговой защитой (arc-rated) согласно NFPA 70E является верным?","opts":["Обычные хлопковые футболки обеспечивают достаточную дуговую защиту","Любая огнестойкая одежда автоматически имеет дуговую защиту","Одежда с дуговой защитой должна иметь дуговой рейтинг, равный или превышающий расчётную падающую энергию на рабочем расстоянии","Одежда с дуговой защитой должна закрывать только руки"],"re":"NFPA 70E требует, чтобы СИЗ с дуговой защитой имели дуговой рейтинг (в кал/см2) не менее доступной падающей энергии; одежда без рейтинга, даже хлопковая, может воспламениться или расплавиться и не обеспечивает сертифицированной защиты."},
  {"id":131,"q":"Розетка, установленная в гараже жилья, должна быть снабжена чем из следующего?","opts":["Конфигурация с фиксацией","Защита GFCI","Только защита AFCI","Изолированный нейтральный провод"],"re":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в гаражах жилых домов."},
  {"id":132,"q":"Зажимы с маркировкой 'CU-AL' или 'AL-CU' требуются при подключении:","opts":["Только проводников больше 1/0","Только медных проводников","Только заземляющих проводников","Алюминиевых или медных проводников на этом зажиме"],"re":"Зажимы с маркировкой CU-AL/AL-CU испытаны и сертифицированы для применения с алюминиевыми и медными проводниками. См. NEC 110.14(A)."},
  {"id":133,"q":"Однофазная цепь двигателя 240 В выдаёт 7200 Вт активной мощности при коэффициенте мощности 0,80; каков линейный ток?","opts":["37,5 А","30 А","24 А","60 А"],"re":"I = P / (V x PF) = 7200 / (240 x 0,80) = 7200/192 = 37,5 А."},
  {"id":134,"q":"На заводской табличке двигателя что указывает сервис-фактор (SF) 1.15?","opts":["Двигатель должен всегда работать при 115% номинального напряжения","Двигатель может непрерывно работать при нагрузке до 115% от его номинальной мощности без немедленного повреждения","Пусковой ток составляет 115% от тока полной нагрузки","Изоляция рассчитана на 115°C"],"re":"Сервис-фактор 1.15 означает, что двигатель может нести непрерывную перегрузку 15% сверх номинальной мощности при указанных условиях; он также влияет на допустимый выбор защиты от перегрузки по NEC 430.32."},
  {"id":135,"q":"Какова роль электробезопасного рабочего состояния в устранении электрических опасностей?","opts":["Оно устраняет опасности поражения током и дугового разряда, поскольку оборудование проверено как обесточенное, изолированное и неспособное снова получить питание","Оно снижает опасность вдвое, но всё равно требует полного комплекта СИЗ","Оно защищает только от дугового разряда, но не от поражения током","Оно применяется только к низковольтным цепям управления"],"re":"После создания и проверки электробезопасного рабочего состояния источник электрической энергии удаляется, устраняя опасности как поражения током, так и дугового разряда, поэтому работа больше не считается работой под напряжением."},
  {"id":136,"q":"Когда к проводнику применяются и температурная коррекция, и коэффициент за пучкование, их нужно:","opts":["Перемножить вместе с базовой ampacity","Сложить вместе","Игнорировать, если проводники рассчитаны на 90°C","Применять раздельно, выбирая меньший"],"re":"Коэффициенты коррекции и снижения перемножаются и применяются к базовой ampacity. См. NEC 310.15(B) и (C)."},
  {"id":137,"q":"Нагрузка 3 кВт работает непрерывно полные сутки; сколько энергии потребляется?","opts":["24 kWh","3 kWh","72 kWh","125 kWh"],"re":"Энергия = 3 кВт x 24 ч = 72 kWh."},
  {"id":138,"q":"На заводской табличке двигателя указано двойное напряжение 230/460 В; что обычно происходит с током полной нагрузки, когда двигатель подключён на более высокое напряжение (460 В)?","opts":["Он примерно удваивается","Он остаётся точно таким же","Он становится нулевым","Он составляет примерно половину значения при 230 В"],"re":"Для данной мощности ток обратно пропорционален напряжению, поэтому подключение на 460 В потребляет примерно половину тока полной нагрузки, требуемого при 230 В."},
  {"id":139,"q":"Проводник с маркировкой USE-2 имеет какой температурный класс?","opts":["60°C","75°C","105°C","90°C"],"re":"Суффикс '-2' означает рейтинг 90°C для влажных и сухих мест, поэтому USE-2 рассчитан на 90°C. См. NEC Table 310.4(A)."},
  {"id":140,"q":"Кто уполномочен определять, что работа под напряжением обоснована, и одобрять разрешение на электрические работы под напряжением?","opts":["Любой работник бригады большинством голосов","Первый человек, прибывший на объект","Торговый представитель производителя оборудования","Уполномоченный руководящий персонал после документирования обоснования и оценки риска"],"re":"NFPA 70E требует, чтобы разрешение на электрические работы под напряжением было рассмотрено и подписано уполномоченным руководством, подтверждающим обоснование работы под напряжением и завершённые оценки риска."},
  {"id":141,"q":"Розетки, установленные в пределах какого расстояния от внешнего края раковины, обычно требуют защиты GFCI в жилье?","opts":["3 фута","4 фута","10 футов","6 футов"],"re":"NEC 210.8(A) требует защиту GFCI для розеток, расположенных в пределах 6 футов от внешнего края раковины."},
  {"id":142,"q":"Насосный двигатель потребляет 4 кВт и выдаёт полезную мощность 5 HP; каков его КПД?","opts":["125 процентов","80 процентов","93 процента","75 процентов"],"re":"Выход = 5 x 746 = 3730 Вт; КПД = 3730/4000 = 0,93 = 93 процента."},
  {"id":143,"q":"Сравниваются однофазный двигатель 5 л.с. 230 В и трёхфазный двигатель 5 л.с. 230 В; какое утверждение об их токах полной нагрузки обычно верно?","opts":["Однофазный двигатель потребляет меньше тока, чем трёхфазный двигатель","Оба потребляют точно одинаковый ток","Однофазный двигатель потребляет больше тока, чем трёхфазный двигатель при той же мощности и напряжении","Трёхфазный двигатель не может работать при 230 В"],"re":"При той же мощности и напряжении однофазный двигатель потребляет существенно больший ток, чем трёхфазный двигатель, поскольку трёхфазная мощность передаётся более эффективно по трём проводникам."},
  {"id":144,"q":"Обычный проводник USE без надлежащей наружной оболочки, как правило, НЕ разрешён для использования в качестве:","opts":["Подземного фидера","Ввода с прямой укладкой в грунт","Подземного ответвления ввода","Внутренней проводки ответвлённых цепей внутри здания"],"re":"USE предназначен для подземного/вводного применения; он не сертифицирован для общей внутренней проводки внутри зданий. См. примечания к NEC Table 310.4(A)."},
  {"id":145,"q":"Во время lockout/tagout, где каждый уполномоченный работник должен разместить своё блокирующее устройство?","opts":["На заводской табличке оборудования","Только на двери электрощитовой","На устройстве изоляции энергии, чтобы каждый работник контролировал изоляцию своим собственным замком","В своём личном ящике для инструментов на хранении"],"re":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы блокирующее устройство устанавливалось на средство изоляции энергии; при участии нескольких работников каждый ставит свой собственный замок (часто через групповую блокировочную скобу), чтобы изоляцию нельзя было снять, пока не закончит каждый работник."},
  {"id":146,"q":"Однофазная нагрузка 8 кВА работает при коэффициенте мощности 0,90; какова активная мощность в кВт?","opts":["7,2 кВт","8,89 кВт","8 кВт","0,9 кВт"],"re":"Активная мощность = кВА x PF = 8 x 0,90 = 7,2 кВт."},
  {"id":147,"q":"Проводник с двойной маркировкой 'THHN/THWN-2' может использоваться во влажном месте при каком температурном классе?","opts":["60°C","90°C","75°C","Не может использоваться во влажных местах"],"re":"Маркировка THWN-2 обеспечивает 90°C как во влажных, так и в сухих местах для проводника с двойной маркировкой. См. NEC Table 310.4(A)."},
  {"id":148,"q":"Трёхфазный двигатель, работающий в системе 480 В, внезапно потребляет большой ток, перегревается и громко гудит; какое условие следует проверить в первую очередь?","opts":["Чрезмерное напряжение цепи управления","Обрыв фазы (однофазный режим) на питании","Перепутанный заземляющий проводник","Слишком большое сечение проводника ответвления"],"re":"Потеря одной фазы (однофазный режим) приводит к перегреву трёхфазного двигателя и потреблению большого тока по оставшимся фазам; проверка обрыва фазы или перегоревшего предохранителя — первый шаг."},
  {"id":149,"q":"Розетка в прачечной зоне жилья, обслуживающая прачечное оборудование, обычно требует какой защиты?","opts":["Защита GFCI","Только защита от вскрытия","Только AFCI","Никакой защиты"],"re":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в прачечных зонах жилья."},
  {"id":150,"q":"Какой фактор увеличивает доступную падающую энергию на данной единице оборудования во время дугового разряда?","opts":["Более короткое время отключения вышестоящего защитного устройства при коротком замыкании","Более длительная продолжительность дуги до того, как защитное устройство отключит короткое замыкание","Большее рабочее расстояние от источника дуги","Меньший доступный ток короткого замыкания"],"re":"Падающая энергия увеличивается при большей продолжительности дуги; чем дольше вышестоящее защитное устройство отключает короткое замыкание, тем больше тепловой энергии выделяется, поэтому быстродействующая защита снижает опасность дугового разряда."},
  {"id":151,"q":"Если цепь 277 В имеет максимально допустимую потерю напряжения 3 процента, какова максимально допустимая потеря в вольтах?","opts":["0,83 В","8,31 В","83,1 В","9,23 В"],"re":"Максимальная потеря = 0,03 x 277 = 8,31 В."},
  {"id":152,"q":"Десять токоведущих проводников проложены в одной трубе; какой коэффициент снижения из Table 310.15(C)(1) применяется?","opts":["50%","70%","80%","45%"],"re":"Для 10-20 токоведущих проводников коэффициент снижения составляет 50%. См. NEC Table 310.15(C)(1)."},
  {"id":153,"q":"Если катушка магнитного пускателя двигателя не получает питание при нажатии кнопки пуска, какой логичный первый пункт для проверки в цепи управления?","opts":["Подшипники двигателя","Направление вращения двигателя","Номинальную мощность на табличке","Целостность цепи управления, включая кнопку стоп, контакты перегрузки и управляющий предохранитель"],"re":"Катушка, которая не срабатывает, указывает на разомкнутую цепь управления; проверьте кнопку стоп (НЗ), контакты перегрузки (НЗ), управляющий предохранитель и целостность катушки, прежде чем подозревать механические проблемы."},
  {"id":154,"q":"Какое утверждение о подсчёте токоведущих проводников для снижения нагрузки верно?","opts":["Заземлённая нейтраль всегда учитывается","Заземляющие проводники оборудования учитываются","Учитываются только незаземлённые (фазные) проводники и квалифицирующиеся нейтрали","Учитываются все проводники в трубе"],"re":"Учитываются только незаземлённые проводники плюс нейтрали, реально несущие ток; EGC и нетоковедущие нейтрали исключаются. См. NEC 310.15(E)."},
  {"id":155,"q":"Что должен сделать квалифицированный специалист перед пересечением границы дугового разряда для выполнения задачи?","opts":["Подождать, пока падающая энергия снизится сама по себе","Снять все металлические украшения и работать в обычной одежде","Надеть СИЗ с дуговой защитой, рейтинг которых равен или превышает падающую энергию на рабочем расстоянии","Письменно уведомить местную пожарную службу"],"re":"NFPA 70E требует, чтобы любой, пересекающий границу дугового разряда, носил СИЗ с дуговой защитой, дуговой рейтинг которых не менее расчётной падающей энергии на рабочем расстоянии, чтобы предотвратить ожог второй степени."},
  {"id":156,"q":"Трасса проводника теряет 7,2 В в цепи 120 В, питающей нагрузку; какое напряжение подаётся на нагрузку?","opts":["112,8 В","127,2 В","6 В","120 В"],"re":"Напряжение на нагрузке = источник минус потеря = 120 - 7,2 = 112,8 В."},
  {"id":157,"q":"Проводники ответвления двигателя длительного режима выбраны на уровне 125% от тока полной нагрузки; устройство защиты от перегрузки для того же двигателя (SF 1.15) выбрано на уровне 125% от FLA с таблички. Почему эти два процента могут ссылаться на разные значения тока?","opts":["Проводники используют табличный ток FLC из NEC, а устройство защиты от перегрузки использует фактический ток полной нагрузки с таблички","Оба всегда должны использовать точно одно и то же значение тока","Устройство защиты от перегрузки использует ток заторможенного ротора","Проводники используют ток с таблички, а защита от перегрузки — табличные значения"],"re":"Согласно NEC 430.6(A), выбор проводника и устройства защиты от короткого замыкания использует табличные значения FLC, тогда как защита от перегрузки по 430.32 основана на фактическом токе полной нагрузки с таблички двигателя."},
  {"id":158,"q":"Когда одна розетка GFCI подключена для защиты последующих розеток, защищаемые выходы должны быть подключены к какому набору клемм на устройстве GFCI?","opts":["Клеммы LINE","Только клемма заземления","Клеммы LOAD","Любой набор работает одинаково"],"re":"Последующие (защищаемые) розетки должны подключаться к клеммам LOAD устройства GFCI; входящее питание подключается к клеммам LINE."},
  {"id":159,"q":"Для длительной нагрузки проводники ответвлённой цепи должны иметь допустимую ampacity не менее какого процента длительной нагрузки?","opts":["100%","125%","150%","115%"],"re":"Согласно NEC 210.19(A) и 215.2, проводники, питающие длительные нагрузки, должны быть рассчитаны не менее чем на 125% длительной нагрузки."},
  {"id":160,"q":"Ток 0,25 А течёт через резистор 480 Ом; какая мощность рассеивается?","opts":["30 Вт","120 Вт","7680 Вт","1920 Вт"],"re":"P = I в квадрате x R = 0,0625 x 480 = 30 Вт."},
  {"id":161,"q":"Согласно разделу 3314 Title 8 Cal/OSHA, как часто должны проверяться или пересматриваться процедуры lockout/tagout?","opts":["Только один раз при первичном приёме работника на работу","Каждые десять лет","Периодически, не реже одного раза в год, чтобы убедиться, что процедуры и работа сотрудников остаются эффективными","Никогда, после создания письменной программы"],"re":"Раздел 3314 Title 8 Cal/OSHA требует периодической проверки, не реже одного раза в год, процедур управления энергией для устранения недостатков и подтверждения того, что уполномоченные работники следуют им правильно."},
  {"id":162,"q":"Однофазный двигатель 240 В длительного режима имеет табличный ток полной нагрузки 20 ампер; какая минимальная допустимая токовая нагрузка проводника ответвления требуется по NEC 430.22?","opts":["20 ампер","25 ампер","23 ампера","30 ампер"],"re":"NEC 430.22 требует 125% от тока полной нагрузки для одного двигателя: 20 А x 1.25 = 25 А минимальная допустимая токовая нагрузка проводника."},
  {"id":163,"q":"Шесть токоведущих проводников в одной трубе при температуре окружающей среды 40°C; и коэффициент коррекции 0.91, и коэффициент снижения 80% применяются к базовой ampacity 90°C = 40 A, давая примерно:","opts":["40 A","36 A","32 A","29 A"],"re":"40 A × 0.91 × 0.80 ≈ 29 A; коэффициенты коррекции и снижения перемножаются согласно NEC 310.15(B) и (C)."},
  {"id":164,"q":"Два резистора последовательно несут одинаковый ток 2 А; если один 15 Ом, а другой 25 Ом, каково суммарное напряжение на паре?","opts":["20 В","8 В","40 В","80 В"],"re":"Общее R = 15 + 25 = 40 Ом; V = I x R = 2 x 40 = 80 В."},
  {"id":165,"q":"Что отличает квалифицированного специалиста от неквалифицированного в отношении границ приближения по поражению током?","opts":["Неквалифицированные лица могут свободно пересекать любую границу, если носят перчатки","Только квалифицированный специалист может пересекать restricted approach boundary в сторону открытых частей под напряжением, используя соответствующие СИЗ и план","Оба могут пересекать все границы одинаково","Только неквалифицированный специалист может пересекать restricted approach boundary"],"re":"NFPA 70E разрешает только квалифицированному специалисту, использующему соответствующие СИЗ от поражения током и документированный план приближения, пересекать restricted approach boundary; неквалифицированные лица удерживаются за пределами limited approach boundary, кроме как под квалифицированным сопровождением."},
  {"id":166,"q":"Какой материал проводника легче по весу и дешевле, что делает его распространённым для крупных вводов и фидеров, несмотря на необходимость увеличения сечения?","opts":["Медь с серебряным покрытием","Медь","Лужёная медь","Алюминий"],"re":"Алюминий легче и дешевле меди, поэтому он широко используется для крупных фидеров и вводов, хотя его сечение приходится увеличивать для равной ampacity. См. NEC Table 310.16."},
  {"id":167,"q":"Если начальная защита от перегрузки, выбранная на уровне 125% от FLA с таблички, срабатывает во время нормального пускового цикла двигателя, что разрешает NEC 430.32 в качестве решения?","opts":["Полностью убрать защиту от перегрузки","Заменить двигатель на блок большей мощности","Уменьшить сечение проводника ответвления","Увеличить уставку срабатывания защиты от перегрузки до более высокого разрешённого максимума (например, до 140% от FLA)"],"re":"NEC 430.32(C) допускает увеличение размера защиты от перегрузки до более высокого максимума (например, до 140% для двигателей с SF 1.15+), когда начального значения недостаточно для запуска двигателя."},
  {"id":168,"q":"Устройство GFCI предназначено для размыкания цепи при обнаружении дисбаланса тока примерно какой величины между фазным и нейтральным проводниками?","opts":["0,5 ампера","20 миллиампер","4–6 миллиампер","5 ампер"],"re":"GFCI класса A предназначен для срабатывания, когда разница между токами фазного и заземлённого проводников достигает примерно 4–6 миллиампер, защищая от поражения током."},
  {"id":169,"q":"Однофазный двигатель 7,5 HP с КПД 90 процентов работает от 240 В; какова приблизительная входная мощность?","opts":["6217 Вт","5036 Вт","5595 Вт","4500 Вт"],"re":"Выход = 7,5 x 746 = 5595 Вт; вход = 5595/0,90 = 6217 Вт."},
  {"id":170,"q":"После электрического инцидента или всякий раз, когда статус цепи неясен, какое предположение работнику безопаснее всего сделать?","opts":["Предположить, что цепь обесточена, чтобы сэкономить время на проверке","Предположить, что автомат сработал и отключил короткое замыкание","Рассматривать все проводники и части как находящиеся под напряжением, пока обесточивание не подтверждено электробезопасным рабочим состоянием","Предположить, что другой работник уже заблокировал её"],"re":"Cal/OSHA и NFPA 70E требуют рассматривать проводники и части цепи как находящиеся под напряжением, пока не создано и не проверено электробезопасное рабочее состояние, поскольку непроверенные предположения об обесточивании вызывают многие электротравмы."},
  {"id":171,"q":"Четыре токоведущих проводника с базовой ampacity 90°C по 55 A каждый собраны в пучок в трубе; какова скорректированная ampacity?","opts":["55 A","49.5 A","44 A","38.5 A"],"re":"Для 4-6 проводников коэффициент снижения 80%, поэтому 55 × 0.80 = 44 A. См. NEC Table 310.15(C)(1)."},
  {"id":172,"q":"Однофазный трансформатор имеет первичное напряжение 480 В и вторичное 120 В, каков его коэффициент трансформации?","opts":["1:4","1:2","2:1","4:1"],"re":"Коэффициент трансформации равен первичному напряжению, делённому на вторичное: 480 В / 120 В = 4:1."},
  {"id":173,"q":"Цепь 120 В питает нагрузку на расстоянии 150 футов; если потеря напряжения в обе стороны составляет 3,6 В, какой процент напряжения источника теряется?","opts":["0,3 процента","1 процент","6 процентов","3 процента"],"re":"Процент потери = 3,6/120 x 100 = 3 процента."},
  {"id":174,"q":"При установке электрической металлической трубки (EMT) на стене, на каком максимальном расстоянии от каждой распределительной коробки, соединительной коробки или другого окончания кабелепровода должен быть надёжно закреплён raceway?","opts":["18 дюймов","10 футов","3 фута","5 футов"],"re":"Согласно NEC 358.30, EMT должна быть надёжно закреплена в пределах 3 футов от каждой распределительной коробки, соединительной коробки, шкафа или фитинга."},
  {"id":175,"q":"При каком приблизительно уровне переменного тока частотой 60 Гц, проходящего через тело человека, человек обычно теряет способность отпустить проводник из-за сокращения мышц?","opts":["Около 1 мА","Около 500 мА","Около 100 мА","Около 10–16 мА"],"re":"Порог отпускания для большинства взрослых составляет примерно 10–16 мА; выше этого мышцы сокращаются, и пострадавший не может отпустить проводник под напряжением."},
  {"id":176,"q":"В сбалансированной трёхфазной системе, соединённой звездой, какова связь между линейным напряжением и фазным напряжением?","opts":["Линейное напряжение равно фазному напряжению","Линейное напряжение равно фазному напряжению, умноженному на 3","Линейное напряжение равно фазному напряжению, делённому на 1.732","Линейное напряжение равно фазному напряжению, умноженному на 1.732"],"re":"При соединении звездой линейное напряжение = фазное напряжение × √3 (1.732), а линейный ток равен фазному току."},
  {"id":177,"q":"Какое устройство предназначено для обнаружения опасных дуговых условий в проводке ответвлённой цепи и требуется для спален жилого помещения?","opts":["GFCI","Устройство защиты от перенапряжений","Розетка с изолированным заземлением","AFCI"],"re":"NEC 210.12 требует защиту от дугового пробоя (AFCI) для ответвлённых цепей, питающих выходы в спальнях жилья, которые обнаруживают дуговые замыкания."},
  {"id":178,"q":"Какой измерительный прибор измеряет сопротивление изоляции проводника, прикладывая высокое постоянное напряжение?","opts":["Токоизмерительные клещи","Прибор для проверки чередования фаз","Мегомметр (megger)","Бесконтактный индикатор напряжения"],"re":"Мегомметр (megger) прикладывает высокое испытательное постоянное напряжение (например, 500 В или 1000 В) для измерения сопротивления изоляции в мегомах."},
  {"id":179,"q":"Какое максимальное суммарное число градусов изгибов допускается на участке кабелепровода между точками протяжки, такими как коробки или соединительные корпуса?","opts":["180 градусов","540 градусов","270 градусов","360 градусов"],"re":"NEC ограничивает суммарное число изгибов между точками протяжки максимум 360 градусами (эквивалент четырёх изгибов по 90 градусов) для кабелепроводов, таких как EMT, RMC, IMC и PVC."},
  {"id":180,"q":"Какой приблизительно уровень тока через тело обычно считается порогом восприятия, когда человек едва ощущает покалывание?","opts":["Около 1 мА","Около 50 мА","Около 200 мА","Около 1000 мА"],"re":"Порог восприятия для большинства людей составляет около 1 мА и вызывает слабое ощущение покалывания."},
  {"id":181,"q":"Какова полная мощность трёхфазной нагрузки, работающей при линейном напряжении 480 В и потребляющей 50 А на линию?","opts":["72 000 ВА","24 000 ВА","41 569 ВА","13 856 ВА"],"re":"Трёхфазная полная мощность S = √3 × VL × IL = 1.732 × 480 × 50 = 41 569 ВА."},
  {"id":182,"q":"Какой прибор позволяет считывать ток в проводнике без разрыва цепи и отсоединения проводов?","opts":["Мегомметр","Токоизмерительные клещи","Прибор для проверки изоляции","Прибор для проверки целостности цепи"],"re":"Токоизмерительные клещи измеряют ток, считывая магнитное поле вокруг проводника, поэтому цепь не нужно размыкать."},
  {"id":183,"q":"Кабель в неметаллической оболочке (тип NM), проложенный по поверхности элементов каркаса, должен быть закреплён с интервалами, не превышающими какое расстояние?","opts":["4 1/2 фута","3 фута","6 футов","10 футов"],"re":"Согласно NEC 334.30, кабель типа NM должен быть закреплён с интервалами, не превышающими 4 1/2 фута."},
  {"id":184,"q":"Токи в диапазоне примерно 100–200 мА через грудную клетку особенно опасны главным образом потому, что они могут вызвать какое опасное для жизни состояние?","opts":["Только лёгкие ожоги кожи","Мышечные судороги, которые быстро проходят","Временную потерю слуха","Фибрилляцию желудочков сердца"],"re":"Токи около 100–200 мА через грудную клетку могут вызвать фибрилляцию желудочков сердца, которая часто смертельна без немедленного вмешательства."},
  {"id":185,"q":"Трёхфазный двигатель на 240 В выдаёт 30 кВт активной мощности при коэффициенте мощности 0.85; какой примерно линейный ток он потребляет?","opts":["72 А","85 А","104 А","60 А"],"re":"IL = P / (√3 × VL × PF) = 30 000 / (1.732 × 240 × 0.85) = 84.9 А ≈ 85 А."},
  {"id":186,"q":"Кабель типа NM должен быть закреплён на каком максимальном расстоянии от каждой распределительной коробки, соединительной коробки или шкафа, где кабель входит?","opts":["12 дюймов","24 дюйма","18 дюймов","8 дюймов"],"re":"Согласно NEC 334.30, кабель NM должен быть закреплён в пределах 12 дюймов от каждой распределительной коробки, соединительной коробки, шкафа или фитинга."},
  {"id":187,"q":"Защита AFCI обычно требуется для ответвлённых цепей, питающих выходы в какой из следующих зон жилья?","opts":["Ванные комнаты","Уличные террасы","Отдельно стоящие неотапливаемые гаражи","Спальни и гостиные"],"re":"NEC 210.12(A) требует защиту AFCI для ответвлённых цепей, питающих выходы в жилых зонах, таких как спальни, гостиные, семейные комнаты и подобные помещения."},
  {"id":188,"q":"Идеальный понижающий трансформатор с коэффициентом 10:1 несёт 5 А в первичной обмотке, каков приблизительный ток во вторичной обмотке?","opts":["0,5 А","50 А","5 А","15 А"],"re":"В идеальном трансформаторе отношение токов обратно коэффициенту трансформации, поэтому при 10:1 первичные 5 А дают около 50 А во вторичной обмотке."},
  {"id":189,"q":"Когда в кабелепроводе или трубке проложено более двух проводников, какой максимально допустимый коэффициент заполнения проводниками в процентах от площади поперечного сечения raceway?","opts":["31 процент","40 процентов","53 процента","60 процентов"],"re":"Согласно NEC, Глава 9, Таблица 1, когда в raceway проложено более 2 проводников, максимальное заполнение составляет 40 процентов площади поперечного сечения."},
  {"id":190,"q":"В сбалансированной трёхфазной системе, соединённой треугольником, какова связь между линейным током и фазным током обмотки?","opts":["Линейный ток равен фазному току","Линейный ток равен фазному току, делённому на 1.732","Линейный ток равен фазному току, умноженному на 3","Линейный ток равен фазному току, умноженному на 1.732"],"re":"При соединении треугольником линейный ток = фазный ток × √3 (1.732), а линейное напряжение равно фазному напряжению."},
  {"id":191,"q":"Устройство защитного отключения класса A (GFCI) рассчитано на срабатывание, когда разница тока между фазным и нейтральным проводниками достигает примерно какого значения?","opts":["500 мА","30 мА","100 мА","5 мА"],"re":"GFCI класса A срабатывает при токе утечки на землю около 5 мА (номинально 4–6 мА) — уровень, выбранный для защиты людей от смертельного поражения током."},
  {"id":192,"q":"В сбалансированном трёхфазном трансформаторе со схемой звезда, как линейное напряжение соотносится с фазным (обмоточным) напряжением?","opts":["Линейное напряжение в корень из 3 раз больше фазного напряжения","Линейное напряжение составляет половину фазного напряжения","Линейное напряжение в 3 раза больше фазного напряжения","Линейное напряжение равно фазному напряжению"],"re":"В схеме звезда линейное напряжение равно фазному напряжению, умноженному на корень из 3 (примерно 1,732), а линейный и фазный токи равны."},
  {"id":193,"q":"Одиночный изолированный проводник, проложенный в кабелепроводе один, может заполнять максимум какой процент площади поперечного сечения raceway?","opts":["31 процент","40 процентов","53 процента","60 процентов"],"re":"Согласно NEC, Глава 9, Таблица 1, для одного проводника в raceway допускается максимальное заполнение 53 процента."},
  {"id":194,"q":"Трёхфазная система звезда имеет фазное напряжение 277 В; каково примерно линейное напряжение?","opts":["277 В","480 В","831 В","160 В"],"re":"Линейное напряжение звезды = фазное напряжение × √3 = 277 × 1.732 = 480 В."},
  {"id":195,"q":"Какую главную опасность призвана уменьшить защита AFCI?","opts":["Пожары, вызванные дуговыми замыканиями","Поражение человека электрическим током","Падение напряжения на длинных линиях","Перегрузка нейтральных проводников"],"re":"Устройства AFCI предназначены для обесточивания цепи при обнаружении дугового замыкания, снижая риск пожаров от искрения в проводке, согласно NEC 210.12."},
  {"id":196,"q":"Согласно OSHA 1926.404, что из перечисленного лучше всего описывает требование к GFCI для розеток 125 В, однофазных, на 15 и 20 А, используемых работниками на стройплощадке?","opts":["Защита GFCI требуется только во время дождя","Защита GFCI никогда не требуется на улице","Защита GFCI требуется для всех таких розеток, не являющихся частью постоянной проводки","Защита GFCI применяется только к цепям 240 В"],"re":"OSHA требует защиту GFCI для всех розеток 125 В, однофазных, на 15, 20 и 30 А, которые не являются частью постоянной проводки и используются работниками."},
  {"id":197,"q":"Какова основная цель использования прибора для проверки чередования фаз перед подключением трёхфазного двигателя?","opts":["Измерить сопротивление изоляции","Проверить последовательность фаз, чтобы двигатель вращался в правильном направлении","Измерить сопротивление заземляющего электрода","Проверить целостность проводника"],"re":"Прибор для проверки чередования фаз подтверждает последовательность A-B-C, чтобы трёхфазный двигатель вращался в нужном направлении при включении."},
  {"id":198,"q":"Когда в кабелепроводе проложено ровно два проводника, какое максимальное заполнение проводниками допускается в процентах от площади поперечного сечения raceway?","opts":["60 процентов","40 процентов","53 процента","31 процент"],"re":"Согласно NEC, Глава 9, Таблица 1, два проводника в raceway ограничены максимальным заполнением 31 процент."},
  {"id":199,"q":"Какова активная мощность, потребляемая трёхфазной нагрузкой при 208 В, потребляющей 40 А на линию при коэффициенте мощности 0.9?","opts":["14 400 Вт","8 320 Вт","16 000 Вт","12 973 Вт"],"re":"P = √3 × VL × IL × PF = 1.732 × 208 × 40 × 0.9 = 12 973 Вт."},
  {"id":200,"q":"На стройплощадке OSHA 1926.404 разрешает работодателю использовать программу обеспечения заземляющего проводника как альтернативу какой защитной мере?","opts":["Процедурам блокировки/маркировки (lockout/tagout)","Требованиям к каскам","Системам индивидуальной защиты от падения","Защите GFCI на временных розетках"],"re":"Программа обеспечения заземляющего проводника является допустимой альтернативой защите GFCI для розеток, не являющихся частью постоянной проводки."},
  {"id":201,"q":"При использовании цифрового мультиметра в режиме измерения сопротивления (ом), при каком условии должна тестироваться цепь?","opts":["Под полной нагрузкой и напряжением","При пониженном напряжении","Под напряжением без нагрузки","Обесточенной, без напряжения"],"re":"Измерения сопротивления и целостности выполняются на обесточенной цепи, так как приложенное напряжение даёт ложные показания и может повредить прибор."},
  {"id":202,"q":"Когда кабель или кабелепровод проходит через деревянную стойку и край просверленного отверстия находится менее чем в 1 1/4 дюйма от ближайшего края стойки, какая защита требуется?","opts":["Стальная пластина или втулка толщиной не менее 1/16 дюйма","Дополнительная защита не требуется","Обмотка кабеля изолентой","Удвоение интервала установки скоб"],"re":"Согласно NEC 300.4(A), когда отверстие находится менее чем в 1 1/4 дюйма от ближайшего края, стальная пластина или втулка толщиной не менее 1/16 дюйма должна защищать проводку от шурупов и гвоздей."},
  {"id":203,"q":"Трёхфазная система 480 В линейного напряжения соединена звездой; какое напряжение от любой линии до нейтрали?","opts":["480 В","277 В","240 В","831 В"],"re":"Напряжение линия-нейтраль (фазное) = линейное напряжение ÷ √3 = 480 ÷ 1.732 = 277 В."},
  {"id":204,"q":"В новом жилом помещении розетки 125 В, 15 и 20 А, установленные в зонах, указанных Кодексом, должны быть какого типа, чтобы препятствовать вставке посторонних предметов детьми?","opts":["Влагостойкие","Защищённые от вскрытия (tamper-resistant)","С изолированным заземлением","Больничного класса"],"re":"NEC 406.12 требует сертифицированные защищённые от вскрытия (TR) розетки для розеток 125 В, 15 и 20 А в жилых помещениях, которые имеют внутренние шторки, препятствующие вставке предметов."},
  {"id":205,"q":"Какой тип raceway наиболее подвержен коррозии и НЕ подходит для сильно коррозионной среды без дополнительной защиты от коррозии?","opts":["Электрическая металлическая трубка (EMT)","PVC Schedule 40","Жёсткий металлический кабелепровод (RMC)","Промежуточный металлический кабелепровод (IMC)"],"re":"Согласно NEC 358.10, EMT и её фитинги подвержены коррозии и требуют дополнительной защиты в сильно коррозионных условиях, в отличие от PVC."},
  {"id":206,"q":"В рамках программы обеспечения заземляющего проводника каждый удлинитель и розетка, не входящие в постоянную проводку, должны как минимум проверяться на непрерывность и правильность подключения заземляющего проводника с какой периодичностью?","opts":["Перед первым использованием, после ремонта и не реже одного раза в 3 месяца","Один раз в год","Только когда инструмент выходит из строя","Один раз в 5 лет"],"re":"OSHA требует проверки перед первым использованием, после ремонта, после подозрения на повреждение и с интервалом не более 3 месяцев (6 месяцев для стационарных розеток, не подверженных повреждению)."},
  {"id":207,"q":"Трансформатор buck-boost чаще всего используется для выполнения какого из следующих действий?","opts":["Небольшая коррекция напряжения, например повышение 208 В примерно до 230 В","Преобразование однофазного питания в трёхфазное","Полная гальваническая развязка между двумя крупными системами","Понижение первичной обмотки до отдельно выделенного питания 120/240 В"],"re":"Трансформатор buck-boost подключается как автотрансформатор для небольшой процентной корректировки напряжения, например понижения или повышения примерно на 5–20 процентов."},
  {"id":208,"q":"Однофазный трансформатор имеет первичное напряжение 480 В и вторичное напряжение 120 В; каков коэффициент трансформации?","opts":["4:1","1:4","2:1","6:1"],"re":"Коэффициент трансформации = первичное напряжение ÷ вторичное напряжение = 480 ÷ 120 = 4, то есть 4:1."},
  {"id":209,"q":"Жёсткий PVC кабелепровод (Schedule 40), установленный на стене, должен быть надёжно закреплён в пределах какого расстояния от каждой коробки, шкафа или другого окончания кабелепровода?","opts":["18 дюймов","8 футов","3 фута","5 футов"],"re":"Согласно NEC 352.30, жёсткий PVC кабелепровод должен быть надёжно закреплён в пределах 3 футов от каждой коробки, шкафа, соединительного корпуса или другого окончания."},
  {"id":210,"q":"В программе обеспечения заземляющего проводника какая из следующих проверок должна выполняться на каждом удлинителе и розетке?","opts":["Измерение выцветания цвета проводника","Проверка электрической непрерывности всех заземляющих проводников","Проверка только прочности шнура на разрыв","Проверка даты гарантии производителя"],"re":"Каждый удлинитель и розетка должны проверяться для подтверждения того, что заземляющий проводник электрически непрерывен и правильно подключён к своему контакту."},
  {"id":211,"q":"Перед подачей напряжения на вновь установленный распределительный щит, какую пусконаладочную проверку следует выполнить на всех соединениях?","opts":["Подать полный ток нагрузки и наблюдать за нагревом","Включить и считать напряжение на каждом автомате","Убедиться, что каждый зажим затянут с моментом, указанным производителем","Распылить очиститель контактов на каждый зажим"],"re":"Ключевой шаг наладки перед подачей напряжения — затянуть все соединения с моментом, указанным производителем, калиброванным динамометрическим инструментом, чтобы предотвратить слабые соединения с высоким сопротивлением."},
  {"id":212,"q":"Трансформатор с коэффициентом трансформации 10:1 имеет 240 В на первичной обмотке; каково вторичное напряжение (без учёта потерь)?","opts":["24 В","120 В","10 В","2 400 В"],"re":"Вторичное напряжение = первичное напряжение ÷ коэффициент трансформации = 240 ÷ 10 = 24 В."},
  {"id":213,"q":"Компенсационный фитинг (expansion fitting) требуется устанавливать на участке жёсткого PVC кабелепровода для компенсации какого условия?","opts":["Электромагнитных помех","Падения напряжения на больших расстояниях","Избыточного заполнения проводниками","Теплового расширения и сжатия кабелепровода"],"re":"Согласно NEC 352.44, компенсационные фитинги должны устанавливаться для компенсации теплового расширения и сжатия, когда ожидаемое изменение длины составляет 1/4 дюйма или более."},
  {"id":214,"q":"Какая особенность отличает защищённую от вскрытия розетку от стандартной?","opts":["Внутренние подпружиненные шторки над прорезями","Более высокий номинальный ток","Водонепроницаемая прокладка","Встроенный подавитель перенапряжений"],"re":"Защищённые от вскрытия розетки (NEC 406.12) используют внутренние подпружиненные шторки, которые открываются только при одновременной вставке обоих контактов вилки, блокируя вставку одного предмета."},
  {"id":215,"q":"Какой метод используется для измерения сопротивления забитого заземляющего стержня относительно земли?","opts":["Проверка целостности мультиметром в режиме ом","Трёхточечный метод падения потенциала для измерения сопротивления заземления","Проверка сопротивления изоляции мегомметром","Измерение тока клещами на вводном проводнике"],"re":"Сопротивление заземляющего электрода обычно измеряется трёхточечным методом падения потенциала со вспомогательными электродами или клещевым измерителем сопротивления заземления."},
  {"id":216,"q":"Портативная электрическая дрель, отмеченная символом квадрата внутри квадрата, называется двойной изоляции; что означает это обозначение в отношении инструмента?","opts":["Она использует два независимых слоя изоляции и не требует заземляющего проводника","Она всегда должна подключаться к GFCI для безопасности","Она рассчитана только на использование во влажных местах","Она содержит две внутренние батареи"],"re":"Символ квадрата внутри квадрата обозначает инструмент двойной изоляции, который обеспечивает две независимые системы изоляции и поэтому не требует заземляющего проводника."},
  {"id":217,"q":"Каков ток полной нагрузки на вторичной обмотке однофазного трансформатора 25 кВА с вторичным напряжением 240 В?","opts":["60 А","104 А","208 А","10 А"],"re":"Ток вторичной обмотки однофазного трансформатора = кВА × 1000 ÷ В = 25 000 ÷ 240 = 104 А."},
  {"id":218,"q":"В стандартной распределительной коробке какой объём в кубических дюймах должен быть выделен на каждый проводник 14 AWG при расчёте заполнения коробки?","opts":["1.5 кубических дюйма","2.5 кубических дюйма","2.25 кубических дюйма","2.0 кубических дюйма"],"re":"Согласно NEC Таблица 314.16(B), каждый проводник 14 AWG требует выделения объёма 2.0 кубических дюйма."},
  {"id":219,"q":"Трёхфазный трансформатор рассчитан на 75 кВА с вторичным напряжением 208 В; каков примерный ток полной нагрузки вторичной линии?","opts":["208 А","625 А","360 А","104 А"],"re":"Трёхфазный ток = кВА × 1000 ÷ (√3 × В) = 75 000 ÷ (1.732 × 208) = 208 А."},
  {"id":220,"q":"Бесконтактный индикатор напряжения лучше всего подходит для какой задачи?","opts":["Измерение точного межфазного напряжения","Измерение коэффициента трансформации трансформатора","Измерение потребляемого тока на фидере","Быстрое определение наличия напряжения без касания проводника"],"re":"Бесконтактный индикатор напряжения считывает электрическое поле и показывает наличие напряжения, но не отображает точное значение."},
  {"id":221,"q":"Заземляемый портативный электроинструмент с трёхштырьковой вилкой подключён к двухпроводной розетке через переходник, у которого заземляющий хвостик оставлен неподключённым; в чём основная опасность?","opts":["Металлический корпус инструмента не имеет пути к земле при внутреннем повреждении","Инструмент будет работать в обратную сторону","Инструмент будет потреблять чрезмерный ток и отключит автомат","Инструмент перегреет розетку"],"re":"Без подключённого заземляющего хвостика повреждение на металлический корпус инструмента оставляет корпус под напряжением без низкоомного пути к земле, подвергая пользователя поражению током."},
  {"id":222,"q":"При расчёте заполнения коробки какой объём в кубических дюймах должен быть выделен на каждый проводник 12 AWG?","opts":["2.25 кубических дюйма","2.0 кубических дюйма","2.5 кубических дюйма","3.0 кубических дюйма"],"re":"Согласно NEC Таблица 314.16(B), каждый проводник 12 AWG требует выделения объёма 2.25 кубических дюйма."},
  {"id":223,"q":"Розетка 15 или 20 А, 125 В, установленная на улице во влажном или мокром месте, должна быть сертифицирована как какой тип?","opts":["Только защищённая от вскрытия","Самозаземляющаяся","Больничного класса","Влагостойкая (WR)"],"re":"NEC 406.9(A) и (B) требуют, чтобы розетки во влажных или мокрых местах были влагостойкого типа (WR), сертифицированного для таких условий."},
  {"id":224,"q":"Если понижающий трансформатор имеет вторичный ток 100 А и коэффициент трансформации 5:1, каков примерный первичный ток (без учёта потерь)?","opts":["500 А","20 А","100 А","25 А"],"re":"Первичный ток = вторичный ток ÷ коэффициент трансформации = 100 ÷ 5 = 20 А (ток обратно пропорционален коэффициенту напряжения)."},
  {"id":225,"q":"При расчёте заполнения коробки как учитываются все заземляющие проводники оборудования, входящие в коробку, независимо от их количества?","opts":["Каждый заземляющий проводник считается как один отдельный проводник","Они вообще не учитываются","Все заземляющие проводники вместе считаются как объём одного проводника на основе самого большого из них","Они считаются вдвойне из-за требования к соединению"],"re":"Согласно NEC 314.16(B)(5), все заземляющие проводники оборудования вместе считаются как объём одного проводника на основе самого большого из присутствующих заземляющих проводников."},
  {"id":226,"q":"Для однофазного трансформатора 25 кВА с вторичным напряжением 240 В, каков приблизительный ток полной нагрузки вторичной обмотки?","opts":["Около 60 А","Около 208 А","Около 104 А","Около 25 А"],"re":"Вторичный ток равен ВА, делённым на напряжение: 25 000 ВА / 240 В ≈ 104 А."},
  {"id":227,"q":"При работе на или рядом с открытыми токоведущими частями под напряжением какой тип переносной лестницы рекомендуется для снижения риска поражения током?","opts":["Алюминиевая лестница","Стальная лестница","Магниевая лестница","Лестница из стеклопластика (непроводящая)"],"re":"Лестница из стеклопластика имеет непроводящие боковые стойки, что делает её правильным выбором рядом с токоведущими частями, где металлическая лестница могла бы стать электрическим путём."},
  {"id":228,"q":"При расчёте заполнения коробки сколько объёмов проводников учитывается для одного устройства, такого как розетка или выключатель, установленного на ярме или скобе?","opts":["Один на основе самого большого проводника, подключённого к устройству","Два на основе самого большого проводника, подключённого к устройству","Три независимо от сечения проводника","Ноль, так как устройства не учитываются"],"re":"Согласно NEC 314.16(B)(4), каждое ярмо или скоба, содержащая одно или несколько устройств, учитывается как два объёма проводников на основе самого большого подключённого к ней проводника."},
  {"id":229,"q":"Трансформатор какой мощности в кВА минимально требуется для питания однофазной нагрузки 240 В, потребляющей 80 А?","opts":["10 кВА","19.2 кВА","33.3 кВА","15 кВА"],"re":"кВА = В × А ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 кВА."},
  {"id":230,"q":"При наладке отдельно выделенной системы от сухого трансформатора, где должно выполняться заземление (соединение) системы?","opts":["На конце нагрузки каждой ответвлённой цепи","Только на трансформаторе энергокомпании","У источника, соединяя вторичный нейтраль с заземляющим электродом","На каждой отдельной розетке"],"re":"Отдельно выделенная система должна иметь заземлённый (нейтральный) проводник, соединённый с заземляющим электродом у источника, обычно системной соединительной перемычкой на трансформаторе."},
  {"id":231,"q":"Электрик должен заменить светильник, расположенный рядом с токоведущими воздушными проводниками под напряжением, и выбирает лестницу; какой из следующих вариантов наименее подходящий?","opts":["Сухая деревянная лестница","Алюминиевая раздвижная лестница","Лестница из стеклопластика","Непроводящая стремянка"],"re":"Алюминиевая лестница проводит ток и наименее подходит рядом с токоведущими проводниками; вместо неё следует использовать стеклопластиковые или другие непроводящие лестницы."},
  {"id":232,"q":"Розетка 15 или 20 А, 125 В в мокром месте должна иметь корпус, который является водонепроницаемым при каком условии?","opts":["Только когда крышка закрыта","Независимо от того, вставлена вилка или нет","Только когда вилка не вставлена","Только в сухую погоду"],"re":"NEC 406.9(B)(1) требует, чтобы розетки в мокрых местах имели водонепроницаемый корпус (крышку 'in-use'/'while-in-use'), который остаётся водонепроницаемым независимо от того, вставлена вилка или нет."},
  {"id":233,"q":"Какой из следующих методов прокладки является гибким и обычно используется для окончательного подключения к двигателю с целью уменьшения передачи вибрации и шума?","opts":["Жёсткий металлический кабелепровод (RMC)","PVC Schedule 80","Электрическая металлическая трубка (EMT)","Гибкий металлический кабелепровод (FMC)"],"re":"Согласно NEC Статья 348, гибкий металлический кабелепровод (FMC) используется там, где требуется гибкость, например для подключения двигателей, для гашения вибрации."},
  {"id":234,"q":"Однофазный трансформатор понижает 7 200 В до 240 В; если первичная обмотка потребляет 5 А, каков примерный вторичный ток (без учёта потерь)?","opts":["0.17 А","30 А","150 А","300 А"],"re":"Вторичный ток = первичный ток × (первичное В ÷ вторичное В) = 5 × (7200 ÷ 240) = 5 × 30 = 150 А."},
  {"id":235,"q":"Если мегомметр показывает очень низкое или близкое к нулю сопротивление изоляции между проводником и землёй, что это, скорее всего, означает?","opts":["Отличную изоляцию","Правильно заземлённую систему, не требующую действий","Обрыв цепи","Пробой изоляции или замыкание на землю"],"re":"Очень низкое показание сопротивления изоляции указывает на повреждённую или ухудшившуюся изоляцию либо путь утечки на землю, что необходимо устранить до подачи напряжения."},
  {"id":236,"q":"Если вы обнаружили коллегу, который всё ещё контактирует с проводником под напряжением и не может отпустить его, какое первое действие правильное?","opts":["Немедленно схватить пострадавшего и оттащить голыми руками","Облить пострадавшего водой, чтобы охладить ожоги","Обесточить цепь или использовать непроводящий предмет, чтобы отделить пострадавшего от источника","Начать компрессии грудной клетки, пока пострадавший под напряжением"],"re":"Сначала необходимо устранить источник электричества, отключив питание или используя непроводящее средство для освобождения пострадавшего, прежде чем прикасаться к нему или начинать СЛР."},
  {"id":237,"q":"Какой гибкий raceway специально сертифицирован и подходит для использования во влажных местах и сырой среде, где могут присутствовать жидкости?","opts":["Гибкий металлический кабелепровод (FMC)","Жидконепроницаемый гибкий металлический кабелепровод (LFMC)","Электрическая неметаллическая трубка (ENT) без фитингов","Стандартная EMT без водонепроницаемых фитингов"],"re":"Согласно NEC Статья 350, жидконепроницаемый гибкий металлический кабелепровод (LFMC) имеет жидконепроницаемую внешнюю оболочку, что делает его пригодным для влажных мест; стандартный FMC не подходит."},
  {"id":238,"q":"Согласно таблице NEC 430.248, ток полной нагрузки однофазного двигателя 240 В, 5 л.с. составляет примерно:","opts":["28 А","15 А","56 А","8 А"],"re":"Таблица NEC 430.248 указывает для двигателя 5 л.с. однофазного 230 В (применяется для 240 В) ток полной нагрузки 28 А."},
  {"id":239,"q":"В трёхфазной обмотке трансформатора со схемой треугольник, как линейный ток связан с фазным (обмоточным) током?","opts":["Линейный ток в 3 раза больше фазного тока","Линейный ток равен фазному току","Линейный ток составляет одну треть фазного тока","Линейный ток в корень из 3 раз больше фазного тока"],"re":"В схеме треугольник линейный ток равен фазному току, умноженному на корень из 3, а линейное и фазное напряжения равны."},
  {"id":240,"q":"Электрическую неметаллическую трубку (ENT) обычно НЕ разрешается устанавливать в каком из следующих мест?","opts":["Открыто там, где подвержено механическим повреждениям","Скрыто внутри стен, полов и потолков","Над подвесным потолком в одноэтажном здании","Заделанной в бетонную плиту"],"re":"Согласно NEC 362.12, ENT не разрешается там, где она подвержена механическим повреждениям, поскольку её неметаллический материал обеспечивает ограниченную механическую защиту."},
  {"id":241,"q":"Крышка, которая сохраняет наружную розетку водонепроницаемой даже когда шнур вставлен, обычно называется как?","opts":["Заподлицо установленная крышка","Глухая крышка","Прокладка лицевой панели","Крышка 'in-use' (while-in-use)"],"re":"Крышка 'in-use' или 'while-in-use' (NEC 406.9(B)(1)) — это корпус пузырькового типа, который сохраняет водонепроницаемость, пока вилка и шнур остаются вставленными в мокром месте."},
  {"id":242,"q":"После того как пострадавший от удара током безопасно отделён от источника электричества и у него отсутствуют пульс и дыхание, какой следующий шаг правильный?","opts":["Подождать, пока заживут ожоги, прежде чем действовать","Начать СЛР и поручить кому-либо вызвать экстренные службы","Дать пострадавшему воды попить","Перенести пострадавшего в машину и ехать в больницу без дальнейшей помощи"],"re":"Как только пострадавший освобождён от источника и у него нет пульса или дыхания, немедленно начинайте СЛР и обеспечьте вызов экстренной медицинской помощи."},
  {"id":243,"q":"При выборе проводников ответвления для одного непрерывно работающего двигателя, какое значение тока требует использовать NEC?","opts":["Фактически измеренный ток двигателя","Ток заторможенного ротора","Значение тока полной нагрузки из таблиц двигателей NEC","Ток с шильдика, делённый на 1.25"],"re":"NEC 430.6(A) требует использовать значения тока полной нагрузки из таблиц 430.247–430.250, а не ток с шильдика, для выбора проводников."},
  {"id":244,"q":"Кабель типа AC (бронированный) должен быть закреплён с интервалами, не превышающими какое расстояние, при установке вдоль элементов каркаса?","opts":["3 фута","8 футов","4 1/2 фута","6 футов"],"re":"Согласно NEC 320.30, кабель типа AC должен быть закреплён с интервалами, не превышающими 4 1/2 фута."},
  {"id":245,"q":"Какая функция прибора правильна для проверки исправности предохранителя без извлечения его из обесточенного держателя?","opts":["Переменное напряжение","Измерение тока клещами","Целостность (ом)","Сопротивление изоляции"],"re":"На обесточенной цепи функция целостности (ом) показывает низкое сопротивление через исправный предохранитель и обрыв через перегоревший."},
  {"id":246,"q":"Почему опасно прикасаться к пострадавшему от удара током, который всё ещё контактирует с источником под напряжением, до того как питание отключено?","opts":["Пострадавший может быть носителем заразного заболевания","Одежда пострадавшего может быть легковоспламеняющейся","Ток может пройти через пострадавшего и в спасателя, создав второго пострадавшего","Спасатель может повредить электрооборудование"],"re":"Если источник всё ещё под напряжением, ток может пройти через пострадавшего в спасателя, делая спасателя вторым пострадавшим от удара током."},
  {"id":247,"q":"Однофазный двигатель 230 В рассчитан на 1 л.с. и работает с КПД около 80% при единичном коэффициенте мощности; какой примерно ток он потребляет?","opts":["3.2 А","4.1 А","2.0 А","6.5 А"],"re":"Входная мощность = 746 ÷ 0.80 = 932.5 Вт; I = 932.5 ÷ 230 = 4.1 А (1 л.с. = 746 Вт)."},
  {"id":248,"q":"Какой тип кабеля специально сертифицирован для прямой укладки в землю без необходимости защитного raceway?","opts":["Кабель типа NM","Кабель типа AC","Кабель типа MC без маркировки для прямой укладки","Кабель типа UF"],"re":"Согласно NEC Статья 340, кабель типа UF (подземный фидер) сертифицирован и подходит для прямой укладки в землю."},
  {"id":249,"q":"Какова основная причина, по которой динамометрическая отвёртка или ключ предпочтительнее затяжки вручную для электрических соединений?","opts":["Прикладывает указанный производителем момент для надёжного соединения с низким сопротивлением","Увеличивает допустимую токовую нагрузку проводника","Устраняет необходимость в инструменте для зачистки","Это быстрее обычного инструмента"],"re":"Калиброванный динамометрический инструмент прикладывает точное значение, указанное производителем, предотвращая слишком слабые (перегрев) или слишком тугие (повреждение) соединения, что требуется для многих сертифицированных зажимов."},
  {"id":250,"q":"Изолированный заземлённый (нейтральный) проводник сечением 6 AWG или меньше должен идентифицироваться каким цветом?","opts":["Зелёный","Синий","Красный","Белый или серый"],"re":"NEC 200.6(A) требует, чтобы заземлённые (нейтральные) проводники сечением 6 AWG или меньше идентифицировались сплошным белым или серым внешним покрытием, либо тремя сплошными белыми/серыми полосами."},
  {"id":251,"q":"Сколько ватт равно одной лошадиной силе для расчётов электродвигателей?","opts":["550 Вт","1 000 Вт","746 Вт","1 200 Вт"],"re":"Одна лошадиная сила равна 746 ваттам, это стандартное преобразование, используемое в расчётах нагрузки двигателей."},
  {"id":252,"q":"Согласно правилам OSHA по временной проводке на стройке, гибкие шнуры и кабели для временного питания должны быть защищены от повреждений; какое состояние сделает шнур непригодным для дальнейшего использования?","opts":["Внешняя оболочка порезана или расщеплена, обнажая внутренние проводники","Шнур рассчитан на тяжёлую или особо тяжёлую эксплуатацию","Шнур окрашен в оранжевый цвет","Шнур длиннее 25 футов"],"re":"Шнур с повреждённой внешней оболочкой, обнажающей проводники, должен быть выведен из эксплуатации; одна лишь длина или цвет не делают шнур непригодным."},
  {"id":253,"q":"Кабель типа NM (в неметаллической оболочке) разрешается использовать в каком из следующих мест?","opts":["Влажные места, например прямая укладка в землю","Заделанный в залитый бетон","Подверженный воздействию масел и других разрушающих агентов","Сухие места обычно сухих, некоррозионных помещений"],"re":"Согласно NEC 334.10 и 334.12, кабель типа NM разрешается в обычно сухих местах и не разрешается во влажных местах, заделанным в бетон или там, где подвержен коррозионным условиям."},
  {"id":254,"q":"Корпус и сердечник трансформатора должны быть подключены к какому проводнику для безопасности?","opts":["К незаземлённому (фазному) проводнику","К защитному проводнику заземления оборудования","Только к вторичному нейтрали на стороне нагрузки","Подключение не требуется"],"re":"Нетоковедущие металлические части трансформатора, такие как корпус и сердечник, должны быть соединены с защитным проводником заземления оборудования для безопасного отвода тока КЗ."},
  {"id":255,"q":"Согласно таблице NEC 430.250, трёхфазный двигатель 460 В, 10 л.с. имеет ток полной нагрузки примерно:","opts":["28 А","14 А","21 А","9 А"],"re":"Таблица NEC 430.250 указывает для трёхфазного двигателя 10 л.с., 460 В ток полной нагрузки 14 А."},
  {"id":256,"q":"Когда фитинги устанавливаются на кабелепроводе, входящем в корпус во влажном месте, какой тип фитинга должен использоваться?","opts":["Стандартный внутренний соединитель","Уменьшающая шайба","Дождезащищённый фитинг или фитинг для влажных мест","Фитинг с установочным винтом"],"re":"Согласно NEC 314.15 и 300.5, фитинги и корпуса, используемые во влажных местах, должны быть сертифицированы для влажных мест, чтобы предотвратить проникновение влаги."},
  {"id":257,"q":"Для временной проводки на стройплощадке гибкие шнуры обычно должны быть какого типа, чтобы выдерживать условия объекта?","opts":["Лёгкий шнур для ламп","Нескрученные оголённые проводники","Однопроводный звонковый провод","Сертифицированные для тяжёлой или особо тяжёлой эксплуатации"],"re":"Временные шнуры на объекте должны быть сертифицированы для тяжёлой или особо тяжёлой эксплуатации, чтобы оболочка выдерживала нагрузки, характерные для стройплощадок."},
  {"id":258,"q":"При запуске электрик использует токоизмерительные клещи на каждой фазе фидера трёхфазного двигателя; на что, скорее всего, указывает большой дисбаланс между фазными токами?","opts":["Двигатель работает нормально","Клещи измеряют сопротивление изоляции","Возможный дефект обмотки, слабое соединение или дисбаланс напряжения","Чередование фаз перевёрнуто"],"re":"Значительный дисбаланс тока между фазами часто указывает на развивающийся дефект обмотки, соединение с высоким сопротивлением (слабое) или дисбаланс питающего напряжения, что требует проверки."},
  {"id":259,"q":"Заземляющий проводник оборудования (EGC), когда он изолирован, идентифицируется чем из следующего?","opts":["Белый или серый","Сплошной чёрный","Зелёный, или зелёный с одной или несколькими жёлтыми полосами","Сплошной красный"],"re":"NEC 250.119 разрешает изолированному EGC быть зелёным или зелёным с одной или несколькими жёлтыми полосами; он также может быть голым."},
  {"id":260,"q":"При выборе проводников ответвления для одного двигателя длительного режима, допустимая нагрузка проводника должна составлять не менее какого процента от тока полной нагрузки двигателя?","opts":["100%","115%","125%","150%"],"re":"NEC 430.22 требует, чтобы проводники ответвления двигателя имели допустимую нагрузку не менее 125% от тока полной нагрузки двигателя."},
  {"id":261,"q":"Кабели или кабелепроводы, проложенные параллельно элементам каркаса, должны быть отодвинуты от ближайшего края элемента каркаса не менее чем на какое расстояние, чтобы избежать необходимости в защитной пластине?","opts":["3/4 дюйма","1 1/4 дюйма","1 дюйм","1 1/2 дюйма"],"re":"Согласно NEC 300.4(D), кабели, проложенные параллельно элементам каркаса, должны находиться не менее чем в 1 1/4 дюйма от ближайшего края или быть защищены стальной пластиной."},
  {"id":262,"q":"Какая практика с удлинителем на объекте является признанной угрозой безопасности?","opts":["Удаление заземляющего штыря с вилки шнура для подключения к двухконтактной розетке","Использование шнура, сертифицированного для уличного применения","Использование шнура с целой литой вилкой","Аккуратная укладка неиспользуемого шнура вне проходов"],"re":"Срезание или удаление заземляющего штыря нарушает путь заземления оборудования и является серьёзной опасностью; остальные практики допустимы."},
  {"id":263,"q":"Коэффициент спроса лучше всего описывается как:","opts":["Отношение максимального спроса к общей подключённой нагрузке","Сумма всех подключённых нагрузок","Отношение номинального напряжения к рабочему напряжению","Произведение напряжения и тока"],"re":"Согласно статье NEC 100, коэффициент спроса — это отношение максимального спроса системы к общей подключённой нагрузке, что позволяет реалистично рассчитывать размер ниже 100% подключённой нагрузки."},
  {"id":264,"q":"Какой raceway имеет самую толстую, тяжёлую стенку и обеспечивает наибольшую физическую защиту проводников?","opts":["Электрическая неметаллическая трубка (ENT)","Электрическая металлическая трубка (EMT)","Жёсткий металлический кабелепровод (RMC)","Гибкий металлический кабелепровод (FMC)"],"re":"Согласно NEC Статья 344, жёсткий металлический кабелепровод (RMC) является стальным raceway с самой толстой стенкой и обеспечивает наибольшую физическую защиту по сравнению с IMC и EMT."},
  {"id":265,"q":"Перед подачей высоковольтного теста мегомметром на цепь, что должно быть подтверждено в первую очередь?","opts":["Цепь полностью под напряжением","Цепь обесточена и изолирована, чувствительная электроника отключена","К дальнему концу подключена нагрузка","Чередование фаз правильное"],"re":"Проверка сопротивления изоляции прикладывает высокое постоянное напряжение, поэтому цепь должна быть обесточена, изолирована, а чувствительное электронное оборудование отключено для безопасности."},
  {"id":266,"q":"Удлинитель, питающий портативный инструмент, проложен через дверной проём, где его может зажать дверью; что обычно требует OSHA в отношении гибких шнуров?","opts":["Гибкие шнуры нельзя прокладывать через дверные проёмы, окна или подобные отверстия, где они могут быть повреждены","Шнуры можно прокладывать через дверные проёмы, если дверь удерживается открытой шнуром","Шнуры через дверные проёмы допустимы, если приклеены к полу","Через дверные проёмы можно прокладывать только шнуры с металлической оболочкой"],"re":"OSHA запрещает прокладку гибких шнуров через дверные проёмы, окна, отверстия в стенах или подобные проёмы, где они подвержены повреждению."},
  {"id":267,"q":"PVC Schedule 80 кабелепровод предпочтительнее PVC Schedule 40 в каком применении?","opts":["Под землёй в местах без движения транспорта","Внутри сухих внутренних стен","Внутри отделанного чердака без доступа","Там, где подвержен механическим повреждениям"],"re":"Согласно NEC 352.10, PVC Schedule 80 имеет более толстую стенку и разрешён там, где кабелепровод подвержен механическим повреждениям, тогда как Schedule 40 не разрешён."},
  {"id":268,"q":"Панель имеет 60 кВА подключённой нагрузки с применимым коэффициентом спроса 70%; какова расчётная нагрузка спроса?","opts":["60 кВА","86 кВА","18 кВА","42 кВА"],"re":"Нагрузка спроса = подключённая нагрузка × коэффициент спроса = 60 × 0.70 = 42 кВА."},
  {"id":269,"q":"Заземляющий проводник оборудования также может быть установлен как что из следующего?","opts":["Белый изолированный проводник","Серый изолированный проводник","Голый проводник","Синий изолированный проводник"],"re":"NEC 250.118 и 250.119 разрешают заземляющему проводнику оборудования быть голым проводником, в дополнение к зелёной/зелёно-жёлтой изолированной идентификации."},
  {"id":270,"q":"Две обмотки трансформатора buck-boost на 120 В подключены для повышения питания 208 В; в чём основное преимущество использования buck-boost вместо разделительного трансформатора для такой малой коррекции?","opts":["Обеспечивает полную развязку от источника","Он меньше и дешевле, так как обрабатывает только повышаемую часть нагрузки","Преобразует питание в трёхфазное","Устраняет необходимость в защите от сверхтока"],"re":"Поскольку buck-boost подключён как автотрансформатор, обрабатывающий только небольшую разницу напряжений, он физически меньше и дешевле полноценного разделительного трансформатора той же мощности."},
  {"id":271,"q":"Почему гибкие шнуры, используемые как временная проводка на стройплощадке, не должны заменять стационарную (постоянную) проводку конструкции?","opts":["Гибкие шнуры дороже постоянной проводки","Гибкие шнуры не предназначены для постоянной установки и в этой роли более подвержены повреждению и перегреву","Гибкие шнуры пропускают слишком мало тока для любого инструмента","Гибкие шнуры запрещено производить"],"re":"Гибкие шнуры не заменяют стационарную проводку, потому что они подвержены механическим повреждениям, не защищены внутри конструкции здания и могут перегреваться при постоянном использовании."},
  {"id":272,"q":"Проводник или кабель, проложенный через металлический элемент каркаса, должен быть защищён втулкой или прокладкой там, где это требуется, потому что металлический край может вызвать какой тип повреждения?","opts":["Падение напряжения","Электромагнитные помехи","Избыточный нагрев","Истирание или порез изоляции проводника"],"re":"Согласно NEC 300.4(B), когда кабели проходят через заводские или просверленные на месте отверстия в металлическом каркасе, сертифицированные втулки или прокладки защищают кабель от истирания об острые металлические края."},
  {"id":273,"q":"По стандартному методу статьи NEC 220, какое значение нагрузки общего освещения назначается на квадратный фут жилого помещения?","opts":["1 ВА на квадратный фут","2 ВА на квадратный фут","3 ВА на квадратный фут","5 ВА на квадратный фут"],"re":"Таблица NEC 220.12 назначает 3 ВА на квадратный фут для общего освещения в жилых помещениях."},
  {"id":274,"q":"Что подтверждает проверка целостности защитного проводника заземления при наладке?","opts":["Наличие непрерывного металлического пути с низким сопротивлением к источнику","Точное сопротивление относительно земли в омах","Качество изоляции проводника","Последовательность фаз питания"],"re":"Проверка целостности защитного проводника заземления подтверждает непрерывный путь с низким сопротивлением для возврата тока КЗ к источнику и срабатывания защиты от сверхтока."},
  {"id":275,"q":"Когда кабель типа NM проложен через просверленные отверстия в деревянных стойках или балках, дополнительное крепление вдоль этого участка считается выполненным, потому что отверстия обеспечивают что?","opts":["Непрерывность заземления","Опору и защиту в каждом месте прохода","Требуемое снижение нагрузки","Компенсацию расширения"],"re":"Согласно NEC 334.30, кабель NM, проложенный через просверленные отверстия в элементах каркаса, считается опираемым и закреплённым каркасом, когда интервалы не превышают пределов норм."},
  {"id":276,"q":"Токоведущие части электрооборудования, работающего при 50 В и более, обычно должны быть ограждены от случайного прикосновения; какой из следующих способов ограждения допустим?","opts":["Размещение оборудования в помещении или корпусе, доступном только квалифицированным лицам","Покраска токоведущих частей в яркий цвет","Размещение предупреждающего знака без физического барьера","Покрытие частей тонким слоем масла"],"re":"Ограждение токоведущих частей по расположению в контролируемом помещении, камере или корпусе, доступном только квалифицированным лицам, является принятым методом; одного знака или краски недостаточно."},
  {"id":277,"q":"Какова нагрузка общего освещения для жилья площадью 2 000 квадратных футов жилого пространства по стандартному расчёту?","opts":["6 000 ВА","4 000 ВА","2 000 ВА","10 000 ВА"],"re":"Общее освещение = площадь × 3 ВА/фут² = 2 000 × 3 = 6 000 ВА."},
  {"id":278,"q":"Какой цвет НЕ разрешается использовать для идентификации незаземлённого (фазного) проводника?","opts":["Белый","Красный","Чёрный","Синий"],"re":"Незаземлённые проводники могут быть любого цвета, кроме белого, серого или зелёного (которые зарезервированы для заземлённых и заземляющих проводников); белый зарезервирован для заземлённого проводника согласно NEC 200.6/200.7."},
  {"id":279,"q":"Идеальный трансформатор повышает 240 В до 480 В; если нагрузка на стороне 480 В потребляет 10 А, каков приблизительный первичный ток (без учёта потерь)?","opts":["20 А","10 А","5 А","40 А"],"re":"Для идеального трансформатора входная мощность равна выходной, поэтому первичный ток = вторичные ВА / первичное напряжение: (480 В × 10 А) / 240 В = 20 А."},
  {"id":280,"q":"Какое максимальное расстояние между опорами жёсткого металлического кабелепровода (RMC) типоразмера 1/2 - 3/4, установленного открыто прямым горизонтальным участком?","opts":["6 футов","16 футов","10 футов","12 футов"],"re":"Согласно NEC Таблица 344.30(B)(2), RMC типоразмера 1/2 и 3/4 требует расстояния между опорами не более 10 футов."},
  {"id":281,"q":"Сколько вольт-ампер требует NEC для каждой из двух минимальных цепей мелких бытовых приборов в расчёте нагрузки жилья?","opts":["1 000 ВА каждая","1 500 ВА каждая","2 000 ВА каждая","3 000 ВА каждая"],"re":"NEC 220.52(A) требует рассчитывать каждую цепь мелких бытовых приборов на 1 500 ВА."},
  {"id":282,"q":"Основная цель ограждения токоведущих частей в электрооборудовании заключается в чём из следующего?","opts":["Улучшить внешний вид установки","Повысить номинальное напряжение проводников","Снизить стоимость оборудования","Предотвратить случайное прикосновение людей и защитить от поражения током"],"re":"Ограждение токоведущих частей предназначено для предотвращения непреднамеренного прикосновения людей, тем самым защищая от поражения током и ожогов."},
  {"id":283,"q":"При поиске неисправности мультиметром вы измеряете 0 вольт на замкнутом выключателе, который должен пропускать ток к работающей нагрузке; что это показание говорит о выключателе?","opts":["Выключатель исправен, так как на замкнутом выключателе должно быть малое или нулевое падение напряжения","Выключатель разомкнут и неисправен","Нагрузка закорочена","Напряжение питания слишком высокое"],"re":"На правильно замкнутом выключателе падение напряжения почти нулевое, поэтому показание 0 В при работающей нагрузке означает, что контакты выключателя исправны."},
  {"id":284,"q":"Соединительная коробка должна иметь маркированный объём или быть достаточного размера, чтобы общее заполнение коробки не превышало что из следующего?","opts":["Половину количества кабельных зажимов","Ровно 75 процентов объёма коробки","Удвоенную площадь наименьшего проводника","Маркированный или расчётный объём коробки"],"re":"Согласно NEC 314.16(A) и (B), общий расчётный объём всего содержимого не должен превышать маркированный или расчётный объём коробки."},
  {"id":285,"q":"В стандартном расчёте нагрузки жилого помещения цепь прачечной рассчитывается по какому значению?","opts":["1 000 ВА","1 500 ВА","2 000 ВА","1 200 ВА"],"re":"NEC 220.52(B) требует рассчитывать цепь прачечной на 1 500 ВА."},
  {"id":286,"q":"GFCI обеспечивает защиту от какой конкретной опасности?","opts":["Сверхтока от короткого замыкания между фазными проводниками","Тока замыкания на землю, протекающего через человека на землю","Перенапряжения от удара молнии","Падения напряжения на длинном фидере"],"re":"GFCI обнаруживает небольшие дисбалансы, вызванные утечкой тока на землю (например, через человека), и срабатывает, предотвращая смертельное поражение; это в первую очередь не устройство защиты от сверхтока или перенапряжения."},
  {"id":287,"q":"Когда белый проводник в кабеле используется как незаземлённый проводник в петле выключателя, что должен сделать электрик на концах?","opts":["Оставить его белым, так как он в кабеле","Подключить его только к нейтральной шине","Переидентифицировать его цветом, отличным от белого, серого или зелёного","Обрезать и заглушить его"],"re":"NEC 200.7(C) разрешает белому проводнику в кабеле служить незаземлённым проводником только если он постоянно переидентифицирован для обозначения его использования путём маркировки цветом, отличным от белого, серого или зелёного."},
  {"id":288,"q":"При расчёте заполнения коробки проводники, которые начинаются за пределами коробки и проходят через неё без сращивания или окончания, учитываются как?","opts":["Каждый учитывается один раз на основе своего сечения","Каждый учитывается как два проводника","Они не учитываются","Учитывается только самый большой"],"re":"Согласно NEC 314.16(B)(1), каждый проводник, который проходит через коробку без сращивания или окончания, учитывается один раз как объём одного проводника."},
  {"id":289,"q":"Что из перечисленного является правильной практикой безопасности при использовании мультиметра для измерения напряжения в щите под напряжением?","opts":["Выбрать прибор с подходящей категорией CAT для цепи и осмотреть щупы перед использованием","Сначала установить прибор в режим ом","Держать оба щупа в одной руке для устойчивости","Использовать прибор и щупы с номиналом ниже напряжения системы"],"re":"Безопасное измерение напряжения под нагрузкой требует прибора и щупов с подходящей категорией CAT для цепи и осмотра щупов на повреждения перед использованием."},
  {"id":290,"q":"По стандартному методу суммарная нагрузка общего освещения, мелких приборов и прачечной жилья составляет 12 000 ВА; каков спрос после применения таблицы NEC 220.42 (первые 3 000 ВА по 100%, остаток по 35%)?","opts":["12 000 ВА","4 200 ВА","6 150 ВА","9 000 ВА"],"re":"Первые 3 000 ВА по 100% = 3 000; остальные 9 000 ВА по 35% = 3 150; итого = 6 150 ВА согласно таблице 220.42."},
  {"id":291,"q":"Когда в коробке присутствует один или несколько внутренних кабельных зажимов, сколько объёмов проводников добавляется на все зажимы?","opts":["Ни одного, зажимы не учитываются","Два независимо от сечения проводника","По одному на каждый присутствующий зажим","Один объём на основе самого большого проводника в коробке"],"re":"Согласно NEC 314.16(B)(2), один или несколько внутренних кабельных зажимов вместе считаются как объём одного проводника на основе самого большого проводника, входящего в коробку."},
  {"id":292,"q":"Защищает ли стандартный GFCI человека от удара током при одновременном прикосновении к фазному и нейтральному (фаза-фаза) проводникам?","opts":["Да, он всегда предотвращает все удары током","Да, но только на цепях 240 В","Нет, потому что ток сбалансирован и дисбаланс на землю не обнаруживается","Нет, потому что GFCI работают только на постоянном токе"],"re":"Если человек касается и фазы, и нейтрали, ток возвращается через нейтраль и остаётся сбалансированным, поэтому GFCI не видит дисбаланса замыкания на землю и не срабатывает."},
  {"id":293,"q":"Трёхфазный трансформатор с первичной обмоткой треугольник и вторичной звезда включён; на вторичной звезде фазное напряжение составляет 277 В, каково ожидаемое межфазное напряжение?","opts":["Около 480 В","Около 831 В","Около 160 В","277 В"],"re":"На вторичной обмотке звезда межфазное напряжение равно фазному, умноженному на корень из 3: 277 В × 1,732 ≈ 480 В."},
  {"id":294,"q":"Жильё имеет две цепи мелких приборов и одну цепь прачечной; какую общую мощность в ВА дают эти три цепи до применения коэффициента спроса?","opts":["3 000 ВА","1 500 ВА","6 000 ВА","4 500 ВА"],"re":"Две цепи мелких приборов (2 × 1 500) + одна цепь прачечной (1 500) = 3 000 + 1 500 = 4 500 ВА."},
  {"id":295,"q":"Какой raceway представляет собой гофрированную гибкую неметаллическую трубку, часто цветную, предназначенную для скрытой установки в жилых и лёгких коммерческих работах?","opts":["Промежуточный металлический кабелепровод (IMC)","Жидконепроницаемый гибкий неметаллический кабелепровод (LFNC)","Жёсткий PVC кабелепровод","Электрическая неметаллическая трубка (ENT)"],"re":"Согласно NEC Статья 362, электрическая неметаллическая трубка (ENT) представляет собой гибкий гофрированный raceway, часто цветной, используемый в скрытых местах."},
  {"id":296,"q":"Какой проводник в стандартной сдвоенной розетке должен подключаться к клемме, обозначенной серебристыми или светлыми винтами?","opts":["Заземлённый (нейтральный) проводник","Незаземлённый (фазный) проводник","Заземляющий проводник оборудования","Транзитный проводник"],"re":"На розетке серебристые/светлые винты — это заземлённые (нейтральные) клеммы; латунные винты — незаземлённые клеммы, а зелёный винт — для EGC, согласно NEC 200.10 и 250.126."},
  {"id":297,"q":"После установки розетки GFCI на объекте что должен сделать электрик, чтобы убедиться, что она работает правильно?","opts":["Измерить длину шнура","Оставить её непроверенной до прибытия инспектора","Проверить цвет лицевой панели","Нажать кнопку TEST и убедиться, что устройство срабатывает, затем нажать RESET"],"re":"Нажатие кнопки TEST должно вызвать срабатывание GFCI, подтверждая работу защитного механизма; затем RESET восстанавливает питание."},
  {"id":298,"q":"При осмотре перед подачей напряжения, какова цель проверки установки главной соединительной перемычки на вводе?","opts":["Соединить заземлённый проводник с системой заземления оборудования для отвода тока КЗ","Изолировать нейтраль от земли","Повысить напряжение на нагрузках","Сбалансировать фазные токи"],"re":"Главная соединительная перемычка соединяет заземлённый (нейтральный) проводник с системой заземления оборудования на вводе, создавая путь, позволяющий току КЗ привести в действие защиту от сверхтока."},
  {"id":299,"q":"Используя таблицу NEC 220.55, столбец C, какова нагрузка спроса для одной бытовой электрической плиты мощностью 12 кВт?","opts":["12 кВт","6 кВт","10 кВт","8 кВт"],"re":"Таблица NEC 220.55, столбец C, даёт 8 кВт для одной плиты не более 12 кВт."},
  {"id":300,"q":"Гибкий металлический кабелепровод (FMC), используемый как гибкая подводка к светильнику, обычно разрешается оставлять без опоры на длину, не превышающую какое расстояние?","opts":["3 фута","6 футов","4 1/2 фута","8 футов"],"re":"Согласно NEC 348.30(A), FMC разрешается оставлять без опоры на длину до 6 футов от клеммы светильника для ответвлений (гибких подводок)."},
  {"id":301,"q":"Рабочий использует портативный электроинструмент со шнуром на улице во влажной зоне; какая комбинация обеспечивает наилучшую защиту от поражения током?","opts":["Незаземлённый инструмент без GFCI","Правильно заземлённый или двойной изоляции инструмент, питаемый через GFCI","Инструмент со снятым заземляющим штырём","Инструмент, подключённый к перетёртому удлинителю"],"re":"Самая безопасная комбинация — это инструмент, который либо правильно заземлён, либо двойной изоляции, и питается через защиту GFCI, особенно во влажных местах."},
  {"id":302,"q":"Какой прибор специально предназначен для измерения, сколько ом сопротивления существует между заземляющим электродом и окружающей землёй?","opts":["Измеритель сопротивления заземления (тестер заземления)","Стандартный мультиметр в режиме ом","Мегомметр","Бесконтактный индикатор напряжения"],"re":"Измеритель сопротивления заземления предназначен для измерения сопротивления электрод-земля методами падения потенциала или клещевым, которые обычный омметр не может выполнить точно."},
  {"id":303,"q":"Крепление кабеля NM НЕ требуется в какой из следующих ситуаций?","opts":["Где кабель протянут между точками доступа через скрытые пространства отделанных зданий и установка опоры непрактична","Где кабель входит в коробку поверхностного монтажа","Где кабель проложен открыто по лицевой стороне отделанной стены","Где кабель проложен по нижней стороне балок перекрытия"],"re":"Согласно NEC 334.30(B), крепление не требуется там, где кабель протянут между точками доступа через скрытые пространства отделанных зданий и установка опоры непрактична."},
  {"id":304,"q":"Согласно NEC 220.54, по какому минимальному значению должна рассчитываться одна бытовая электрическая сушилка для одежды, даже если её паспортная мощность ниже?","opts":["3 000 ВА","5 000 ВА","4 500 ВА","1 500 ВА"],"re":"NEC 220.54 требует рассчитывать бытовую электрическую сушилку на 5 000 ВА или паспортную мощность, в зависимости от того, что больше."},
  {"id":305,"q":"Чтобы управлять одним светильником из двух разных мест, какая схема переключения используется?","opts":["Два однополюсных выключателя","Один четырёхпозиционный (4-way) выключатель","Два трёхпозиционных (3-way) выключателя","Два двухполюсных выключателя"],"re":"Управление одной нагрузкой из двух мест достигается парой 3-way выключателей, соединённых транзитными (traveler) проводниками."},
  {"id":306,"q":"Распределительная коробка, установленная в отделанной стене из негорючего материала, такого как гипсокартон, должна быть смонтирована так, чтобы передний край был утоплен не более чем на какое расстояние от отделанной поверхности?","opts":["Заподлицо, без допустимого утопления","Не более 1/4 дюйма от поверхности","Не более 1 дюйма от поверхности","Не более 1 1/4 дюйма от поверхности"],"re":"Согласно NEC 314.20, в стенах из негорючего материала коробка может быть утоплена не более чем на 1/4 дюйма от отделанной поверхности."},
  {"id":307,"q":"Электрические ожоги от контакта с токоведущими частями могут быть обманчиво серьёзными, потому что наиболее тяжёлое повреждение тканей часто происходит где?","opts":["Только на поверхности кожи","Только в одежде пострадавшего","Только в волосах и ногтях","Глубоко внутри тела по пути тока между точками входа и выхода"],"re":"Ток, проходящий через тело, выделяет тепло глубоко в тканях, поэтому внутренние повреждения по пути тока часто гораздо тяжелее, чем видимые поверхностные раны."},
  {"id":308,"q":"Каков минимальный размер ввода в амперах, требуемый для одного односемейного жилья согласно NEC 230.79(C)?","opts":["100 А","60 А","125 А","150 А"],"re":"NEC 230.79(C) требует минимальный номинал отключающего устройства ввода 100 А для односемейного жилья."},
  {"id":309,"q":"Какой самый надёжный способ убедиться, что цепь обесточена, перед началом работы, иногда называемый тестом живой-мёртвый-живой?","opts":["Проверить прибор на известном источнике под напряжением, проверить цепь, затем снова проверить источник","Один раз использовать бесконтактный индикатор","Смотреть только на положение рукоятки автомата","Считать обесточенной, если свет выключен"],"re":"Метод живой-мёртвый-живой подтверждает, что прибор работает на известном источнике под напряжением, показывает, что цепь обесточена, затем снова подтверждает работу прибора, доказывая отсутствие напряжения."},
  {"id":310,"q":"Распределительная коробка, установленная в горючей поверхности стены, такой как деревянные панели, должна быть смонтирована так, чтобы передний край располагался как относительно отделанной поверхности?","opts":["Заподлицо или выступать от отделанной поверхности","Утоплена на 1/4 дюйма","Утоплена на 1/2 дюйма","Утоплена на 1 дюйм"],"re":"Согласно NEC 314.20, в стенах из горючего материала коробка должна быть заподлицо или выступать от отделанной поверхности."},
  {"id":311,"q":"Односемейное жильё 120/240 В однофазное имеет расчётную общую нагрузку спроса 24 000 ВА; какова минимальная требуемая токовая нагрузка ввода?","opts":["200 А","150 А","125 А","100 А"],"re":"Ток ввода = ВА ÷ В = 24 000 ÷ 240 = 100 А."},
  {"id":312,"q":"Какой фактор наиболее непосредственно определяет величину тока, который протекает через человека, контактирующего с проводником под фиксированным напряжением?","opts":["Рост человека","Цвет изоляции проводника","Сопротивление тела и точек контакта на пути тока","Время суток"],"re":"По закону Ома при данном напряжении ток равен напряжению, делённому на сопротивление, поэтому меньшее сопротивление тела и контакта (например, мокрая кожа) приводит к большему, более опасному току."},
  {"id":313,"q":"Токоизмерительные клещи надеты одновременно на все три фазных проводника сбалансированной трёхфазной цепи; что они должны идеально показать?","opts":["Межфазное напряжение","Сумму всех трёх фазных токов","Ток только одной фазы","Приблизительно ноль, так как сбалансированные токи компенсируются"],"re":"Когда все проводники сбалансированного набора проходят через клещи вместе, их магнитные поля компенсируются, поэтому прибор показывает почти ноль; на этом основано обнаружение тока утечки."},
  {"id":314,"q":"Чтобы управлять одним светильником из трёх или более мест, какая комбинация выключателей требуется?","opts":["Три 3-way выключателя","Три однополюсных выключателя","Три 4-way выключателя","Два 3-way выключателя и один или более 4-way выключателей"],"re":"Управление из трёх или более мест использует два 3-way выключателя по концам и один или более 4-way выключателей между ними, подключённых через транзитные проводники."},
  {"id":315,"q":"Кабель типа MC (металлобронированный), установленный открыто и проложенный по элементам каркаса, должен быть закреплён с интервалами, не превышающими какое расстояние?","opts":["3 фута","6 футов","4 фута","8 футов"],"re":"Согласно NEC 330.30, кабель типа MC должен быть закреплён с интервалами, не превышающими 6 футов."},
  {"id":316,"q":"При расчёте нагрузки фидера или ввода для жилья стационарные приборы, такие как водонагреватель и посудомоечная машина, классифицируются под каким термином NEC?","opts":["Нагрузки стационарно закреплённых приборов","Непрерывные нагрузки","Нагрузки двигателей","Нагрузки общего освещения"],"re":"NEC 220.53 охватывает стационарно закреплённые (фиксированные) приборы, допуская коэффициент спроса 75% при наличии четырёх или более на фидере жилья."},
  {"id":317,"q":"При проверке соединений трансформатора на запуске, почему правильная полярность (суммирующая или вычитающая) важна при параллельном соединении или объединении трансформаторов?","opts":["Неправильная полярность может вызвать короткое замыкание или неправильное напряжение при соединении обмоток","Она влияет только на цвет изоляторов","Она определяет класс изоляции","Она меняет номинал кВА"],"re":"Полярность трансформатора необходимо проверять, чтобы соединённые или параллельные обмотки складывались правильно; обратная полярность может создать короткое замыкание или неправильное выходное напряжение."},
  {"id":318,"q":"На стройплощадке розетка 30 А, 125 В, однофазная, не входящая в постоянную проводку и используемая работниками, должна иметь какую защиту согласно OSHA 1926.404?","opts":["Никакой особой защиты не требуется","Только крышку с фиксацией","Только сетевой фильтр от перенапряжений","Защиту GFCI или охват программой обеспечения заземляющего проводника"],"re":"OSHA распространяет требование GFCI на однофазные розетки 125 В на 15, 20 и 30 А, не входящие в постоянную проводку, с программой обеспечения заземления в качестве альтернативы."},
  {"id":319,"q":"Какое утверждение лучше всего описывает разрешённое использование промежуточного металлического кабелепровода (IMC)?","opts":["Он разрешён только в сухих внутренних помещениях","Он разрешён только под землёй","Он никогда не может иметь резьбу","Он может использоваться во всех тех же атмосферных условиях и помещениях, что и RMC"],"re":"Согласно NEC Статья 342, IMC является стальным raceway с более тонкой стенкой, разрешённым во всех тех же местах и условиях, что и жёсткий металлический кабелепровод (RMC)."},
  {"id":320,"q":"Согласно NEC 220.53, когда четыре или более стационарно закреплённых прибора находятся на одном фидере жилья, какой коэффициент спроса можно применить к их суммарной паспортной нагрузке?","opts":["50%","75%","65%","100%"],"re":"NEC 220.53 разрешает коэффициент спроса 75% для четырёх или более стационарно закреплённых приборов (исключая плиты, сушилки, отопление и кондиционирование)."},
  {"id":321,"q":"При наладке показание сопротивления изоляции мегомметром снимается сразу и снова через одну минуту для вычисления какого полезного диагностического значения?","opts":["Коэффициента трансформации","Чередования фаз","Индекса поляризации (PI)","Сопротивления заземляющего электрода"],"re":"Индекс поляризации — это отношение показания через 10 минут (или 1 минуту) к более раннему, указывающее на состояние изоляции; более высокое отношение обычно означает лучшую, более сухую изоляцию."},
  {"id":322,"q":"Перед началом СЛР для пострадавшего от удара током единственное наиболее важное условие, которое должно быть выполнено, какое из следующих?","opts":["Ожоги пострадавшего перевязаны","Автоматический выключатель заменён на новый","Пострадавшему дали жидкости","Пострадавший больше не контактирует ни с каким источником под напряжением"],"re":"СЛР нельзя начинать, пока пострадавший полностью не освобождён от источника под напряжением; иначе спасатель рискует также получить удар током."},
  {"id":323,"q":"При определении минимального размера коробки, содержащей несколько проводников разного сечения, каково правильное требование к общему объёму?","opts":["Объём самого большого проводника, умноженный на количество проводников","Сумма индивидуальных объёмов для каждого проводника и компонента","Всегда минимум 18 кубических дюймов","Объём только самого маленького проводника"],"re":"Согласно NEC 314.16(B), общее заполнение коробки представляет собой сумму индивидуальных объёмов для всех проводников, устройств, зажимов и заземляющих проводников."},
  {"id":324,"q":"Сколько клемм имеет 3-way выключатель, не считая винта заземления?","opts":["Две","Три","Четыре","Пять"],"re":"3-way выключатель имеет три токоведущих клеммы: одну общую (часто более тёмную) клемму и две транзитные (traveler) клеммы."},
  {"id":325,"q":"Используя NEC 220.12, минимальное количество цепей общего освещения 15 А, 120 В, требуемое для нагрузки освещения жилья 6 000 ВА, составляет:","opts":["4 цепи","2 цепи","5 цепей","8 цепей"],"re":"Каждая цепь 15 А, 120 В несёт 1 800 ВА; 6 000 ÷ 1 800 = 3.33, округляется вверх до 4 цепей."},
  {"id":326,"q":"Жидконепроницаемый гибкий неметаллический кабелепровод (LFNC) и жидконепроницаемый гибкий металлический кабелепровод (LFMC) требуют сертифицированных фитингов в первую очередь для поддержания какой характеристики установки?","opts":["Жидконепроницаемой целостности в местах окончаний","Максимального радиуса изгиба","Цветовой маркировки","Только непрерывности заземления"],"re":"Согласно NEC 350.42 и 356.42, только фитинги, сертифицированные и предназначенные для данного кабелепровода, могут использоваться для сохранения жидконепроницаемого уплотнения в соединениях."},
  {"id":327,"q":"Каков правильный первый шаг для изменения направления вращения работающего трёхфазного двигателя, который при запуске вращается не в ту сторону?","opts":["Обесточить и поменять местами любые два из трёх линейных проводников","Повысить напряжение питания","Добавить трансформатор buck-boost","Поменять только защитный проводник заземления"],"re":"Направление вращения трёхфазного двигателя меняется обесточиванием цепи и перестановкой любых двух из трёх линейных (фазных) проводников на клеммах двигателя."},
  {"id":328,"q":"Почему сопротивление кожи человека является важным фактором тяжести поражения током и как влага влияет на него?","opts":["Влага повышает сопротивление кожи, снижая протекание тока","Сухая кожа всегда пропускает больше тока, чем мокрая","Влага не влияет на сопротивление кожи","Влага понижает сопротивление кожи, позволяя протекать большему току и увеличивая опасность"],"re":"Мокрая или потная кожа имеет гораздо меньшее сопротивление, чем сухая, поэтому при том же напряжении через тело протекает больше тока, делая поражение более опасным."},
  {"id":329,"q":"В стандартном расчёте жилья нагрузки спроса плиты и сушилки добавляются к спросу освещения/приборов по какому проценту их расчётных по NEC значений спроса?","opts":["35%","100%","75%","40%"],"re":"После применения коэффициентов спроса таблиц 220.55 и 220.54 значения спроса плиты и сушилки добавляются на 100% к расчёту ввода/фидера."},
  {"id":330,"q":"Участок EMT содержит три изгиба по 90 градусов и один изгиб 45 градусов между двумя протяжными коробками; каков суммарный изгиб в градусах и допустим ли он?","opts":["315 градусов, допустимо","315 градусов, недопустимо","405 градусов, недопустимо","270 градусов, допустимо"],"re":"Три изгиба по 90 градусов (270) плюс один изгиб 45 градусов равны 315 градусам, что находится в пределах максимально допустимых 360 градусов между точками протяжки согласно NEC 358.26."},
  {"id":331,"q":"Меньшее значение сопротивления заземляющего электрода обычно считается лучше; какое условие способствует снижению измеренного сопротивления заземляющего стержня?","opts":["Влажная почва и более длинный или несколько соединённых электродов","Сухая песчаная почва с высоким удельным сопротивлением","Слабый коррозированный заземляющий зажим","Короткий стержень, забитый всего на несколько дюймов"],"re":"Влажная почва и увеличенная площадь поверхности электрода, например более длинный стержень или несколько соединённых стержней, снижают переходное сопротивление к земле и улучшают систему заземления."},
  {"id":332,"q":"Когда портативный электроинструмент падает в воду, оставаясь подключённым к сети, какова правильная первая реакция?","opts":["Залезть в воду и вытащить инструмент за шнур","Обесточить цепь на автомате или отключить от сети, не касаясь воды, затем достать инструмент","Продолжить использовать инструмент после высыхания","Налить ещё воды, чтобы промыть его"],"re":"Инструмент под напряжением может сделать воду опасной; сначала безопасно снимите питание, не касаясь воды, затем достаньте и осмотрите инструмент перед дальнейшим использованием."},
  {"id":333,"q":"Сколько токоведущих клемм имеет 4-way выключатель, не считая винта заземления?","opts":["Две","Четыре","Три","Шесть"],"re":"4-way выключатель имеет четыре клеммы, расположенные как две пары транзитных проводников, и устанавливается между двумя 3-way выключателями."},
  {"id":334,"q":"Трёхфазная панель 208 В питает сбалансированную нагрузку 36 кВА; каков примерный линейный ток на каждой фазе?","opts":["173 А","100 А","115 А","60 А"],"re":"IL = кВА × 1000 ÷ (√3 × VL) = 36 000 ÷ (1.732 × 208) = 36 000 ÷ 360.3 = 100 А."},
  {"id":335,"q":"Когда кабель проложен в пазу, вырезанном в лицевой стороне деревянной стойки, что требуется для защиты кабеля от шурупов и гвоздей?","opts":["Ничего, паз всегда допустим","Заполнение паза герметиком","Окрашивание кабеля в яркий цвет","Стальная пластина толщиной не менее 1/16 дюйма, установленная по лицевой стороне паза"],"re":"Согласно NEC 300.4(A)(2), кабели, проложенные в пазах в дереве, должны быть защищены стальной пластиной толщиной не менее 1/16 дюйма по лицевой стороне паза."},
  {"id":336,"q":"Какая последовательность лучше всего описывает правильный порядок наладки перед вводом нового фидера в эксплуатацию?","opts":["Сначала подать напряжение, затем проверить момент и заземление","Проверить момент соединений и заземление, выполнить проверку сопротивления изоляции, затем подать напряжение и измерить напряжения","Измерить чередование фаз только после приложения полной нагрузки","Приложить нагрузку, затем проверить защитный проводник заземления"],"re":"Правильная наладка выполняется сначала на обесточенной системе: проверить момент и заземление, выполнить проверку сопротивления изоляции, и только затем подать напряжение для измерения рабочих напряжений."},
  {"id":337,"q":"В чём главное преимущество безопасности портативного инструмента двойной изоляции, когда заземляющий проводник источника питания может быть ненадёжным?","opts":["Его можно использовать при любом напряжении без ограничений","Его два независимых слоя изоляции защищают пользователя даже без заземляющего проводника","Он никогда не требует обслуживания","Он автоматически повышает свой номинальный ток"],"re":"Двойная изоляция обеспечивает второй независимый барьер между токоведущими частями и пользователем, давая защиту от поражения током, которая не зависит от внешнего заземляющего проводника."},
  {"id":338,"q":"Чистая расчётная нагрузка жилья составляет 27 600 ВА на однофазном вводе 240 В; каков требуемый минимальный номинал ввода из стандартных размеров?","opts":["100 А","150 А","125 А","200 А"],"re":"27 600 ÷ 240 = 115 А; следующий стандартный размер ввода/защиты — 125 А."},
  {"id":339,"q":"Какое максимальное расстояние между опорами обычно требуется для электрической металлической трубки (EMT) вдоль открытого прямого участка?","opts":["6 футов","8 футов","12 футов","10 футов"],"re":"Согласно NEC 358.30(A), EMT должна поддерживаться с интервалами, не превышающими 10 футов вдоль участка."},
  {"id":340,"q":"При проверке обесточенной ответвлённой цепи омметром показание бесконечного (OL) сопротивления между двумя концами одного проводника указывает на какое состояние?","opts":["Обрыв цепи","Короткое замыкание","Замыкание на землю","Нормальная целостность"],"re":"Бесконечное сопротивление по одному проводнику означает, что ток не проходит, что и является определением обрыва. Хорошая целостность дала бы показание около нуля ом."},
  {"id":341,"q":"На 3-way выключателе одиночная клемма, которая соединяется либо с линией, либо с нагрузкой, обычно называется как?","opts":["Общая клемма","Клемма заземления","Транзитная клемма","Нейтральная клемма"],"re":"Общая клемма 3-way выключателя (обычно тёмный или чёрный винт) соединяется с линией (источником) на одном выключателе и с нагрузкой на другом."},
  {"id":342,"q":"Какова минимальная длина одиночного заземляющего стержня, который должен находиться в контакте с грунтом, чтобы служить заземляющим электродом?","opts":["6 футов","10 футов","8 футов","4 фута"],"re":"NEC 250.52(A)(5) требует, чтобы стержневой электрод имел длину не менее 8 футов в контакте с грунтом."},
  {"id":343,"q":"Две бытовые плиты по 12 кВт на одном фидере имеют спрос по таблице 220.55, столбец C, равный 11 кВт; это показывает, что коэффициент спроса для плит:","opts":["Увеличивает расчётную нагрузку выше паспортной","Уменьшает суммарную нагрузку ниже суммы паспортных значений","Не влияет на несколько плит","Применяется только к коммерческим кухням"],"re":"Две плиты по 12 кВт дают 24 кВт паспортной мощности, но таблица 220.55, столбец C, допускает только 11 кВт, показывая, что коэффициент спроса снижает нагрузку ниже подключённой суммы."},
  {"id":344,"q":"Согласно NEC 110.26(A)(1), какова минимальная глубина рабочего пространства перед электрооборудованием с напряжением 0-150 вольт относительно земли, если открытые токоведущие части находятся с одной стороны, а с другой стороны нет токоведущих или заземлённых частей?","opts":["2 фута","3 фута","3,5 фута","4 фута"],"re":"NEC 110.26(A)(1) Условие 1 требует минимальной глубины рабочего пространства 3 фута для оборудования с напряжением 0-150 В относительно земли."},
  {"id":345,"q":"Одиночный стержневой электрод, не имеющий сопротивления заземления 25 Ом или менее, должен быть дополнен как минимум сколькими дополнительными электродами?","opts":["Двумя дополнительными электродами","Одним дополнительным электродом","Тремя дополнительными электродами","Дополнительный электрод не требуется"],"re":"NEC 250.53(A)(2) требует, чтобы одиночный стержневой электрод с сопротивлением более 25 Ом был дополнен одним дополнительным электродом."},
  {"id":346,"q":"Стандартное устройство GFCI класса A рассчитано на срабатывание, когда разница между токами фазы и нейтрали достигает примерно какого значения?","opts":["20 А","5 А","30 мА","5 мА"],"re":"GFCI класса A срабатывает при токе утечки на землю около 4–6 мА, номинально 5 мА, чтобы защитить людей от поражения током."},
  {"id":347,"q":"Каков примерный ток полной нагрузки трёхфазной нагрузки 480 В, выдающей 100 кВт при коэффициенте мощности 1.0?","opts":["100 А","208 А","120 А","150 А"],"re":"IL = P ÷ (√3 × VL × PF) = 100 000 ÷ (1.732 × 480 × 1.0) = 100 000 ÷ 831.4 = 120 А."},
  {"id":348,"q":"Согласно NEC 110.26(A)(3), какова минимальная требуемая высота (свободное пространство над головой) рабочего пространства вокруг сервисного оборудования, распределительных щитов или центров управления двигателями с номиналом 1200 ампер или менее?","opts":["7 футов 6 дюймов","6 футов","7 футов","6 футов 6 дюймов"],"re":"NEC 110.26(A)(3) требует минимальной высоты 6,5 футов (6 футов 6 дюймов) для рабочего пространства вокруг электрооборудования."},
  {"id":349,"q":"Когда два заземляющих стержня используются для образования заземляющего электрода, какое минимальное расстояние требуется между ними?","opts":["На расстоянии 3 фута","На расстоянии 6 футов","На расстоянии 8 футов","На расстоянии 10 футов"],"re":"NEC 250.53(A)(3) требует, чтобы стержневые электроды, входящие в группу, располагались на расстоянии не менее 6 футов друг от друга."},
  {"id":350,"q":"Используя таблицу NEC 310.16 в колонке 60°C, какова допустимая токовая нагрузка медного проводника 12 AWG?","opts":["15 A","20 A","25 A","30 A"],"re":"Согласно таблице NEC 310.16, медный проводник 12 AWG в колонке клемм 60°C имеет допустимую ампацитету 20 A."},
  {"id":351,"q":"Выключатель, управляющий освещением в жилье, как правило, не должен размыкать какой проводник?","opts":["Незаземлённый (фазный) проводник","Транзитный проводник","Заземлённый (нейтральный) проводник","Отвод к выключателю"],"re":"NEC 404.2(B) требует, чтобы выключатели управляли незаземлённым проводником; заземлённый (нейтральный) проводник, как правило, не должен размыкаться (с ограниченными исключениями)."},
  {"id":352,"q":"Электрик замечает, что лампы накаливания заметно тускнеют каждый раз, когда на той же цепи запускается крупный двигатель; этот симптом наиболее прямо указывает на какую проблему?","opts":["Чрезмерное падение напряжения из-за недостаточного сечения или перегруженного проводника","Замыкание на землю в осветительной цепи","Неисправное устройство GFCI","Обратная полярность на розетке"],"re":"Потускнение при большом токе указывает на падение напряжения, чаще всего вызванное недостаточным сечением проводников, длинными трассами или ослабленными соединениями, которые не могут обеспечить пусковой ток."},
  {"id":353,"q":"Согласно NEC 110.26(A)(2), минимальная ширина рабочего пространства перед электрооборудованием должна равняться ширине оборудования или какому минимальному размеру, в зависимости от того, что больше?","opts":["24 дюйма","30 дюймов","42 дюйма","36 дюймов"],"re":"NEC 110.26(A)(2) требует, чтобы ширина рабочего пространства составляла минимум 30 дюймов или ширину оборудования, в зависимости от того, что больше."},
  {"id":354,"q":"Электрод, заключённый в бетон (Ufer), должен состоять не менее чем из 20 футов оголённого медного проводника не меньше какого сечения?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"re":"NEC 250.52(A)(3) допускает использование электрода, заключённого в бетон, с использованием не менее 20 футов оголённого медного проводника сечением не менее 4 AWG."},
  {"id":355,"q":"Какова допустимая ампацитета медного проводника 10 AWG в колонке 60°C таблицы NEC 310.16?","opts":["30 A","25 A","20 A","40 A"],"re":"Таблица NEC 310.16 указывает 10 AWG медь как 30 A в колонке 60°C."},
  {"id":356,"q":"Устройство AFCI специально предназначено для обнаружения и реагирования на какое опасное состояние?","opts":["Перенапряжение от скачков сети","Малые токи замыкания на землю","Дуговые замыкания в проводке и соединениях","Дисбаланс фаз между линиями"],"re":"AFCI определяет высокочастотную сигнатуру тока дугового разряда, например от повреждённой или ослабленной проводки, и размыкает цепь для предотвращения пожаров."},
  {"id":357,"q":"Когда электрод, заключённый в бетон, использует электропроводящую стальную арматуру с покрытием, арматура должна иметь диаметр не менее какого значения?","opts":["1/4 дюйма","1/2 дюйма","3/8 дюйма","5/8 дюйма"],"re":"NEC 250.52(A)(3) требует, чтобы арматура, используемая в качестве электрода, заключённого в бетон, имела диаметр не менее 1/2 дюйма."},
  {"id":358,"q":"Согласно NEC 110.26(A)(2), рабочее пространство шириной 30 дюймов перед распределительным щитом разрешается измерять каким образом?","opts":["Только по центру распределительного щита","Только от левого края оборудования","По диагонали по лицевой стороне оборудования","Либо по центру оборудования, либо со смещением, при условии достижения ширины 30 дюймов"],"re":"NEC 110.26(A)(2) разрешает измерять ширину 30 дюймов либо по центру оборудования, либо со смещением, при условии сохранения полной ширины 30 дюймов."},
  {"id":359,"q":"Согласно NEC 240.6(A), какое из следующих НЕ является стандартным номиналом тока для предохранителя или автоматического выключателя с обратнозависимой выдержкой?","opts":["35 A","45 A","70 A","55 A"],"re":"Согласно NEC 240.6(A), 55 A не является стандартным номиналом; стандартные номиналы перескакивают с 50 A на 60 A."},
  {"id":360,"q":"Кнопочный выключатель общего назначения, установленный в металлической коробке, как правило, должен быть снабжён каким соединением для безопасности?","opts":["Соединение с заземлённым (нейтральным) проводником","Заземляющее соединение оборудования с ярмом выключателя","Устройство защиты от перенапряжений","Изолированный заземляющий проводник"],"re":"NEC 404.9(B) требует, чтобы кнопочные выключатели, включая типы с металлической лицевой панелью, были эффективно заземлены путём подключения заземляющего проводника оборудования к металлическому ярму или планке выключателя."},
  {"id":361,"q":"Автоматический выключатель срабатывает мгновенно и резко сразу после повторного включения без подключённой нагрузки; такое поведение наиболее явно указывает на какую неисправность?","opts":["Постепенную перегрузку","Нормальное тепловое срабатывание от нагрева","Высокоомное ослабленное соединение","Прямое короткое замыкание (фаза–нейтраль или фаза–земля)"],"re":"Мгновенное срабатывание без нагрузки указывает на короткое замыкание, при котором очень большой ток короткого замыкания активирует магнитное мгновенное расцепление выключателя. Перегрузка срабатывает медленно под нагрузкой."},
  {"id":362,"q":"Металлическая подземная водопроводная труба, используемая в качестве заземляющего электрода, должна находиться в прямом контакте с землёй на протяжении не менее скольких футов?","opts":["5 футов","20 футов","8 футов","10 футов"],"re":"NEC 250.52(A)(1) требует, чтобы металлическая подземная водопроводная труба находилась в прямом контакте с землёй на протяжении 10 футов или более, чтобы квалифицироваться как электрод."},
  {"id":363,"q":"Согласно NEC 110.26(E)(1), выделенное пространство для оборудования над распределительным или коммутационным щитом должно простираться от верха оборудования на высоту скольких футов над оборудованием или до конструктивного потолка, в зависимости от того, что ниже?","opts":["3 фута","6,5 фута","6 футов","10 футов"],"re":"NEC 110.26(E)(1)(a) требует, чтобы выделенное электрическое пространство простиралось на 6 футов над оборудованием или до конструктивного потолка, в зависимости от того, что ниже."},
  {"id":364,"q":"Непрерывная нагрузка потребляет 16 A; какая минимальная ампацитета OCPD ответвления требуется до применения поправок на температуру или групповую прокладку?","opts":["20 A","18 A","16 A","25 A"],"re":"Согласно NEC 210.20(A), OCPD должен быть не менее 125% непрерывной нагрузки: 16 A × 1,25 = 20 A."},
  {"id":365,"q":"Металлическая подземная водопроводная труба, используемая в качестве заземляющего электрода, всегда должна быть дополнена чем из следующего?","opts":["Дополнительным заземляющим электродом","Грозовым разрядником","Вторым водомером","Более крупным вводным проводником"],"re":"NEC 250.53(D)(2) требует, чтобы электрод в виде металлической подземной водопроводной трубы был дополнен дополнительным электродом одного из типов, указанных в 250.52."},
  {"id":366,"q":"В многопроводной ответвлённой цепи какова основная опасность, если общая нейтраль становится ослабленной или оборванной при включённой цепи?","opts":["Выключатели немедленно сработают от перегрузки","GFCI не пройдёт тестирование","Подключённые нагрузки могут оказаться под аномально высоким или низким напряжением","Заземляющий проводник несёт полный ток нагрузки"],"re":"При обрыве общей нейтрали нагрузки фаза–нейтраль оказываются включёнными последовательно между двумя линиями, поэтому напряжение делится неравномерно и может повредить оборудование."},
  {"id":367,"q":"В пределах выделенного пространства для оборудования над распределительным щитом, требуемого NEC 110.26(E), что из перечисленного специально разрешается Кодексом?","opts":["Посторонние трубопроводы, такие как водопровод","Воздуховод системы ОВКВ, проходящий через пространство","Поддон для слива от оборудования сверху","Трубопровод спринклерной защиты для данной зоны"],"re":"NEC 110.26(E)(1)(b) запрещает посторонние системы (трубопроводы, воздуховоды и т.д.) в выделенном пространстве, но специально разрешает трубопровод спринклерной защиты для данной зоны."},
  {"id":368,"q":"Согласно NEC, глава 9, таблица 1, каков максимальный процент площади поперечного сечения кабелепровода, который может быть заполнен при прокладке более двух проводников в трубе?","opts":["31%","60%","53%","40%"],"re":"NEC глава 9, таблица 1 ограничивает заполнение до 40% для более чем двух проводников в трубе."},
  {"id":369,"q":"Когда водомер установлен в металлической подземной водопроводной трубе, используемой в качестве электрода, что должно быть предусмотрено для поддержания электрической непрерывности?","opts":["Диэлектрическая муфта","Пластиковая прокладка","Только второй заземляющий стержень","Соединительная перемычка вокруг счётчика"],"re":"NEC 250.53(D)(1) требует установки соединительной перемычки вокруг изолирующих компонентов, таких как водомер, для обеспечения непрерывности электрода."},
  {"id":370,"q":"Стандартная сдвоенная розетка 15 А, 125 В на ответвлённой цепи 20 А, обслуживающей несколько выходов, разрешена по какой причине?","opts":["Розетка 15 А никогда не допускается на цепи 20 А","NEC Таблица 210.21(B)(3) разрешает розетки 15 А на цепи 20 А с двумя или более выходами","Допускаются только одиночные розетки","Только если розетка GFCI"],"re":"NEC Таблица 210.21(B)(3) разрешает использовать розетки с номиналом 15 А на ответвлённых цепях 20 А, где питаются две или более розетки."},
  {"id":371,"q":"Каков правильный способ проверить, что розетка GFCI функционирует исправно?","opts":["Нажать кнопку TEST и убедиться, что устройство срабатывает и снимает питание","Считать линейное напряжение при включённом устройстве","Измерить сопротивление между линейными клеммами","Подать нагрузку 30 мА и убедиться, что оно удерживается"],"re":"Нажатие кнопки TEST создаёт небольшой имитированный дисбаланс; исправный GFCI должен сработать и обесточить розетку, после чего RESET восстанавливает питание."},
  {"id":372,"q":"Какой максимальный процент заполнения кабелепровода допускается для одного проводника согласно NEC, глава 9, таблица 1?","opts":["31%","53%","40%","60%"],"re":"NEC глава 9, таблица 1 допускает заполнение 53% для одного проводника в кабелепроводе."},
  {"id":373,"q":"Согласно NEC 110.27(A), токоведущие части электрооборудования с напряжением 50 вольт или более должны быть защищены от случайного контакта одним из следующих методов?","opts":["Покраска токоведущих частей изоляционной краской","Размещение в помещении, доступном только квалифицированным лицам","Размещение предупреждающего знака в пределах 10 футов","Нанесение диэлектрической смазки на проводники"],"re":"NEC 110.27(A) разрешает защищать токоведущие части путём размещения в помещении, хранилище или корпусе, доступном только квалифицированным лицам, среди прочих перечисленных методов."},
  {"id":374,"q":"Если верхний конец заземляющего стержня открыт и подвержен механическому повреждению, как он должен быть установлен, чтобы избежать дополнительных требований по защите?","opts":["Не менее чем на 6 дюймов выше уровня грунта","Заподлицо с уровнем земли или ниже него","Окрашен красной краской","Обёрнут лентой"],"re":"NEC 250.53(G) требует, чтобы стержень был установлен заподлицо с землёй или ниже неё, если только надземный конец и соединение не защищены."},
  {"id":375,"q":"Двигатель работает вяло и глохнет под нагрузкой, а измерения показывают напряжение на клеммах значительно ниже паспортного во время работы; наиболее вероятная причина:","opts":["Неисправный автомат AFCI","Чрезмерное падение напряжения в питающих проводниках","Завышенный аппарат защиты от сверхтока","Перепутанные линия и нейтраль"],"re":"Низкое напряжение на клеммах под нагрузкой снижает крутящий момент двигателя, вызывая вялую работу и остановку; это классический симптом падения напряжения из-за недостаточного сечения или перегруженных проводников."},
  {"id":376,"q":"Все заземляющие электроды, имеющиеся в здании, такие как заземляющий стержень и электрод в бетоне, должны быть:","opts":["Подключены только к нейтральной шине","Электрически изолированы друг от друга","Соединены вместе для образования системы заземляющих электродов","Использованы по одному в чередующиеся дни"],"re":"NEC 250.50 требует, чтобы все имеющиеся электроды были соединены вместе для образования системы заземляющих электродов."},
  {"id":377,"q":"Согласно NEC, глава 9, таблица 1, каков максимальный процент заполнения кабелепровода при прокладке ровно двух проводников?","opts":["26%","31%","40%","53%"],"re":"NEC глава 9, таблица 1 ограничивает два проводника в кабелепроводе заполнением 31%."},
  {"id":378,"q":"Согласно NEC 110.27(A), при каком уровне напряжения токоведущие части электрооборудования обычно требуют защиты от случайного контакта?","opts":["50 вольт или более","30 вольт или более","24 вольта или более","120 вольт или более"],"re":"NEC 110.27(A) требует, чтобы токоведущие части с напряжением 50 вольт или более были защищены от случайного контакта."},
  {"id":379,"q":"Одиночная розетка, установленная на индивидуальной ответвлённой цепи, должна иметь номинальный ток не менее какого значения относительно ответвлённой цепи?","opts":["Половина номинала ответвлённой цепи","Одна треть номинала ответвлённой цепи","Ровно 15 А независимо от цепи","Равный или больше номинала ответвлённой цепи"],"re":"NEC 210.21(B)(1) требует, чтобы одиночная розетка на индивидуальной ответвлённой цепи имела номинальный ток не менее номинала ответвлённой цепи."},
  {"id":380,"q":"Показание омметра почти ноль ом между незаземлённым (фазным) проводником и проводником заземления оборудования в обесточенной цепи указывает на что?","opts":["Замыкание на землю или короткое замыкание на землю","Обрыв нейтрали","Нормальное сопротивление изоляции","Перегруженный проводник"],"re":"Почти нулевое сопротивление между фазным и заземляющим проводниками означает, что они непреднамеренно соединены, что является замыканием на землю. Исправная изоляция показывает очень высокое сопротивление."},
  {"id":381,"q":"Каков максимальный размер медного проводника заземляющего электрода, требуемый там, где единственным электродом является одиночный заземляющий стержень?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"re":"NEC 250.66(A) устанавливает, что GEC к стержневому электроду не обязан быть больше 6 AWG из меди."},
  {"id":382,"q":"Для расчётов заполнения коробки согласно NEC 314.16(B), какой объём отводится на каждый проводник 14 AWG?","opts":["2,00 куб. дюйма","1,50 куб. дюйма","2,25 куб. дюйма","2,50 куб. дюйма"],"re":"NEC, таблица 314.16(B) отводит 2,00 кубических дюйма на каждый проводник 14 AWG."},
  {"id":383,"q":"Электрик должен работать на лицевой стороне распределительного щита 480 вольт с открытыми токоведущими частями с одной стороны и заземлённой бетонной блочной стеной непосредственно сзади; какое условие рабочего пространства и глубина по NEC 110.26(A)(1) применяется?","opts":["Условие 1, 3 фута","Условие 3, 4 фута","Условие 2, 3,5 фута","Условие 2, 3 фута"],"re":"Для 151-600 В относительно земли с открытыми токоведущими частями с одной стороны и заземлёнными частями (бетон) с другой это Условие 2, требующее 3,5 фута согласно NEC Таблица 110.26(A)(1)."},
  {"id":384,"q":"Каков максимальный размер медного проводника заземляющего электрода, требуемый там, где соединение выполняется с электродом, заключённым в бетон?","opts":["4 AWG","6 AWG","8 AWG","3 AWG"],"re":"NEC 250.66(B) устанавливает, что GEC к электроду, заключённому в бетон, не обязан быть больше 4 AWG из меди."},
  {"id":385,"q":"Автомат на 15 А срабатывает примерно через 10–15 минут работы нескольких приборов, но успешно включается и удерживается при меньшем числе нагрузок; такая картина указывает на:","opts":["Глухое короткое замыкание","Замыкание на землю","Длительную перегрузку","Неисправный датчик AFCI"],"re":"Задержанное срабатывание, коррелирующее с числом нагрузок, — это признак тепловой перегрузки, когда ток умеренно превышает номинал и со временем нагревает биметаллический элемент."},
  {"id":386,"q":"Какой объём для одного проводника NEC, таблица 314.16(B) отводит проводнику 12 AWG?","opts":["2,25 куб. дюйма","2,00 куб. дюйма","2,50 куб. дюйма","3,00 куб. дюйма"],"re":"NEC, таблица 314.16(B) отводит 2,25 кубических дюйма на каждый проводник 12 AWG."},
  {"id":387,"q":"Какой класс розетки изготовлен по более высокому стандарту по ударопрочности, силе удержания и долговечности для требовательных применений?","opts":["Бытовой класс","Стандартный класс","Декоративный класс","Больничный класс"],"re":"Розетки больничного класса изготавливаются по более высоким стандартам (обозначены зелёной точкой) для большей долговечности, удержания контакта и надёжности, чем бытовой или стандартный классы."},
  {"id":388,"q":"Согласно NEC 110.26(C), как минимум один вход, обеспечивающий доступ и выход из рабочего пространства вокруг электрооборудования, требуется в первую очередь для защиты от какой опасности?","opts":["Перегрев оборудования","Несанкционированный доступ посторонних","Блокировка работников возле оборудования под напряжением во время аварийной ситуации","Проникновение влаги в щит"],"re":"Требования NEC 110.26(C) к входу/выходу обеспечивают возможность быстрого покидания рабочего пространства работником в случае дугового разряда или другой аварийной ситуации."},
  {"id":389,"q":"Проводник заземляющего электрода, являющийся единственным соединением с одиночным заземляющим стержнем и проложенный открыто, должен быть защищён, если он меньше какого сечения?","opts":["8 AWG","10 AWG","4 AWG","6 AWG"],"re":"NEC 250.64(B) допускает прокладку медного GEC сечением 6 AWG или больше по поверхности без металлической защиты там, где он не подвержен серьёзному механическому повреждению."},
  {"id":390,"q":"При тепловизионном обследовании работающей панели одна клемма выключателя оказывается значительно горячее идентичных соседних клемм с похожим током; эта горячая точка наиболее вероятно указывает на:","opts":["Ослабленное или высокоомное соединение","Завышенное сечение проводника","Сработавший GFCI","Идеально затянутое соединение"],"re":"Локальная горячая точка на соединении обычно означает ослабленное или корродированное соединение, создающее дополнительное сопротивление, которое выделяет тепло под нагрузкой и может привести к отказу или пожару."},
  {"id":391,"q":"Коробка устройства содержит шесть токоведущих проводников 12 AWG без других элементов заполнения; какой общий объём коробки требуется по NEC 314.16(B)?","opts":["12,0 куб. дюйма","15,0 куб. дюйма","13,5 куб. дюйма","18,0 куб. дюйма"],"re":"Шесть проводников 12 AWG по 2,25 куб. дюйма каждый составляют 13,5 кубических дюйма согласно NEC, таблица 314.16(B)."},
  {"id":392,"q":"Для ввода с незаземлёнными вводными проводниками 2 AWG из меди, каков минимальный размер медного проводника заземляющего электрода согласно таблице 250.66?","opts":["10 AWG","4 AWG","6 AWG","8 AWG"],"re":"Таблица 250.66 требует медный GEC сечением 8 AWG для вводных проводников 2 AWG из меди."},
  {"id":393,"q":"Согласно NEC 110.26(C)(2), для оборудования с номиналом 1200 ампер или более и шириной более 6 футов сколько входов в рабочее пространство (по одному с каждого конца) обычно требуется, если не выполнены особые исключения?","opts":["Вход не требуется","Только один вход","Три входа","Два входа"],"re":"NEC 110.26(C)(2) требует два входа/выхода, по одному с каждого конца, для крупного оборудования с номиналом 1200 А или более и шириной более 6 футов."},
  {"id":394,"q":"Согласно NEC 314.16(B), сколько объёмных единиц совокупно засчитываются все заземляющие проводники оборудования, входящие в коробку?","opts":["Одну на каждый заземляющий проводник","Ноль","Одну, по наибольшему заземляющему проводнику","Две всего"],"re":"NEC 314.16(B)(5) засчитывает все заземляющие проводники оборудования как одну объёмную единицу по наибольшему такому проводнику."},
  {"id":395,"q":"Приступая к поиску неисправности мёртвой розетки, какой шаг логично выполнить ПЕРВЫМ?","opts":["Заменить розетку","Заменить вводную панель","Протянуть новый провод к розетке","Подтвердить проблему и проверить сработавший автомат или GFCI"],"re":"Правильная последовательность диагностики начинается с подтверждения симптома и проверки самых простых и вероятных причин, таких как сработавший автомат или вышестоящий GFCI, до сложных работ."},
  {"id":396,"q":"Для ввода с незаземлёнными вводными проводниками 1/0 AWG из меди, каков минимальный размер медного проводника заземляющего электрода согласно таблице 250.66?","opts":["8 AWG","6 AWG","4 AWG","2 AWG"],"re":"Таблица 250.66 требует медный GEC сечением 6 AWG для вводных проводников от более чем 2 AWG до 1/0 AWG из меди."},
  {"id":397,"q":"Для бельевых шкафов поверхностно-монтируемый накаливания или светодиодный светильник с полностью закрытой лампой должен сохранять минимальный зазор сколько от ближайшего пространства хранения?","opts":["6 дюймов","18 дюймов","12 дюймов","24 дюйма"],"re":"NEC 410.16(C) требует минимальный зазор 12 дюймов между поверхностно-монтируемым полностью закрытым светильником накаливания/светодиодным и ближайшей точкой пространства хранения шкафа."},
  {"id":398,"q":"Согласно NEC 110.26(D), что должно быть предусмотрено в рабочем пространстве вокруг сервисного оборудования, коммутационных щитов, распределительных щитов и центров управления двигателями, установленных внутри помещений?","opts":["Огнетушитель","Заземляющий коврик","Освещение","Телефон"],"re":"NEC 110.26(D) требует, чтобы освещение было предусмотрено для всех рабочих пространств вокруг сервисного оборудования, коммутационных щитов, распределительных щитов и центров управления двигателями, расположенных внутри помещений."},
  {"id":399,"q":"При выборе сечения проводников ответвления NEC рекомендует, чтобы падение напряжения, как правило, не превышало какого процента только для ответвления?","opts":["1%","3%","5%","8%"],"re":"Информационное примечание NEC 210.19 рекомендует максимальное падение напряжения 3% на ответвлении и 5% суммарно для фидера и ответвления."},
  {"id":400,"q":"В цепи 120 вольт вольтметр показывает 120 В между фазой и землёй, но 0 В между фазой и нейтралью; это показание наиболее вероятно указывает на:","opts":["Короткое замыкание между фазой и нейтралью","Глухое замыкание на землю","Нормальную исправно работающую цепь","Обрыв нейтрали"],"re":"Полное напряжение относительно земли, но отсутствие напряжения относительно нейтрали означает, что путь нейтрали разорван; прибор замыкает цепь через землю, подтверждая обрыв нейтрали."},
  {"id":401,"q":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 15 ампер согласно таблице 250.122?","opts":["12 AWG","10 AWG","14 AWG","16 AWG"],"re":"Таблица 250.122 требует медный EGC сечением 14 AWG для устройства защиты от сверхтока с номиналом 15 ампер."},
  {"id":402,"q":"NEC рекомендует, чтобы суммарное падение напряжения фидера и ответвления до самой дальней точки не превышало какого общего процента?","opts":["3%","5%","8%","10%"],"re":"Информационные примечания NEC рекомендуют, чтобы суммарное падение напряжения фидера и ответвления не превышало 5%."},
  {"id":403,"q":"Согласно NEC 110.26(B), рабочее пространство, требуемое перед электрооборудованием, должно содержаться свободным и НЕ может использоваться для какой цели?","opts":["Временный доступ во время монтажа","Проход квалифицированных лиц","Хранение материалов и оборудования","Установка требуемого осветительного прибора"],"re":"NEC 110.26(B) требует, чтобы рабочее пространство было свободным, и запрещает его использование для хранения; когда обычно закрытые токоведущие части открыты, пространство должно быть надлежащим образом защищено."},
  {"id":404,"q":"В правильно сбалансированной многопроводной ответвлённой цепи 120/240 вольт ток, протекающий по общей нейтрали, равен:","opts":["Сумме двух линейных токов","Удвоенному большему линейному току","Разности двух линейных токов","Всегда нулю независимо от нагрузки"],"re":"Когда две незаземлённые линии находятся на противоположных фазах, нейтраль несёт только небаланс (разность) токов, поэтому при правильном подключении нейтраль можно безопасно использовать совместно."},
  {"id":405,"q":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 20 ампер согласно таблице 250.122?","opts":["14 AWG","12 AWG","10 AWG","8 AWG"],"re":"Таблица 250.122 требует медный EGC сечением 12 AWG для устройства защиты от сверхтока с номиналом 20 ампер."},
  {"id":406,"q":"Поверхностно-монтируемый люминесцентный светильник на стене или потолке бельевого шкафа должен сохранять минимальный зазор сколько от ближайшего пространства хранения?","opts":["6 дюймов","3 дюйма","12 дюймов","18 дюймов"],"re":"NEC 410.16(C) разрешает поверхностно-монтируемые люминесцентные светильники в бельевых шкафах с минимальным зазором 6 дюймов от ближайшей точки пространства хранения."},
  {"id":407,"q":"Соединения проводников на оборудовании с номиналом 100 A или менее обычно основываются на какой температурной колонке, если оборудование не сертифицировано и не маркировано иначе?","opts":["75°C","60°C","90°C","105°C"],"re":"Согласно NEC 110.14(C)(1)(a), соединения для цепей 100 A или менее по умолчанию используют колонку 60°C, если не маркировано для более высокой."},
  {"id":408,"q":"Каков минимальный размер медного проводника заземления оборудования, требуемый для цепи на 60 ампер согласно таблице 250.122?","opts":["8 AWG","10 AWG","12 AWG","6 AWG"],"re":"Таблица 250.122 требует медный EGC сечением 10 AWG для устройства защиты от сверхтока с номиналом 60 ампер."},
  {"id":409,"q":"Для воздушного сервисного ввода проводников 120/240 вольт, пересекающего жилую подъездную дорогу, не подверженную движению грузовиков, каков минимальный вертикальный зазор над подъездной дорогой, требуемый NEC?","opts":["10 футов","15 футов","12 футов","18 футов"],"re":"Согласно NEC 230.24(B), проводники сервисного ввода с напряжением не более 300 В относительно земли требуют зазора 12 футов над жилой территорией и подъездными дорогами, не подверженными движению грузовиков."},
  {"id":410,"q":"Если нажатие кнопки TEST на розетке GFCI НЕ вызывает её срабатывания, правильный вывод:","opts":["GFCI работает идеально","Нагрузка ниже по цепи слишком мала","Напряжение цепи слишком высокое","GFCI неисправен и подлежит замене"],"re":"GFCI, который не срабатывает по своей кнопке TEST, утратил защитную функцию и подлежит замене, так как он больше не может прервать реальное замыкание на землю."},
  {"id":411,"q":"Даже при установке проводников с номиналом 90°C, каково основное разрешённое назначение колонки ампацитеты 90°C в таблице NEC 310.16?","opts":["Для итоговой ампацитеты соединения","Только для расчётов нагрузки","Как исходная ампацитета для применения коэффициентов поправки и коррекции","Её вообще нельзя использовать"],"re":"Согласно NEC 110.14(C), колонка 90°C используется как отправная точка для дерейтинга, но итоговая ампацитета не должна превышать номинал температуры соединения."},
  {"id":412,"q":"Каков минимальный размер медного проводника заземления оборудования, требуемый для цепи на 100 ампер согласно таблице 250.122?","opts":["10 AWG","8 AWG","6 AWG","4 AWG"],"re":"Таблица 250.122 требует медный EGC сечением 8 AWG для устройства защиты от сверхтока с номиналом 100 ампер."},
  {"id":413,"q":"Согласно NEC 230.24(B), каков минимальный вертикальный зазор для проводников воздушного сервисного ввода над общественной улицей, переулком или дорогой, подверженной движению грузовиков?","opts":["12 футов","15 футов","22 фута","18 футов"],"re":"NEC 230.24(B)(4) требует зазора 18 футов над общественными улицами, переулками, дорогами и другими зонами, подверженными движению грузовиков."},
  {"id":414,"q":"Какая практика обслуживания лучше всего помогает предотвратить нагрев от ослабленных соединений на клеммах панелей и устройств со временем?","opts":["Периодически перетягивать соединения по спецификациям производителя","Оставлять клеммы слегка ослабленными для теплового расширения","Красить все клеммы для предотвращения коррозии","Увеличивать номинал автомата для снижения нагрева"],"re":"Соединения могут ослабевать из-за тепловых циклов и вибрации; периодический осмотр и затяжка до заданного значения сохраняют низкое сопротивление и предотвращают накопление тепла."},
  {"id":415,"q":"Какой тип светильника НЕ разрешается устанавливать в бельевом шкафу?","opts":["Светильник накаливания с открытой или незащищённой лампой","Встраиваемый люминесцентный светильник","Поверхностно-монтируемый светодиодный светильник","Полностью закрытый поверхностно-монтируемый светильник накаливания"],"re":"NEC 410.16(B) запрещает светильники накаливания с открытыми или частично закрытыми лампами и подвесные светильники в бельевых шкафах из-за риска возгорания."},
  {"id":416,"q":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 40 ампер согласно таблице 250.122?","opts":["12 AWG","14 AWG","8 AWG","10 AWG"],"re":"Таблица 250.122 требует медный EGC сечением 10 AWG для устройства защиты от сверхтока с номиналом 40 ампер."},
  {"id":417,"q":"Какова допустимая ампацитета медного проводника 14 AWG в колонке 60°C таблицы NEC 310.16?","opts":["10 A","15 A","20 A","25 A"],"re":"Таблица NEC 310.16 указывает 14 AWG медь как 15 A в колонке 60°C."},
  {"id":418,"q":"Согласно NEC 230.24(A), проводники воздушного сервисного ввода должны сохранять минимальный зазор скольких футов над поверхностью крыши в общем случае до применения каких-либо исключений с уменьшенным зазором?","opts":["3 фута","8 футов","6 футов","10 футов"],"re":"NEC 230.24(A) обычно требует, чтобы проводники имели зазор не менее 8 футов над поверхностью крыши, с несколькими исключениями для уменьшенного зазора."},
  {"id":419,"q":"Две цепи розеток 120 вольт, питаемые от ОДНОЙ фазы, подключены к одной общей нейтрали; наиболее серьёзное последствие:","opts":["Нейтраль несёт только разность двух токов","Заземляющий проводник оказывается под напряжением","Цепи вообще не включатся","Общая нейтраль может перегружаться, потому что токи складываются, а не вычитаются"],"re":"Когда обе фазы на одной фазе, токи нейтрали складываются, а не компенсируются, поэтому единственная нейтраль может быть вынуждена нести ток выше номинала и перегреваться."},
  {"id":420,"q":"Когда проводник заземления оборудования увеличивается в размере из-за увеличения сечения незаземлённых проводников, EGC должен быть увеличен каким образом?","opts":["Его не нужно увеличивать","Ровно на один размер AWG","Удвоен в размере","Пропорционально увеличению площади в круговых милах незаземлённых проводников"],"re":"NEC 250.122(B) требует, чтобы EGC был увеличен пропорционально увеличению площади в круговых милах незаземлённых проводников."},
  {"id":421,"q":"Питается некратковременная (непостоянная) нагрузка 24 A; выбирая следующий стандартный OCPD по NEC 240.6(A), какой номинал устройства защиты подходит?","opts":["20 A","35 A","30 A","25 A"],"re":"Согласно NEC 240.6(A), 25 A является стандартным номиналом и подходит для непостоянной нагрузки 24 A."},
  {"id":422,"q":"Автомат AFCI постоянно срабатывает на цепи, но штекерный тестер и визуальный осмотр не показывают замыкания на землю или явного короткого замыкания; какой разумный следующий шаг поиска неисправности?","opts":["Немедленно заменить всю панель","Проверить кабель на повреждения, ослабленные соединения или склонные к дуге контакты в этой цепи","Увеличить номинал тока автомата","Отсоединить заземляющий проводник оборудования"],"re":"Поскольку AFCI реагируют на дугу, повторные срабатывания требуют проверки повреждённой изоляции, скоб, пробивших кабель, или ослабленных соединений, создающих сигнатуры дуги."},
  {"id":423,"q":"Согласно NEC 230.24(B)(1), проводники сервисного ввода, ограниченные 150 вольтами относительно земли, требуют минимального вертикального зазора скольких футов над готовым грунтом, тротуарами или платформами, доступными только пешеходам?","opts":["10 футов","8 футов","12 футов","15 футов"],"re":"NEC 230.24(B)(1) требует зазора 10 футов над готовым грунтом, тротуарами или доступными поверхностями, с которых их можно достать, для проводников, ограниченных 150 В относительно земли."},
  {"id":424,"q":"Когда один проводник заземления оборудования проложен с несколькими цепями в одном кабелепроводе, он должен выбираться на основе какого устройства защиты от сверхтока?","opts":["Наибольшего устройства защиты от сверхтока, защищающего проводники в кабелепроводе","Наименьшего в группе","Среднего значения всех устройств","Первой установленной цепи"],"re":"NEC 250.122(C) требует, чтобы один EGC для нескольких цепей выбирался по наибольшему устройству защиты от сверхтока в кабелепроводе."},
  {"id":425,"q":"Светильник, используемый как короб (raceway) для проводников цепи, разрешён только когда он какой?","opts":["Окрашен под цвет потолка","Установлен ниже 8 футов","Сертифицирован и маркирован для использования как короб (raceway)","Рассчитан на мокрые места"],"re":"NEC 410.64 разрешает использовать светильники как короб (raceway) для проводников цепи только если они сертифицированы и маркированы для использования как короб (или предназначены для торцевой сборки)."},
  {"id":426,"q":"Непрерывная нагрузка требует сечения проводников минимум на 22 A после коэффициента 125%; используя колонку 75°C таблицы 310.16, какой минимальный медный проводник удовлетворяет этому требованию 22 A?","opts":["14 AWG","10 AWG","12 AWG","8 AWG"],"re":"В колонке 75°C 12 AWG равен 25 A, но ограничен 20 A по NEC 240.4(D); 10 AWG при 35 A — наименьший проводник, обеспечивающий не менее 22 A."},
  {"id":427,"q":"Главная соединительная перемычка, соединяющая заземлённый (нейтральный) проводник с системой заземления оборудования, устанавливается в каком месте?","opts":["На каждом субпанели","Только на устройстве отключения ввода","На самой дальней розетке","На каждом заземляющем электроде"],"re":"NEC 250.24(B) и 250.28 требуют, чтобы главная соединительная перемычка устанавливалась на устройстве отключения ввода."},
  {"id":428,"q":"При использовании вольтметра для поиска обрыва в последовательной цепочке из трёх нагрузок, которые все обесточены, где появится полное напряжение источника?","opts":["На каждой нагрузке поровну","На точке обрыва (разрыва)","На заземляющем проводнике","Нигде, прибор везде показывает ноль"],"re":"В последовательной цепи с обрывом всё напряжение источника падает на разрыве, поскольку ток не течёт, поэтому измерение полного напряжения на элементе выявляет обрыв."},
  {"id":429,"q":"Рассматривая глубину укладки как вопрос безопасности, какова минимальная глубина закапывания, требуемая NEC Таблица 300.5 для кабеля UF прямого закапывания, питающего жилую ответвлённую цепь 120 вольт или менее, защищённую 20-амперным GFCI, в траншее без другой защиты?","opts":["6 дюймов","12 дюймов","18 дюймов","24 дюйма"],"re":"NEC Таблица 300.5 разрешает глубину укладки 12 дюймов для жилых ответвлённых цепей с номиналом 120 В или менее, защищённых GFCI на 20 ампер или менее."},
  {"id":430,"q":"Согласно NEC 240.4(D), какова максимальная защита от сверхтока, обычно допускаемая для медного проводника 14 AWG независимо от его ампацитеты при 90°C?","opts":["15 A","20 A","25 A","30 A"],"re":"NEC 240.4(D) ограничивает медный проводник 14 AWG максимальным устройством защиты на 15 A."},
  {"id":431,"q":"На субпанели, расположенной в отдельном корпусе ниже по цепи от ввода, нейтральный (заземлённый) проводник должен быть:","opts":["Соединён с корпусом соединительным винтом","Изолирован от шины заземления оборудования и корпуса","Подключён только к местному заземляющему стержню","Подключён только к шине заземления оборудования"],"re":"NEC 250.24(A)(5) запрещает соединение нейтрали с землёй на стороне нагрузки от ввода; нейтраль должна быть изолирована на субпанели."},
  {"id":432,"q":"Проводники и соединения, которые горячие на ощупь и обесцвечены на розетке при нормальной нагрузке, чаще всего возникают из-за:","opts":["Обрыва нейтрали в другом месте","Правильно подобранного сечения проводника","Недостаточного сечения или ослабленного соединения проводника","Правильно сработавшего GFCI"],"re":"Нагрев и обесцвечивание указывают на чрезмерное сопротивление, обычно из-за недостаточного сечения проводника или ослабленного, плохо выполненного соединения, рассеивающего мощность в виде тепла."},
  {"id":433,"q":"Стандартный диммер накаливания, как правило, подходит для управления каким типом нагрузки?","opts":["Резистивная (накаливания) осветительная нагрузка","Нагрузка розетки","Стандартная двигательная нагрузка","Люминесцентный балласт, не рассчитанный на регулировку"],"re":"Стандартный диммер предназначен для резистивных осветительных нагрузок накаливания (и сертифицированных совместимых); его нельзя использовать на двигателях или нерегулируемых балластах, если он специально не рассчитан на это."},
  {"id":434,"q":"Согласно NEC 240.4(D), какое максимальное стандартное устройство защиты допускается для защиты медного проводника 12 AWG?","opts":["15 A","25 A","20 A","30 A"],"re":"NEC 240.4(D) ограничивает медный проводник 12 AWG максимальным устройством защиты на 20 A."},
  {"id":435,"q":"Согласно NEC Таблица 300.5, какова общая минимальная глубина закапывания (укрытие) для кабелей или проводников прямого закапывания с номиналом 0-1000 вольт, где не применяется специальное разрешённое уменьшение?","opts":["12 дюймов","24 дюйма","18 дюймов","30 дюймов"],"re":"NEC Таблица 300.5 Колонка 1 указывает 24 дюйма укрытия как общий минимум для проводников прямого закапывания с номиналом 0-1000 вольт."},
  {"id":436,"q":"Соединение между заземлённым (нейтральным) проводником и проводниками заземления оборудования разрешается в какой единственной точке в типичном вводе?","opts":["Только в гнезде счётчика","На каждом распределительном щите ответвлённых цепей","На главном вводном оборудовании","В каждой соединительной коробке"],"re":"NEC 250.24(A)(5) ограничивает соединение нейтрали с землёй вводным оборудованием; соединения ниже по цепи не разрешаются."},
  {"id":437,"q":"Распределительный щит питает непрерывную нагрузку 40 A; какой минимальный номинал OCPD требуется для соблюдения правила 125% непрерывной нагрузки?","opts":["50 A","45 A","40 A","60 A"],"re":"40 A × 1,25 = 50 A, и 50 A является стандартным номиналом согласно NEC 240.6(A)."},
  {"id":438,"q":"GFCI защищает от поражения током, сравнивая ток в каких двух проводниках?","opts":["Фазном и заземляющем проводнике оборудования","Двух незаземлённых линиях цепи 240 вольт","Незаземлённом (фазном) и заземлённом (нейтральном) проводниках","Нейтральном и заземляющем проводнике"],"re":"GFCI постоянно сравнивает ток фазы и нейтрали; любая разница означает, что ток утекает другим путём (замыкание на землю), и он срабатывает примерно при 5 мА."},
  {"id":439,"q":"Согласно NEC Таблица 300.5, каково минимальное укрытие для проводников, установленных в жёсткой металлической трубе (RMC) или промежуточной металлической трубе (IMC) с номиналом 0-1000 вольт, закопанных в месте, не подверженном движению транспорта?","opts":["18 дюймов","12 дюймов","6 дюймов","24 дюйма"],"re":"NEC Таблица 300.5 Колонка 3 разрешает укрытие 6 дюймов для проводников в RMC или IMC, поскольку эти трубопроводы обеспечивают надёжную физическую защиту."},
  {"id":440,"q":"Металлические кабелепроводы, кабельные лотки и корпуса, используемые в качестве проводников заземления оборудования, должны быть эффективно соединены прежде всего для обеспечения чего?","opts":["Снижения стоимости монтажа","Декоративного внешнего вида","Пути тока замыкания с низким сопротивлением","Увеличения допустимой нагрузки проводника"],"re":"NEC 250.4(A)(5) и 250.96 требуют соединения для обеспечения эффективного пути с низким сопротивлением для устранения замыканий на землю."},
  {"id":441,"q":"Когда один заземляющий проводник оборудования и проводники разных сечений занимают коробку, какое сечение проводника определяет объёмную единицу для этого заземляющего проводника согласно NEC 314.16(B)(5)?","opts":["Наименьший заземляющий проводник","Среднее всех проводников","Наибольший заземляющий проводник оборудования","Всегда 14 AWG"],"re":"NEC 314.16(B)(5) основывает единую единицу заземляющего проводника на наибольшем присутствующем заземляющем проводнике оборудования."},
  {"id":442,"q":"Датчик присутствия, используемый для управления освещением на основе обнаруженного движения, чаще всего работает по какому принципу?","opts":["Измерение температуры проводника","Обнаружение замыканий на землю","Определение падения напряжения линии","Пассивное инфракрасное или ультразвуковое обнаружение движения"],"re":"Датчики присутствия обычно используют пассивное инфракрасное (PIR), ультразвуковое или двухтехнологическое обнаружение движения, чтобы включать освещение при наличии людей и выключать после освобождения помещения."},
  {"id":443,"q":"Какой прибор наиболее подходит для измерения сопротивления изоляции, чтобы подтвердить предполагаемое высокоомное замыкание между проводниками?","opts":["Токоизмерительные клещи","Бесконтактный индикатор напряжения","Штекерный тестер розеток","Тестер сопротивления изоляции (мегомметр)"],"re":"Мегомметр подаёт высокое испытательное постоянное напряжение для выявления пробоя изоляции и утечки, которые обычный омметр может пропустить, что делает его идеальным для дефектов изоляции."},
  {"id":444,"q":"Когда металлический кабелепровод, содержащий вводные проводники, входит в корпус с концентрическими или эксцентрическими выбивными отверстиями, соединение должно выполняться с помощью:","opts":["Только стандартной контргайки","Только пластиковой втулки","Ленты поверх выбивного отверстия","Соединительной арматуры, такой как соединительные втулки или соединительные контргайки"],"re":"NEC 250.92(B) требует соединительной арматуры для вводных кабелепроводов на корпусах с концентрическими или эксцентрическими выбивными отверстиями."},
  {"id":445,"q":"Согласно NEC 110.16(A), электрооборудование, такое как коммутационные и распределительные щиты в зданиях, кроме жилых, которое может потребовать осмотра под напряжением, должно иметь полевую или заводскую маркировку для предупреждения о какой опасности?","opts":["Электромагнитные помехи","Угарный газ","Дуговой разряд (arc flash)","Радиационное облучение"],"re":"NEC 110.16(A) требует полевую или заводскую маркировку, предупреждающую квалифицированных лиц о потенциальной опасности электрического дугового разряда."},
  {"id":446,"q":"В расчёте заполнения коробки сколько объёмных единиц засчитывается на каждое ярмо или планку, удерживающую устройство (например, выключатель или розетку), согласно NEC 314.16(B)(4)?","opts":["Одну, по наибольшему подключённому проводнику","Две, по наибольшему подключённому проводнику","Одну на каждую клемму","Ни одной"],"re":"NEC 314.16(B)(4) засчитывает каждое ярмо или планку как две объёмные единицы по наибольшему проводнику, подключённому к устройству."},
  {"id":447,"q":"Соединительная перемычка, используемая на стороне питания ввода (соединительная перемычка стороны питания), выбирается на основе какой таблицы?","opts":["Таблицы 250.122","Таблицы 310.16","Таблицы 250.66","Таблицы 300.5"],"re":"NEC 250.102(C) выбирает соединительные перемычки стороны питания по таблице 250.66 на основе размера вводного проводника."},
  {"id":448,"q":"Перед измерением сопротивления омметром для поиска обрыва или замыкания цепь должна быть:","opts":["Полностью под номинальным напряжением","Нагружена до полного паспортного тока","Подключена к работающему генератору","Обесточена и проверена на отсутствие напряжения"],"re":"Омметры подают собственный испытательный ток и могут быть повреждены или дать ложные показания при подключении к цепи под напряжением, поэтому цепь сначала должна быть обесточена и проверена на отсутствие напряжения."},
  {"id":449,"q":"Согласно NEC 110.24(A), сервисное оборудование в зданиях, кроме жилых, должно иметь разборчивую полевую маркировку с какой из следующих частей информации?","opts":["Номер лицензии подрядчика-установщика","Общая подключённая нагрузка в кВА","Дата следующей проверки","Максимальный доступный ток короткого замыкания"],"re":"NEC 110.24(A) требует, чтобы сервисное оборудование имело полевую маркировку с максимальным доступным током короткого замыкания, включая дату выполнения расчёта."},
  {"id":450,"q":"Какое условие позволяет полагаться на переходную шайбу как единственное средство соединения для вводного кабелепровода?","opts":["Никакое; переходные шайбы не допускаются как единственное средство соединения для вводных кабелепроводов","Когда проводник медный","Когда она окрашена","Когда кабелепровод из ПВХ"],"re":"NEC 250.92(B) не допускает стандартные переходные шайбы в качестве средства соединения для вводных кабелепроводов; требуются сертифицированные соединительные устройства."},
  {"id":451,"q":"Все внутренние кабельные зажимы в коробке совокупно засчитываются как сколько объёмных единиц согласно NEC 314.16(B)(2)?","opts":["Одну на каждый зажим","Две всего","Одну, по наибольшему проводнику в коробке","Ноль"],"re":"NEC 314.16(B)(2) засчитывает все кабельные зажимы вместе как одну объёмную единицу по наибольшему присутствующему проводнику."},
  {"id":452,"q":"Многие современные электронные диммеры и датчики присутствия требуют наличия какого проводника в коробке выключателя для питания их внутренней электроники?","opts":["Второго незаземлённого проводника","Только перемычки выравнивания потенциалов","Изолированного заземляющего проводника","Заземлённого (нейтрального) проводника"],"re":"Многие электронные диммеры и датчики требуют заземлённый (нейтральный) проводник у устройства для питания электроники; NEC 404.2(C) обычно требует нейтраль в местах выключателей для поддержки таких устройств."},
  {"id":453,"q":"Домовладелец сообщает, что автомат GFCI срабатывает только во время дождя, когда подключён уличный удлинитель; наиболее вероятная причина:","opts":["Простая тепловая перегрузка","Влага, вызывающая утечку тока на землю","Только перепутанное подключение линии и нагрузки","Недостаточный размер вводной панели"],"re":"Срабатывание GFCI, связанное с погодой, обычно вызвано попаданием воды, создающим небольшой ток утечки на землю, превышающий порог срабатывания 5 мА."},
  {"id":454,"q":"Согласно NEC 110.22(A), каждое отключающее устройство должно иметь разборчивую маркировку с указанием его назначения, если не выполняется какое условие?","opts":["Оно рассчитано менее чем на 100 ампер","Оно установлено лицензированным электриком","Оно расположено в зоне видимости оборудования, которым управляет, и назначение очевидно","Это автоматический выключатель в литом корпусе"],"re":"NEC 110.22(A) требует, чтобы каждое отключающее устройство имело разборчивую маркировку для идентификации его назначения, если оно не расположено и не устроено так, что назначение очевидно."},
  {"id":455,"q":"Какова минимальная глубина закладки для кабеля UF или проводников прямого заложения, рассчитанных на 0–1000 вольт, под жилой лужайкой согласно таблице 300.5?","opts":["12 дюймов","18 дюймов","24 дюйма","6 дюймов"],"re":"Таблица 300.5, столбец 1, требует 24 дюйма покрытия для кабелей и проводников прямого заложения не в кабелепроводе."},
  {"id":456,"q":"Какой термин оценки обозначает детализированный перечень всех материалов, устройств и фитингов, подсчитанных по чертежам, необходимых для завершения работы?","opts":["Ведомость материалов (material takeoff)","Трудовая единица (labor unit)","Распределение накладных расходов","Изменение заказа (change order)"],"re":"Material takeoff — это детализированный подсчёт материалов и устройств, полученный из строительной документации."},
  {"id":457,"q":"Чрезмерное падение напряжения на длинной ответвлённой цепи лучше всего уменьшить путём:","opts":["Увеличения сечения проводника (большего калибра провода)","Установки более крупного аппарата защиты от сверхтока","Добавления нагрузок в цепь","Снижения напряжения питания"],"re":"Падение напряжения пропорционально сопротивлению и длине проводника; увеличение сечения провода снижает сопротивление и уменьшает падение при данном токе."},
  {"id":458,"q":"Какова минимальная глубина закладки для проводников, проложенных в жёстком неметаллическом кабелепроводе (ПВХ), одобренном для прямого заложения, 0–1000 вольт, согласно таблице 300.5?","opts":["18 дюймов","24 дюйма","6 дюймов","12 дюймов"],"re":"Таблица 300.5, столбец 4, требует 18 дюймов покрытия для проводников в неметаллических кабелепроводах, сертифицированных для прямого заложения."},
  {"id":459,"q":"Согласно NEC 408.4(A), каждая цепь и модификация цепи в распределительном щите должна быть разборчиво идентифицирована по её ясному, очевидному и конкретному назначению каким способом?","opts":["Схема, приклеенная к ближайшей стене","Каталог цепей, расположенный на лицевой стороне или внутри дверцы щита","Устное объяснение владельцу здания","Этикетка только на главных сервисных проводниках"],"re":"NEC 408.4(A) требует каталог цепей или идентификацию цепей, расположенную на лицевой стороне или внутри дверцы щита, что поддерживает безопасную идентификацию отключающих устройств."},
  {"id":460,"q":"В электротехнической оценке 'трудовая единица' (labor unit) наиболее непосредственно представляет что из следующего?","opts":["Цену материала","Общие накладные расходы проекта","Расчётное время на установку конкретного элемента","Процент наценки на материалы"],"re":"Labor unit — это стандартизированное расчётное время установки (часто в часах), назначенное для монтажа определённого элемента."},
  {"id":461,"q":"При подключении проводника 12 AWG под винт устройства соединение следует затягивать согласно какому правилу?","opts":["Как можно туже с максимальным усилием","Пока головка винта не сорвётся","Только от руки без инструмента","До указанного производителем значения момента затяжки"],"re":"NEC 110.14(D) требует, чтобы соединения затягивались до значения момента, указанного производителем, обычно с использованием калиброванного динамометрического инструмента, для обеспечения надёжного соединения."},
  {"id":462,"q":"Хотя рукоятка автомата остаётся в положении ON, но питание не доходит до цепи, наиболее подходящее первое измерение:","opts":["Сопротивления нагрузки при включённом питании","Момента затяжки винтов нейтральной шины","Сопротивления изоляции корпуса панели","Напряжения на выходной клемме автомата относительно нейтрали"],"re":"Измерение напряжения на выходе автомата показывает, действительно ли автомат подаёт питание, что логически отделяет неисправный автомат от проблемы в проводке ниже по цепи."},
  {"id":463,"q":"Каково минимальное покрытие для жилой ответвлённой цепи, рассчитанной на 120 вольт или менее и 20 ампер или менее, защищённой GFCI, согласно таблице 300.5?","opts":["24 дюйма","18 дюймов","6 дюймов","12 дюймов"],"re":"Таблица 300.5, столбец 5, допускает 6 дюймов покрытия для жилых цепей на 120 вольт, 20 ампер или менее, защищённых GFCI."},
  {"id":464,"q":"Падение напряжения в однофазной цепи прямо пропорционально какой комбинации факторов?","opts":["Только площади сечения проводника","Проценту заполнения кабелепровода","Напряжению и классу изоляции проводника","Току и длине цепи в одну сторону"],"re":"Однофазное падение напряжения растёт с увеличением как тока нагрузки, так и длины цепи (VD = 2 × K × I × L / CM)."},
  {"id":465,"q":"При измерении напряжения на трёхфазном распределительном щите 480 вольт внутри коммерческого здания, какую категорию измерений (CAT) должны иметь цифровой мультиметр и его щупы как минимум?","opts":["CAT I","CAT II","CAT III","CAT 0"],"re":"CAT III — это минимальный рейтинг для измерений на стационарных установках, таких как распределительные щиты и ответвлённые цепи в коммерческих зданиях; CAT IV используется на сервисном вводе."},
  {"id":466,"q":"Какое минимальное покрытие требуется для проводников в жёстком металлическом кабелепроводе (RMC), закопанном непосредственно в землю, 0–1000 вольт, согласно таблице 300.5?","opts":["18 дюймов","12 дюймов","24 дюйма","6 дюймов"],"re":"Таблица 300.5, столбец 2, требует 6 дюймов покрытия для жёсткого металлического кабелепровода и промежуточного металлического кабелепровода."},
  {"id":467,"q":"Ключевое преимущество тепловизионной съёмки при электрическом обслуживании в том, что она позволяет технику:","opts":["Обесточивать оборудование перед осмотром","Обнаруживать перегрев соединений бесконтактно, пока система под нагрузкой","Измерять точные значения сопротивления цепи","Заменить необходимость в спецификациях момента затяжки"],"re":"Инфракрасная термография находит аномальное тепло от ослабленных или отказывающих соединений на работающем нагруженном оборудовании без физического контакта, обеспечивая раннее вмешательство."},
  {"id":468,"q":"Чтобы уменьшить падение напряжения на длинном ответвлении без изменения нагрузки или длины, какой самый прямой метод?","opts":["Увеличить номинал OCPD","Уменьшить сечение проводника","Увеличить сечение проводника","Использовать меньший кабелепровод"],"re":"Увеличение сечения проводника (большая площадь в круговых милах) снижает сопротивление и, следовательно, уменьшает падение напряжения."},
  {"id":469,"q":"Электрику необходимо измерить напряжение на линейной стороне главного сервисного отключающего устройства коммерческого здания; какой рейтинг CAT наиболее подходит для прибора в этом месте?","opts":["CAT I","CAT II","CAT IV","CAT III"],"re":"CAT IV предназначен для измерений в начале установки, таких как сервисный ввод и линейная сторона главного отключающего устройства, где доступная энергия короткого замыкания наибольшая."},
  {"id":470,"q":"Отверстия для безвинтового подключения ('back-wire') на задней стороне многих бытовых розеток 15 А, как правило, ограничены проводниками какого сечения?","opts":["Только 12 AWG однопроволочный","Только 14 AWG однопроволочный","10 AWG многопроволочный","8 AWG однопроволочный"],"re":"Безвинтовые контакты push-in ('back-wire') на стандартных розетках 15 А обычно сертифицированы только для 14 AWG однопроволочного медного; более крупные проводники должны использовать винтовые клеммы."},
  {"id":471,"q":"Проводники и кабели прямого заложения, выходящие из грунта, должны быть защищены корпусом или кабелепроводом, простирающимся от требуемой глубины покрытия вверх как минимум до какой высоты над законченным уровнем грунта?","opts":["4 фута","6 футов","8 футов","3 фута"],"re":"NEC 300.5(D)(1) требует защиты от требуемой глубины покрытия до не менее 8 футов над законченным уровнем грунта."},
  {"id":472,"q":"Чтобы определить, вызвано ли срабатывание автомата неисправностью проводки или подключённым прибором, разумный шаг поиска неисправности:","opts":["Отключить все нагрузки и сбросить; если держит, подключать нагрузки по одной","Увеличить номинал автомата и повторить проверку","Заменить нейтральную шину","Замкнуть автомат перемычкой"],"re":"Отключение нагрузок и их подключение по одной логически сужает неисправность до проводки или конкретного устройства, следуя систематическому методу изоляции."},
  {"id":473,"q":"Непрерывная нагрузка 30 A питается проводниками, оканчивающимися на оборудовании 75°C; какое минимальное сечение медного проводника требуется из колонки 75°C таблицы 310.16, чтобы нести 125% нагрузки?","opts":["6 AWG","4 AWG","8 AWG","10 AWG"],"re":"30 A × 1,25 = 37,5 A; в колонке 75°C медь 8 AWG (50 A) — наименьший проводник, отвечающий этому, так как 10 AWG всего 35 A."},
  {"id":474,"q":"Что касается рейтингов категории измерений, почему прибор с рейтингом CAT III 600 В может быть безопаснее прибора с рейтингом CAT II 1000 В при измерении на распределительном щите?","opts":["Прибор CAT II физически не может считывать 600 вольт","Рейтинг установившегося напряжения — единственный фактор, важный для безопасности","CAT II всегда означает прибор более высокого качества","Рейтинг CAT III отражает более высокую устойчивость к переходным перенапряжениям для данного места, что важнее, чем значение установившегося напряжения"],"re":"Рейтинг CAT отражает способность прибора выдерживать переходные перенапряжения и доступную энергию короткого замыкания в данном месте; более высокий номер CAT, подходящий для места, более защищает, чем более высокий рейтинг установившегося напряжения при более низкой категории."},
  {"id":475,"q":"Когда кабель прямого заложения проложен под зданием, он должен быть:","opts":["Закопан на 36 дюймов в любом случае","Проложен в кабелепроводе","Оставлен без какой-либо защиты","Соединён через каждые 10 футов"],"re":"Таблица 300.5 и 300.5(C) требуют, чтобы кабели, проходящие под зданием, прокладывались в кабелепроводе, выходящем за пределы здания."},
  {"id":476,"q":"Показание 240 вольт между двумя незаземлёнными линиями, но только 95 вольт на одной линии относительно нейтрали и 145 вольт на другой линии относительно нейтрали в многопроводной цепи указывает на:","opts":["Нормальное сбалансированное состояние","Короткое замыкание между линиями","Обрыв или потерю нейтрали, вызывающие неравное деление напряжения","Неисправное устройство GFCI"],"re":"Полное междулинейное напряжение в норме, но неравные показания линия–нейтраль, которые в сумме дают 240 В, выявляют обрыв нейтрали, при котором напряжение делится по импедансу нагрузки."},
  {"id":477,"q":"Когда ампацитета проводника не соответствует стандартному номиналу OCPD, а цепь не является многоточечной розеточной цепью, NEC 240.4(B) разрешает какое действие для номиналов 800 A или менее?","opts":["Использовать только следующий меньший стандартный OCPD","Округлить ампацитету до ближайших 5 A","Использовать следующий больший стандартный OCPD","Корректировка OCPD не допускается"],"re":"NEC 240.4(B) позволяет использовать следующий больший стандартный номинал OCPD, когда ампацитета проводника не совпадает со стандартным, с учётом предела 800 A и других условий."},
  {"id":478,"q":"Предупреждающая лента, помещённая в траншею над подземным вводом, как правило, должна располагаться не менее чем на какой высоте над проводниками?","opts":["На 12 дюймов выше подземной установки","Непосредственно поверх проводников","Только на поверхности","На 24 дюйма выше проводников"],"re":"NEC 300.5(D)(3) требует предупреждающую ленту не менее чем на 12 дюймов выше подземных вводных проводников, не заключённых в бетон."},
  {"id":479,"q":"При намотке однопроволочного проводника под зажимной винт устройства петля должна формироваться так, чтобы она оборачивалась вокруг винта в каком направлении?","opts":["Против часовой стрелки","По часовой стрелке, в направлении затяжки винта","Прямо поперёк без петли","Это не имеет значения"],"re":"Петля проводника должна оборачиваться по часовой стрелке (в направлении затяжки) вокруг зажимного винта, чтобы винт втягивал провод внутрь, а не выталкивал его при затяжке."},
  {"id":480,"q":"Перед использованием цифрового мультиметра для проверки обесточенности цепи в рамках процедуры блокировки/маркировки, какова наилучшая практика для подтверждения исправности самого прибора?","opts":["Постучать прибором по твёрдой поверхности для сброса","Предположить, что прибор работает, если его дисплей включился","Считать показания прибора только один раз на предполагаемо обесточенной цепи","Использовать тест «живой-мёртвый-живой», проверяя известный источник под напряжением до и после измерения"],"re":"Метод «живой-мёртвый-живой» (проверка перед прикосновением) подтверждает, что прибор считывает известный источник под напряжением, затем предполагаемо обесточенную цепь, затем снова источник под напряжением, чтобы убедиться, что прибор не вышел из строя во время теста."},
  {"id":481,"q":"Коробка содержит четыре проводника 12 AWG и два проводника 14 AWG без устройств и зажимов; какой общий объём коробки требуется по NEC 314.16(B)?","opts":["11,0 куб. дюйма","13,0 куб. дюйма","13,5 куб. дюйма","15,0 куб. дюйма"],"re":"Четыре 12 AWG по 2,25 = 9,0 куб. дюйма плюс два 14 AWG по 2,00 = 4,0 куб. дюйма, итого 13,0 кубических дюйма."},
  {"id":482,"q":"Производители рекомендуют тестировать устройства GFCI и AFCI с помощью их кнопок тестирования как часто в рамках обслуживания?","opts":["Только один раз при установке","Только при возникновении неисправности","Периодически, например ежемесячно","Никогда, так как они не требуют обслуживания"],"re":"Поскольку эти защитные устройства могут отказать незаметно, производители обычно советуют периодически, как правило ежемесячно, нажимать кнопку TEST, чтобы убедиться, что защита остаётся работоспособной."},
  {"id":483,"q":"Когда подземный кабелепровод входит в здание или выходит вертикально вверх, открытый конец должен быть:","opts":["Оставлен полностью открытым для вентиляции","Загерметизирован для предотвращения проникновения влаги","Заполнен бетоном","Закрыт только лентой"],"re":"NEC 300.5(G) требует герметизации концов кабелепроводов и проводников для предотвращения проникновения влаги или газов."},
  {"id":484,"q":"Какой тип лестницы должен выбрать электрик при работе вблизи открытых проводников или оборудования под напряжением?","opts":["Стеклопластиковая лестница","Алюминиевая выдвижная лестница","Стальная платформенная лестница","Мокрая деревянная лестница"],"re":"Стеклопластиковые лестницы непроводящие и являются подходящим выбором для электромонтажных работ вблизи частей под напряжением; металлические лестницы проводящие, и их следует избегать."},
  {"id":485,"q":"Согласно NEC 240.6(A), какая последовательность правильно перечисляет три последовательных стандартных номинала предохранителя/выключателя?","opts":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"re":"Стандартные номиналы в NEC 240.6(A) включают 30, 40 и 50 A подряд; 55 A не стандартен, поэтому 50/55/60 неверно."},
  {"id":486,"q":"При черновом монтаже вводной мачты, используемой для поддержки проводников воздушного ввода, мачта и её крепления должны быть:","opts":["Не больше кабелепровода 1/2 дюйма","Изготовлены только из пластика","Достаточной прочности, чтобы выдержать натяжение проводников","Ограничены внутренним использованием"],"re":"NEC 230.28 требует, чтобы вводная мачта имела достаточную прочность или была закреплена так, чтобы выдержать натяжение проводников воздушного ввода."},
  {"id":487,"q":"Цепь тёплая у автомата, и автомат срабатывает после долгой работы, но проверка на короткое замыкание не показывает глухой неисправности; такое сочетание лучше всего соответствует какому диагнозу?","opts":["Перегрузке, возможно усугублённой ослабленным соединением, добавляющим нагрев","Глухому замыканию на землю","Только неисправному датчику AFCI","Обрыву цепи"],"re":"Нагрев со временем работы при задержанном срабатывании и отсутствии глухого замыкания указывает на перегрузку, а ослабленное соединение может добавить резистивный нагрев, ускоряющий срабатывание."},
  {"id":488,"q":"В стандартной ответвлённой цепи на 120 вольт с использованием кабеля NM какого цвета должен быть заземляющий проводник оборудования (EGC)?","opts":["Белый или серый","Чёрный или красный","Зелёный, зелёный с жёлтой полосой или неизолированный","Синий или жёлтый"],"re":"Согласно NEC 250.119, заземляющие проводники оборудования должны быть зелёными, зелёными с одной или несколькими жёлтыми полосами или неизолированными; белый/серый зарезервирован для заземлённого (нейтрального) проводника."},
  {"id":489,"q":"Следуя правилу 4 к 1 для прямой или выдвижной лестницы, где должно быть размещено основание, если лестница касается стены в точке на высоте 12 футов?","opts":["1 фут от стены","3 фута от стены","6 футов от стены","12 футов от стены"],"re":"Правило 4 к 1 размещает основание на расстоянии 1 фута от стены на каждые 4 фута рабочей высоты; 12 футов, делённые на 4, равны 3 футам от стены."},
  {"id":490,"q":"Только что из следующего может быть прикреплено к вводной мачте?","opts":["Телевизионные антенны","Фурнитура для бельевой верёвки","Кабели связи","Проводники воздушного ввода или верхнего ввода"],"re":"NEC 230.28(B) разрешает прикреплять к вводной мачте только проводники воздушного ввода или верхнего ввода."},
  {"id":491,"q":"Ответвление обслуживает непрерывную нагрузку 12 A плюс непостоянную нагрузку 8 A; какой минимальный номинал OCPD требуется?","opts":["25 A","23 A","20 A","30 A"],"re":"Согласно NEC 210.20(A), OCPD ≥ (12 A × 1,25) + 8 A = 23 A, и следующий стандартный номинал — 25 A."},
  {"id":492,"q":"Когда цепь 120 вольт показывает правильное напряжение без нагрузки, но напряжение резко падает значительно ниже нормы в момент приложения нагрузки, неисправность наиболее вероятно в:","opts":["Высокоомном (ослабленном или корродированном) соединении в питающем пути","Слишком малой мощности устройства нагрузки","Кнопке TEST устройства GFCI","Проводнике заземляющего электрода"],"re":"Напряжение, нормальное без нагрузки, но сильно проседающее под нагрузкой, указывает на высокоомное последовательное соединение, которое снижает напряжение только при протекании тока."},
  {"id":493,"q":"Каков минимальный вертикальный зазор для проводников воздушного ввода, проходящих над жилой подъездной дорожкой, где напряжение не превышает 300 вольт относительно земли?","opts":["10 футов","18 футов","15 футов","12 футов"],"re":"NEC 230.24(B) требует зазор 12 футов над жилыми подъездными дорожками и зонами с автомобильным движением для цепей, не превышающих 300 вольт относительно земли."},
  {"id":494,"q":"В расчётах падения напряжения по формуле VD = 2 × K × I × L / CM, что обозначает переменная 'CM'?","opts":["Материал кабелепровода","Температуру проводника в Цельсиях","Множитель непрерывной нагрузки","Круговые милы проводника"],"re":"В формуле падения напряжения CM — это площадь поперечного сечения проводника, выраженная в круговых милах."},
  {"id":495,"q":"Согласно стандарту OSHA для общей промышленности (29 CFR 1910), примерно на какой высоте над нижним уровнем обычно требуется защита от падения для работников на приподнятой рабочей поверхности?","opts":["2 фута","6 футов","4 фута","10 футов"],"re":"OSHA 29 CFR 1910.28 (общая промышленность) обычно требует защиту от падения на высоте 4 фута над нижним уровнем; строительный стандарт (1926) использует 6 футов."},
  {"id":496,"q":"После подтверждения симптома и сбора информации следующий логичный шаг в структурированном процессе поиска неисправности:","opts":["Сформулировать гипотезу о вероятной причине и проверить её","Заменять случайные компоненты, пока не заработает","Задокументировать ремонт до проверки","Подать питание на цепь и уйти"],"re":"Эффективный поиск неисправности следует логической последовательности: наблюдать симптом, собрать данные, выдвинуть гипотезу о вероятной причине, затем проверить её перед ремонтом."},
  {"id":497,"q":"Что из перечисленного лучше всего описывает основную защитную функцию розетки GFCI (устройства защитного отключения по току утечки на землю)?","opts":["Она защищает оборудование от перегрева из-за перегрузки","Она обнаруживает дуговые замыкания в проводке ответвлённой цепи","Она защищает людей от поражения электрическим током, обнаруживая малый дисбаланс тока между фазным и нейтральным проводниками","Она ограничивает скачки напряжения от молнии или коммутационных перенапряжений"],"re":"GFCI сравнивает ток в фазном и нейтральном проводниках и отключается при малом дисбалансе (около 4-6 мА), защищая людей от поражения током; AFCI обнаруживает дугу, а устройство защиты от перенапряжений справляется со скачками напряжения (NEC 210.8)."},
  {"id":498,"q":"Какова минимальная глубина свободного рабочего пространства, требуемая перед электрооборудованием, которое, вероятно, потребует осмотра под напряжением, при типичном Условии 1 (600 вольт или менее) согласно 110.26?","opts":["2 фута","5 футов","4 фута","3 фута"],"re":"Таблица 110.26(A)(1) требует минимум 3 фута (900 мм) свободной рабочей глубины при Условии 1."},
  {"id":499,"q":"Для существующей одногнёздной коробки устройства какое значение должно быть известно для расчёта заполнения коробки, когда коробка не указана в таблице NEC 314.16(A)?","opts":["Цвет коробки","Типоразмер кабелепровода","Номинал автомата","Маркированный объём коробки в кубических дюймах"],"re":"Согласно NEC 314.16(A), нестандартные коробки должны иметь долговечную маркировку их объёма в кубических дюймах для использования в расчёте."},
  {"id":500,"q":"Какая комбинация средств индивидуальной защиты наиболее подходит, когда электрик должен выполнить задачу с риском дугового разряда, например установку выключателя 480 вольт, который нельзя обесточить?","opts":["Хлопковая футболка, обычные солнцезащитные очки и кожаные рабочие перчатки","Синтетическая нейлоновая куртка и латексные смотровые перчатки","Светоотражающий жилет, каска и голые руки для лучшей ловкости","Дугостойкая одежда, лицевой щиток или капюшон, рассчитанный на энергию воздействия, и резиновые перчатки с рейтингом напряжения с кожаными защитными чехлами"],"re":"Работа под напряжением с риском дугового разряда требует дугостойкой одежды и защиты лица, соответствующей энергии воздействия, а также резиновых изолирующих перчаток с рейтингом напряжения с кожаными защитными чехлами согласно NFPA 70E."}
];
